# SOLUTION ALTERNATIVE POUR LES EMAILS (SMTP DIRECT)
# ========================
# ========================
# SOLUTION POUR EMAILS AVEC HOSTINGER
# ========================
import smtplib
import ssl
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from email.header import Header
from email.utils import formataddr
import os
from datetime import datetime
import logging

logger = logging.getLogger(__name__)

class EmailService:
    """Service d'email utilisant SMTP Hostinger"""
    
    def __init__(self):
        # Configuration Hostinger
        self.smtp_server = 'smtp.hostinger.com'
        self.smtp_port_tls = 587  # Pour TLS
        self.smtp_port_ssl = 465   # Pour SSL
        
        # Vos identifiants Hostinger
        self.sender_email = 'contact@egalyx.com'
        self.sender_name = 'Egalyx Control'
        self.password = os.environ.get('HOSTINGER_EMAIL_PASSWORD', '')
        
        # Mode simulation si pas de mot de passe
        if not self.password:
            print("⚠️ HOSTINGER_EMAIL_PASSWORD non défini - emails en mode simulation")
            self.simulation_mode = True
        else:
            self.simulation_mode = False
            print(f"✅ Service email Hostinger configuré pour {self.sender_email}")
    
    def send_email(self, to_email, subject, body, html_body=None, cc=None, bcc=None):
        """Envoyer un email via SMTP Hostinger"""
        
        # Mode simulation
        if self.simulation_mode:
            print(f"📧 [SIMULATION] Email à: {to_email}")
            print(f"   Sujet: {subject}")
            return True
        
        # Essayer d'abord TLS (port 587)
        try:
            return self._send_via_tls(to_email, subject, body, html_body, cc, bcc)
        except Exception as e_tls:
            print(f"⚠️ TLS échoué, tentative SSL: {e_tls}")
            
            # Fallback SSL (port 465)
            try:
                return self._send_via_ssl(to_email, subject, body, html_body, cc, bcc)
            except Exception as e_ssl:
                print(f"❌ SSL également échoué: {e_ssl}")
                
                # Dernier recours: simulation
                print(f"📧 [FALLBACK] Email à: {to_email}")
                return False
    
    def _send_via_tls(self, to_email, subject, body, html_body=None, cc=None, bcc=None):
        """Envoi via TLS (port 587) avec vérification SSL désactivée"""
        # ← Cette ligne doit être indentée sous la définition
        
        import ssl
        msg = self._create_message(to_email, subject, body, html_body, cc, bcc)
        
        # Créer un contexte SSL qui ne vérifie pas les certificats
        context = ssl.create_default_context()
        context.check_hostname = False
        context.verify_mode = ssl.CERT_NONE
        
        with smtplib.SMTP(self.smtp_server, self.smtp_port_tls, timeout=30) as server:
            server.ehlo()
            server.starttls(context=context)  # Utiliser le contexte modifié
            server.ehlo()
            server.login(self.sender_email, self.password)
            server.send_message(msg)
        
        print(f"✅ Email envoyé (TLS) à {to_email}")
        return True
    
    def _send_via_ssl(self, to_email, subject, body, html_body=None, cc=None, bcc=None):
        """Envoi via SSL (port 465) - Configuration Hostinger OFFICIELLE"""
        import ssl
        msg = self._create_message(to_email, subject, body, html_body, cc, bcc)
        
        # Contexte SSL standard
        context = ssl.create_default_context()
        
        # Connexion SSL directe sur le port 465 (COMME INDIQUÉ PAR HOSTINGER)
        with smtplib.SMTP_SSL('smtp.hostinger.com', 465, timeout=30, context=context) as server:
            # Authentification avec l'email COMPLET
            server.login('contact@egalyx.com', self.password)
            server.send_message(msg)
        
        logger.info(f"✅ Email envoyé via Hostinger à {to_email}")
        return True
    
    def _create_message(self, to_email, subject, body, html_body=None, cc=None, bcc=None):
        """Crée le message email"""
        # ← Cette ligne doit être indentée sous la définition
        
        from email.mime.text import MIMEText
        from email.mime.multipart import MIMEMultipart
        from email.header import Header
        from email.utils import formataddr
        
        msg = MIMEMultipart('alternative')
        msg['Subject'] = subject
        msg['From'] = formataddr((str(Header(self.sender_name, 'utf-8')), self.sender_email))
        
        # Destinataires
        if isinstance(to_email, list):
            msg['To'] = ', '.join(to_email)
            recipients = to_email
        else:
            msg['To'] = to_email
            recipients = [to_email]
        
        # CC
        if cc:
            if isinstance(cc, list):
                msg['Cc'] = ', '.join(cc)
                recipients.extend(cc)
            else:
                msg['Cc'] = cc
                recipients.append(cc)
        
        # BCC - juste pour la liste des destinataires, pas dans l'en-tête
        if bcc:
            if isinstance(bcc, list):
                recipients.extend(bcc)
            else:
                recipients.append(bcc)
        
        # Contenu texte
        text_part = MIMEText(body, 'plain', 'utf-8')
        msg.attach(text_part)
        
        # Contenu HTML
        if html_body:
            html_part = MIMEText(html_body, 'html', 'utf-8')
            msg.attach(html_part)
        
        return msg
    
    def send_contact_confirmation(self, nom_complet, email, societe, telephone, sujet, message, reference):
        """Envoyer les emails pour une demande de contact"""
        # ← Cette ligne doit être indentée sous la définition
        
        # 1. Email à l'administrateur
        admin_subject = f"🔔 Nouvelle demande: {sujet[:50]}"
        admin_body = f"""
        NOUVELLE DEMANDE DE CONTACT
        ===========================
        
        📋 Informations :
        - Nom : {nom_complet}
        - Email : {email}
        - Société : {societe or 'Non spécifié'}
        - Téléphone : {telephone or 'Non spécifié'}
        
        📝 Sujet : {sujet}
        
        💬 Message :
        {message}
        
        📎 Référence : {reference}
        📅 Date : {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}
        """
        
        admin_sent = self.send_email(
            to_email='contact@egalyx.com',
            subject=admin_subject,
            body=admin_body
        )
        
        # 2. Email de confirmation au client
        client_subject = "Confirmation de votre demande - Egalyx Control"
        client_body = f"""
        Confirmation de votre demande - Egalyx Control
        
        Bonjour {nom_complet},
        
        Nous avons bien reçu votre demande.
        
        Référence : {reference}
        Sujet : {sujet}
        Date : {datetime.now().strftime('%d/%m/%Y à %H:%M')}
        
        Notre équipe vous contactera dans les plus brefs délais.
        
        Cordialement,
        L'équipe Egalyx Control
        """
        
        client_sent = self.send_email(
            to_email=email,
            subject=client_subject,
            body=client_body
        )
        
        return admin_sent and client_sent

# Initialiser le service email
email_service = EmailService()

