@app.route('/test-hostinger')
def test_hostinger():
    """Test la connexion Hostinger"""
    import socket
    import ssl
    
    results = []
    results.append("🔧 TEST CONNEXION HOSTINGER")
    results.append("=" * 50)
    
    # Vérifier la variable d'environnement
    password = os.environ.get('HOSTINGER_EMAIL_PASSWORD', '')
    results.append(f"HOSTINGER_EMAIL_PASSWORD: {'✅ Défini' if password else '❌ Non défini'}")
    
    # Test DNS
    try:
        ip = socket.gethostbyname('smtp.hostinger.com')
        results.append(f"✅ DNS résolu: smtp.hostinger.com -> {ip}")
    except Exception as e:
        results.append(f"❌ DNS échoué: {e}")
    
    # Test port 587 (TLS)
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(5)
        result = sock.connect_ex(('smtp.hostinger.com', 587))
        if result == 0:
            results.append("✅ Port 587 (TLS) accessible")
        else:
            results.append(f"❌ Port 587 inaccessible (code: {result})")
        sock.close()
    except Exception as e:
        results.append(f"❌ Erreur port 587: {e}")
    
    # Test port 465 (SSL)
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(5)
        result = sock.connect_ex(('smtp.hostinger.com', 465))
        if result == 0:
            results.append("✅ Port 465 (SSL) accessible")
        else:
            results.append(f"❌ Port 465 inaccessible (code: {result})")
        sock.close()
    except Exception as e:
        results.append(f"❌ Erreur port 465: {e}")
    
    # Test authentification
    if password:
        try:
            # Test TLS
            server = smtplib.SMTP('smtp.hostinger.com', 587, timeout=10)
            server.ehlo()
            server.starttls(context=ssl.create_default_context())
            server.ehlo()
            server.login('contact@egalyx.com', password)
            results.append("✅ Authentification TLS réussie")
            server.quit()
            
            # Test SSL
            context = ssl.create_default_context()
            server = smtplib.SMTP_SSL('smtp.hostinger.com', 465, timeout=10, context=context)
            server.login('contact@egalyx.com', password)
            results.append("✅ Authentification SSL réussie")
            server.quit()
            
        except Exception as e:
            results.append(f"❌ Authentification échouée: {e}")
    
    return "<pre>" + "\n".join(results) + "</pre>"
