# Définition des filtres (doivent être définis avant l'enregistrement)
def nl2br(value):
    """Convertit les retours à la ligne en balises <br> (version sécurisée)."""
    if value is None:
        return ''
    escaped = escape(str(value))
    result = escaped.replace('\n', '<br>\n')
    return Markup(result)

def safe_nl2br(value):
    """Convertit les retours à la ligne en balises <br> sans échappement HTML."""
    if value is None:
        return ''
    result = str(value).replace('\n', '<br>\n')
    return Markup(result)

def truncate(text, length=100, end='...'):
    """Tronque le texte."""
    if not text:
        return ''
    if len(text) <= length:
        return text
    return text[:length - len(end)] + end

def format_date(value, format='%d/%m/%Y'):
    """Formate une date."""
    if not value:
        return ''
    if isinstance(value, datetime):
        return value.strftime(format)
    return value

def format_datetime(value, format='%d/%m/%Y %H:%M'):
    """Formate une date et heure."""
    if not value:
        return ''
    if isinstance(value, datetime):
        return value.strftime(format)
    return value

def yes_no(value):
    """Convertit un booléen en Oui/Non."""
    return 'Oui' if value else 'Non'

def join_list(value, separator=', '):
    """Join a list into a string."""
    if not value:
        return ''
    if isinstance(value, list):
        return separator.join(str(item) for item in value)
    return str(value)

def slugify(value):
    """Convertit une chaîne en slug (pour les URLs)."""
    if not value:
        return ''
    value = normalize('NFKD', str(value)).encode('ascii', 'ignore').decode('ascii')
    value = value.lower()
    value = re.sub(r'[^\w\s-]', '', value)
    value = re.sub(r'[-\s]+', '-', value)
    return value.strip('-')

# Enregistrement des filtres
filters = {
    'nl2br': nl2br,
    'safe_nl2br': safe_nl2br,
    'truncate': truncate,
    'format_date': format_date,
    'format_datetime': format_datetime,
    'yes_no': yes_no,
    'join_list': join_list,
    'slugify': slugify
}

