def admin_required(f):
    """Décorateur qui vérifie que l'utilisateur est admin"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_authenticated:
            flash('Veuillez vous connecter pour accéder à cette page.', 'error')
            return redirect(url_for('login'))
        
        if current_user.role != 'admin':
            flash('Accès non autorisé. Cette page est réservée aux administrateurs.', 'error')
            return redirect(url_for('dashboard'))
        
        return f(*args, **kwargs)
    return decorated_function

def super_admin_required(f):
    """Décorateur pour le super admin (accès universel)"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_authenticated:
            flash('Accès refusé : connexion requise', 'error')
            return redirect(url_for('login', next=request.url))
        if current_user.role != 'super_admin':
            flash('Accès refusé : privilèges super administrateur requis', 'error')
            return redirect(url_for('dashboard'))
        return f(*args, **kwargs)
    return decorated_function

def login_required_decorator(f):
    """Décorateur de connexion requis (compatible avec Flask-Login)"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not current_user.is_authenticated:
            flash('Veuillez vous connecter pour accéder à cette page.', 'warning')
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function

def permission_required(permission):
    """Décorateur pour vérifier des permissions spécifiques"""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if not current_user.is_authenticated:
                flash('Veuillez vous connecter pour accéder à cette page.', 'warning')
                return redirect(url_for('login'))
            
            if hasattr(current_user, 'has_permission'):
                if not current_user.has_permission(permission):
                    flash(f'Accès refusé : permission "{permission}" requise', 'danger')
                    return redirect(url_for('dashboard'))
            elif hasattr(current_user, 'role'):
                # Vérification basée sur le rôle
                allowed_roles = {
                    'can_manage_risks': ['admin', 'manager', 'super_admin'],
                    'can_manage_kri': ['admin', 'manager', 'super_admin'],
                    'can_manage_audit': ['admin', 'manager', 'auditeur', 'super_admin'],
                    'can_manage_users': ['admin', 'super_admin'],
                    'can_view_reports': ['admin', 'manager', 'auditeur', 'utilisateur', 'super_admin'],
                    'can_export_data': ['admin', 'manager', 'super_admin']
                }
                
                if permission in allowed_roles:
                    if current_user.role not in allowed_roles[permission]:
                        flash(f'Accès refusé : rôle {current_user.role} non autorisé', 'danger')
                        return redirect(url_for('dashboard'))
            
            return f(*args, **kwargs)
        return decorated_function
    return decorator

print("✅ Décorateurs de permissions définis :")
