# ========================
# SYSTÈME DE TRADUCTION UNIFIÉ
# ========================

from collections import OrderedDict


class UnifiedTranslationSystem:
    """Système de traduction unique et simple"""
    
    def __init__(self, app_root_path='.'):
        self.translations = OrderedDict()
        self.csv_file = os.path.join(app_root_path, 'translations', 'to_translate.csv')
        self.load_translations()
    
    def load_translations(self):
        """Charge les traductions depuis le CSV"""
        if not os.path.exists(self.csv_file):
            print(f"⚠️ Fichier CSV non trouvé: {self.csv_file}")
            return
        
        try:
            with open(self.csv_file, 'r', encoding='utf-8') as f:
                # Essayer différents formats
                content = f.read()
                
                # Essayer avec virgule
                if ',' in content:
                    f.seek(0)
                    reader = csv.reader(f)
                    for row in reader:
                        if len(row) >= 2:
                            french = row[0].strip()
                            english = row[1].strip()
                            if french and english and french != english:
                                self.translations[french] = english
                
                # Sinon essayer point-virgule
                elif ';' in content:
                    f.seek(0)
                    reader = csv.reader(f, delimiter=';')
                    for row in reader:
                        if len(row) >= 2:
                            french = row[0].strip().strip('"')
                            english = row[1].strip().strip('"')
                            if french and english and french != english:
                                self.translations[french] = english
            
            print(f"✅ {len(self.translations)} traductions chargées")
            
        except Exception as e:
            print(f"❌ Erreur chargement CSV: {e}")
    
    def translate(self, text, lang='en'):
        """Traduit un texte (lang='fr' ou 'en')"""
        if not text or lang == 'fr':
            return str(text) if text else ''
        
        text_str = str(text).strip()
        
        # Chercher la traduction exacte
        if text_str in self.translations:
            return self.translations[text_str]
        
        # Chercher avec différentes capitalisations
        lower_text = text_str.lower()
        for french, english in self.translations.items():
            if french.lower() == lower_text:
                return english
        
        # Chercher une correspondance partielle
        for french, english in self.translations.items():
            if french in text_str:
                return text_str.replace(french, english)
        
        # Retourner l'original si pas de traduction
        return text_str

# Créer l'instance globale
translation_system = UnifiedTranslationSystem()

# Liste des langues supportées (garder simple)
LANGUAGES = {
    'fr': {'name': 'Français', 'flag': 'fr', 'dir': 'ltr'},
    'en': {'name': 'English', 'flag': 'gb', 'dir': 'ltr'}
}

def get_current_language():
    """Détermine la langue actuelle - SIMPLE ET FONCTIONNEL"""
    try:
        # 1. Paramètre URL (priorité absolue)
        if request and request.args.get('lang'):
            lang = request.args.get('lang')
            if lang in ['fr', 'en']:
                return lang
        
        # 2. Session
        if session and session.get('lang'):
            lang = session.get('lang')
            if lang in ['fr', 'en']:
                return lang
        
        # 3. Cookie
        if request and request.cookies.get('lang'):
            lang = request.cookies.get('lang')
            if lang in ['fr', 'en']:
                return lang
        
        # 4. Par défaut
        return 'fr'
    except Exception as e:
        print(f"⚠️ Erreur détermination langue: {e}")
        return 'fr'


@app.before_request
def handle_language():
    """Gère la langue avant chaque requête"""
    try:
        # Déterminer la langue
        lang = 'fr'
        
        # Vérifier les sources dans l'ordre
        if request.args.get('lang') in ['fr', 'en']:
            lang = request.args.get('lang')
        elif session.get('lang') in ['fr', 'en']:
            lang = session.get('lang')
        elif request.cookies.get('lang') in ['fr', 'en']:
            lang = request.cookies.get('lang')
        
        # Stocker dans g et session
        g.current_lang = lang
        session['lang'] = lang
        
        print(f"🌐 Langue définie: {lang}")
        
    except Exception as e:
        print(f"⚠️ Erreur handle_language: {e}")
        g.current_lang = 'fr'
        session['lang'] = 'fr'

