@app.route('/change-language/<lang_code>')
def change_language(lang_code):
    """Change la langue - Compatibilité avec les templates existants"""
    if lang_code not in ['fr', 'en']:
        flash('Langue non supportée', 'error')
        return redirect(request.referrer or url_for('dashboard'))
    
    print(f"🌐 Changement de langue demandé vers: {lang_code}")
    
    # Sauvegarder
    session['lang'] = lang_code
    response = make_response(redirect(request.referrer or url_for('dashboard')))
    response.set_cookie('lang', lang_code, max_age=365*24*60*60)
    
    flash(f'Langue changée en {LANGUAGES[lang_code]["name"]}', 'success')
    return response

