# Cette fonction peut être utilisée dans les routes pour vérifier l'accès
def check_route_access(required_permission=None, required_role=None):
    """Vérifie l'accès à une route basé sur les permissions ou le rôle"""
    if not current_user.is_authenticated:
        flash('Veuillez vous connecter pour accéder à cette page.', 'warning')
        return redirect(url_for('login'))
    
    if required_role and current_user.role != required_role:
        flash(f'Accès refusé : rôle {required_role} requis', 'error')
        return redirect(url_for('dashboard'))
    
    if required_permission:
        if hasattr(current_user, 'has_permission'):
            if not current_user.has_permission(required_permission):
                flash(f'Accès refusé : permission {required_permission} requise', 'error')
                return redirect(url_for('dashboard'))
        else:
            # Logique de secours basée sur le rôle
            pass
    
    return None  # Accès autorisé

