def log_security_event(event_type, details=None, user_id=None):
    """
    Journalise un événement de sécurité dans la base de données
    
    Args:
        event_type: Type d'événement (login_failure, password_reset, etc.)
        details: Dictionnaire de détails supplémentaires
        user_id: ID de l'utilisateur concerné (optionnel)
    """
    try:
        # Vérifier si la table security_logs existe, sinon utiliser JournalActivite
        from models import JournalActivite
        from flask import request
        
        # Convertir les détails en JSON si c'est un dict
        import json
        if isinstance(details, dict):
            details_json = json.dumps(details, ensure_ascii=False)
        else:
            details_json = str(details) if details else None
        
        # Créer l'entrée de journal
        journal = JournalActivite(
            utilisateur_id=user_id,
            action=event_type,
            details=details_json,
            entite_type='securite',
            ip_address=request.remote_addr if request else None,
            user_agent=request.user_agent.string if request and request.user_agent else None
        )
        
        db.session.add(journal)
        db.session.commit()
        
        print(f"🔒 [SECURITY] {event_type}: {details}")
        
    except Exception as e:
        # Ne pas bloquer l'application si la journalisation échoue
        print(f"⚠️ Erreur journalisation sécurité: {e}")
        db.session.rollback()


# Version simplifiée si vous préférez juste logger dans la console
def log_security_event_simple(event_type, details=None, user_id=None):
    """
    Version simplifiée qui logge seulement dans la console
    """
    from flask import request
    
    user_info = f"user_id={user_id}" if user_id else "anonymous"
    ip_info = f"ip={request.remote_addr}" if request else "no_ip"
    
    print(f"🔒 [SECURITY] {event_type} - {user_info} - {ip_info} - {details}")
    
def declencher_mise_a_jour_risque(risque_id, action, utilisateur_id, donnees_supplementaires=None):
    """Déclencher une mise à jour automatique pour un risque"""
    risque = Risque.query.get(risque_id)
    if not risque:
        return
    
    # Récupérer les informations de la requête si disponibles
    from flask import request
    
    ip_address = None
    user_agent = None
    
    try:
        if request:
            ip_address = request.remote_addr
            user_agent = request.user_agent.string
    except RuntimeError:
        # Pas de contexte de requête
        pass
    
    # Créer les détails
    details = None
    if donnees_supplementaires:
        if isinstance(donnees_supplementaires, dict):
            details_parts = []
            for key, value in donnees_supplementaires.items():
                # Formater les valeurs spéciales
                if isinstance(value, list):
                    value = ', '.join(str(v) for v in value)
                elif isinstance(value, dict):
                    value = str(value)
                details_parts.append(f"{key}: {value}")
            details = "\n".join(details_parts)
        else:
            details = str(donnees_supplementaires)
    
    # Journaliser l'action avec 'details' (pas 'description')
    journal = JournalActivite(
        utilisateur_id=utilisateur_id,
        action=action,
        details=details,  # ✅ CORRIGÉ : utilise 'details'
        entite_type='risque',
        entite_id=risque_id,
        ip_address=ip_address,
        user_agent=user_agent
    )
    db.session.add(journal)
    
    # Synchroniser les matrices si nécessaire
    actions_sync = [
        'champ_personnalise_ajoute', 'champ_personnalise_modifie',
        'fichier_ajoute', 'fichier_supprime', 'evaluation_modifiee',
        'kri_associe', 'kri_modifie', 'risque_modifie'
    ]
    
    if action in actions_sync:
        synchroniser_matrices_apres_modification(risque.cartographie_id)
    
    db.session.commit()
    print(f"📝 Activité journalisée: {action} pour risque {risque_id}")

def synchroniser_matrices_apres_modification(cartographie_id):
    """Synchroniser les matrices après modification d'un risque"""
    try:
        # Import local pour éviter les dépendances circulaires
        from utils import synchroniser_matrices_apres_evaluation
        synchroniser_matrices_apres_evaluation(cartographie_id)
    except Exception as e:
        print(f"⚠️ Erreur synchronisation matrices: {e}")

def analyser_constatations_pour_recommandations(constatations):
    """Analyser les constatations pour générer des recommandations intelligentes"""
    if not constatations:
        return []
    
    recommandations = []
    statistiques = {
        'par_type': {},
        'par_gravite': {},
        'themes': set()
    }
    
    # Analyser les constatations
    for constatation in constatations:
        # Compter par type
        if constatation.type_constatation:
            statistiques['par_type'][constatation.type_constatation] = \
                statistiques['par_type'].get(constatation.type_constatation, 0) + 1
        
        # Compter par gravité
        if constatation.gravite:
            statistiques['par_gravite'][constatation.gravite] = \
                statistiques['par_gravite'].get(constatation.gravite, 0) + 1
        
        # Extraire les thèmes des causes racines
        if constatation.cause_racine:
            mots_cles = ['formation', 'procédure', 'documentation', 'contrôle', 
                        'surveillance', 'communication', 'ressource', 'équipement']
            for mot in mots_cles:
                if mot in constatation.cause_racine.lower():
                    statistiques['themes'].add(mot)
    
    # Générer des recommandations basées sur l'analyse
    
    # 1. Recommandation basée sur la gravité
    if 'critique' in statistiques['par_gravite'] and statistiques['par_gravite']['critique'] > 0:
        recommandations.append({
            'texte': f"Mettre en œuvre un plan d'action prioritaire pour traiter les {statistiques['par_gravite']['critique']} constatations critiques identifiées",
            'priorite': 5,
            'categorie': 'urgence',
            'raison': 'Présence de constatations critiques'
        })
    
    # 2. Recommandation basée sur les types de constatations
    for type_const, nombre in statistiques['par_type'].items():
        if nombre >= 2:  # Si plusieurs constatations du même type
            recommandations.append({
                'texte': f"Renforcer les contrôles concernant les {type_const.replace('_', ' ')} (identifiés dans {nombre} constatations)",
                'priorite': 4,
                'categorie': 'prevention',
                'raison': f'Récurrence des {type_const}'
            })
    
    # 3. Recommandations basées sur les thèmes
    if 'formation' in statistiques['themes']:
        recommandations.append({
            'texte': "Renforcer le programme de formation du personnel sur les procédures identifiées comme problématiques",
            'priorite': 4,
            'categorie': 'formation',
            'raison': 'Manque de formation identifié dans les causes racines'
        })
    
    if 'procédure' in statistiques['themes'] or 'documentation' in statistiques['themes']:
        recommandations.append({
            'texte': "Réviser et améliorer la documentation des procédures pour une meilleure compréhension et application",
            'priorite': 3,
            'categorie': 'documentation',
            'raison': 'Déficience procédurale identifiée'
        })
    
    # 4. Recommandations générales basées sur le volume
    total_constatations = len(constatations)
    if total_constatations >= 5:
        recommandations.append({
            'texte': "Mettre en place un tableau de bord de suivi des actions correctives avec des points de contrôle réguliers",
            'priorite': 4,
            'categorie': 'suivi',
            'raison': f'Volume important de constatations ({total_constatations})'
        })
    
    # 5. Recommandation de suivi systématique
    recommandations.append({
        'texte': "Planifier un audit de suivi dans les 6 mois pour vérifier l'efficacité et la pérennité des actions correctives",
        'priorite': 5,
        'categorie': 'suivi',
        'raison': 'Audit complet réalisé'
    })
    
    # Trier par priorité
    recommandations.sort(key=lambda x: x['priorite'], reverse=True)
    
    return recommandations[:5]  # Limiter à 5 recommandations max

def analyser_tendances_audit(constatations, recommandations):
    """Analyser les tendances de l'audit pour la conclusion"""
    if not constatations:
        return {
            'points_forts': ["Aucune constatation identifiée"],
            'points_amelioration': ["Aucun point d'amélioration identifié"],
            'tendance_globale': 'satisfaisante'
        }
    
    points_forts = []
    points_amelioration = []
    
    # Analyser les constatations closes
    constatations_closes = [c for c in constatations if c.statut == 'clos']
    if constatations_closes:
        points_forts.append(f"{len(constatations_closes)} constatations déjà closes")
    
    # Analyser les constatations de conformité (points positifs)
    constatations_conformite = [c for c in constatations if c.type_constatation == 'conformite']
    if constatations_conformite:
        points_forts.append(f"{len(constatations_conformite)} points de conformité identifiés")
    
    # Analyser les constatations critiques
    constatations_critiques = [c for c in constatations if c.gravite == 'critique']
    if constatations_critiques:
        points_amelioration.append(f"{len(constatations_critiques)} constatations critiques nécessitant une attention immédiate")
    
    # Analyser les recommandations terminées
    recommandations_terminees = [r for r in recommandations if r.statut == 'termine']
    if recommandations_terminees:
        points_forts.append(f"{len(recommandations_terminees)} recommandations déjà mises en œuvre")
    
    # Analyser les recommandations en retard
    recommandations_en_retard = [r for r in recommandations if hasattr(r, 'est_en_retard') and r.est_en_retard]
    if recommandations_en_retard:
        points_amelioration.append(f"{len(recommandations_en_retard)} recommandations en retard de traitement")
    
    # Déterminer la tendance globale
    ratio_amelioration = len(points_amelioration) / (len(points_forts) + len(points_amelioration)) if (points_forts or points_amelioration) else 0
    
    if ratio_amelioration > 0.7:
        tendance_globale = 'preoccupante'
    elif ratio_amelioration > 0.4:
        tendance_globale = 'mitigee'
    else:
        tendance_globale = 'satisfaisante'
    
    # Ajouter des points par défaut si liste vide
    if not points_forts:
        points_forts.append("Système d'audit fonctionnel")
    
    if not points_amelioration:
        points_amelioration.append("Maintenir la vigilance sur les processus audités")
    
    return {
        'points_forts': points_forts[:5],  # Limiter à 5 points
        'points_amelioration': points_amelioration[:5],
        'tendance_globale': tendance_globale
    }

def get_fichier_metadata(constatation_id, filename):
    """Récupère les métadonnées d'un fichier"""
    try:
        from models import FichierMetadata
        metadata = FichierMetadata.query.filter_by(
            nom_fichier=filename,
            entite_type='constatation',
            entite_id=constatation_id
        ).first()
        
        if metadata:
            return {
                'commentaire': metadata.commentaire or '',
                'responsable': metadata.responsable.username if metadata.responsable else 'Non défini',
                'date_upload': metadata.created_at.strftime('%d/%m/%Y') if metadata.created_at else '',
                'taille': f"{metadata.taille / 1024:.1f} KB" if metadata.taille else 'N/A'
            }
    except Exception as e:
        print(f"Erreur métadonnées: {e}")
    
    return {
        'commentaire': '',
        'responsable': 'Non défini',
        'date_upload': '',
        'taille': 'N/A'
    }

