@app.route('/admin/utilisateur/<int:id>/toggle', methods=['POST'])
@login_required
def api_toggle_user_status(id):
    """Activer/désactiver un utilisateur"""
    if not (current_user.is_client_admin or current_user.role == 'admin'):
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    user = User.query.get_or_404(id)
    
    # Vérifier que l'utilisateur appartient au même client
    if user.client_id != current_user.client_id:
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    # Ne pas pouvoir modifier soi-même
    if user.id == current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas modifier votre propre statut'}), 400
    
    try:
        user.is_active = not user.is_active
        new_status = 'activé' if user.is_active else 'désactivé'
        
        db.session.commit()
        
        # Journaliser
        log_activity(current_user.id, 'toggle_user_status',
                    f"Utilisateur {user.username} {new_status}",
                    'user', user.id)
        
        return jsonify({
            'success': True,
            'message': f'Utilisateur {user.username} {new_status}',
            'is_active': user.is_active
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

@app.route('/client-admin/utilisateur/<int:id>/toggle', methods=['POST'])
@login_required
def client_api_toggle_user_status(id):
    """Activer/désactiver un utilisateur - version admin client"""
    
    # Vérifier que c'est un admin client
    if not current_user.is_client_admin:
        return jsonify({'error': 'Accès réservé aux administrateurs client'}), 403
    
    user = User.query.get_or_404(id)
    client = current_user.client
    
    # Vérifications
    if not client:
        return jsonify({'error': 'Aucun client associé à votre compte'}), 400
    
    # Vérifier que l'utilisateur appartient au même client
    if user.client_id != client.id:
        return jsonify({'error': 'Accès non autorisé à cet utilisateur'}), 403
    
    # Ne pas pouvoir modifier soi-même
    if user.id == current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas modifier votre propre statut'}), 400
    
    # Empêcher de modifier un autre admin client
    if user.is_client_admin and user.id != current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas modifier un autre administrateur client'}), 403
    
    try:
        user.is_active = not user.is_active
        new_status = 'activé' if user.is_active else 'désactivé'
        
        db.session.commit()
        
        # Journaliser l'action - CORRIGÉ : import direct
        journal = JournalActiviteClient(
            client_id=client.id,
            utilisateur_id=current_user.id,
            action='toggle_user_status',
            details={
                'user_id': user.id,
                'username': user.username,
                'nouveau_statut': 'actif' if user.is_active else 'inactif',
                'action_par': current_user.username
            }
        )
        db.session.add(journal)
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Utilisateur {user.username} {new_status}',
            'is_active': user.is_active
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

@app.route('/client-admin/utilisateur/<int:id>/supprimer', methods=['POST'])
@login_required
def client_api_delete_user(id):
    """Supprimer un utilisateur - version admin client"""
    
    try:
        print(f"🔍 Début suppression utilisateur {id}")
        
        # Vérifier que c'est un admin client
        if not current_user.is_client_admin:
            print("❌ Pas admin client")
            return jsonify({'error': 'Accès réservé aux administrateurs client'}), 403
        
        user = User.query.get_or_404(id)
        client = current_user.client
        
        # Vérifications
        if not client:
            print("❌ Pas de client associé")
            return jsonify({'error': 'Aucun client associé à votre compte'}), 400
        
        # Vérifier que l'utilisateur appartient au même client
        if user.client_id != client.id:
            print(f"❌ Mauvais client: user.client_id={user.client_id}, current={client.id}")
            return jsonify({'error': 'Accès non autorisé à cet utilisateur'}), 403
        
        # Ne pas pouvoir se supprimer soi-même
        if user.id == current_user.id:
            return jsonify({'error': 'Vous ne pouvez pas vous supprimer vous-même'}), 400
        
        # Empêcher de supprimer un autre admin client
        if user.is_client_admin:
            return jsonify({'error': 'Vous ne pouvez pas supprimer un autre administrateur client'}), 403
        
        print(f"✅ Vérifications OK, suppression de {user.username}")
        
        # Utiliser la fonction de suppression sécurisée
        result = delete_user_safely(id, current_user.id)
        
        if result['success']:
            # Journaliser
            try:
                journal = JournalActiviteClient(
                    client_id=client.id,
                    utilisateur_id=current_user.id,
                    action='suppression_utilisateur',
                    details={
                        'user_id': user.id,
                        'username': user.username,
                        'supprime_par': current_user.username
                    }
                )
                db.session.add(journal)
                db.session.commit()
                print("✅ Journal créé")
            except Exception as journal_error:
                print(f"⚠️ Erreur journal: {journal_error}")
            
            print(f"✅ Utilisateur {user.username} supprimé avec succès")
            
            return jsonify({
                'success': True,
                'message': f'Utilisateur {user.username} supprimé avec succès',
                'dependencies': result.get('dependencies', [])
            })
        else:
            return jsonify({'error': result['error']}), 500
        
    except Exception as e:
        db.session.rollback()
        print(f"❌ Erreur suppression: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({'error': f'Erreur serveur: {str(e)}'}), 500

def refresh_sqlalchemy_cache():
    """Force la réinitialisation du cache SQLAlchemy pour détecter les nouvelles colonnes"""
    print("🔄 Réinitialisation du cache SQLAlchemy...")
    
    try:
        # 1. Fermer toutes les sessions
        db.session.close_all()
        
        # 2. Réinitialiser les métadonnées
        db.metadata.clear()
        db.metadata.reflect(bind=db.engine)
        
        # 3. Réinitialiser le mapper pour chaque modèle problématique
        from sqlalchemy.orm import class_mapper
        
        models_to_refresh = [
            ZoneRisqueProcessus,
            Alerte,
            ZoneRisqueOrganigramme,
            PointDecision,
            ElementLogigramme,
            LienLogigramme,
            ProcessusActivite,
            GuideEvaluation
        ]
        
        for model in models_to_refresh:
            try:
                mapper = class_mapper(model)
                mapper._configure_all()
                print(f"✅ Cache réinitialisé pour {model.__name__}")
            except Exception as e:
                print(f"⚠️ Erreur pour {model.__name__}: {e}")
        
        print("✅ Cache SQLAlchemy réinitialisé")
        
    except Exception as e:
        print(f"❌ Erreur réinitialisation cache: {e}")
        import traceback
        traceback.print_exc()

app.route('/admin/utilisateur/<int:id>/supprimer', methods=['POST'])
@login_required
def api_delete_user(id):
    """Supprimer un utilisateur"""
    if not current_user.is_client_admin:
        return jsonify({'error': 'Accès réservé aux administrateurs client'}), 403
    
    user = User.query.get_or_404(id)
    
    # Vérifier que l'utilisateur appartient au même client
    if user.client_id != current_user.client_id:
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    # Ne pas pouvoir se supprimer soi-même
    if user.id == current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas vous supprimer vous-même'}), 400
    
    try:
        username = user.username
        
        # Journaliser avant suppression
        log_activity(current_user.id, 'delete_user',
                    f"Suppression utilisateur {username}",
                    'user', user.id)
        
        # Supprimer l'utilisateur
        db.session.delete(user)
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Utilisateur {username} supprimé avec succès'
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500



@app.route('/api/client/environment/<int:env_id>/maintenance', methods=['POST'])
@login_required
@super_admin_required
def api_maintenance_environment(env_id):
    """Mettre un environnement en maintenance"""
    env = EnvironnementClient.query.get_or_404(env_id)
    
    try:
        new_status = 'en_maintenance' if env.statut != 'en_maintenance' else 'actif'
        old_status = env.statut
        env.statut = new_status
        
        if new_status == 'en_maintenance':
            env.date_maintenance = datetime.utcnow()
        
        db.session.commit()
        
        # Journaliser
        journal = JournalActiviteClient(
            client_id=env.client_id,
            utilisateur_id=current_user.id,
            action='environment_maintenance',
            details={
                'env_id': env.id,
                'env_name': env.nom,
                'old_status': old_status,
                'new_status': new_status,
                'by': current_user.username
            }
        )
        db.session.add(journal)
        db.session.commit()
        
        return jsonify({
            'success': True,
            'new_status': new_status,
            'message': f'Environnement {env.nom} passé en {new_status}'
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

# Dans app.py, après les imports et la création de l'app

# ==================== MIDDLEWARE SOUS-DOMAIN ====================

@app.before_request
def detect_client_subdomain():
    """Détecte le sous-domaine et route vers le client correspondant"""
    host = request.host
    
    # En développement : utiliser localhost avec paramètre client
    if 'localhost' in host or '127.0.0.1' in host:
        # Vous pouvez gérer les sous-domaines locaux aussi
        # Ex: client1.localhost:5000
        if 'localhost' in host and ':' in host:
            # Extraire la partie avant .localhost
            parts = host.split(':')[0].split('.')
            if len(parts) > 1 and parts[0] not in ['www', 'api', 'admin']:
                subdomain = parts[0]
                # Trouver le client par référence (pas par sous-domaine en dev)
                client = Client.query.filter_by(reference=subdomain).first()
                if client:
                    g.client_id = client.id
                    g.client_subdomain = subdomain
    
    # En production, extraire le sous-domaine
    elif 'votresociete.com' in host:  # Remplacez par votre vrai domaine
        subdomain = host.replace('.votresociete.com', '')
        
        # Si c'est un sous-domaine client (pas www, pas api)
        if subdomain and subdomain not in ['www', 'api', 'admin']:
            # Trouver le client par sous-domaine
            client = Client.query.filter_by(sous_domaine=f"{subdomain}.votresociete.com").first()
            if client:
                g.client_id = client.id
                g.client_subdomain = subdomain
                
                # Si l'utilisateur n'est pas connecté, rediriger vers login client
                if not current_user.is_authenticated and request.endpoint not in ['client_login_page', 'static']:
                    return redirect(url_for('client_login_page', client_reference=client.reference))

@app.route('/client-login', methods=['GET', 'POST'])
def client_login_subdomain():
    """Login automatique par sous-domaine"""
    if hasattr(g, 'client_subdomain'):
        # Chercher le client par sous-domaine en production ou référence en dev
        if 'votresociete.com' in request.host:
            client = Client.query.filter(
                Client.sous_domaine.like(f"%{g.client_subdomain}%")
            ).first()
        else:
            # En développement, chercher par référence
            client = Client.query.filter_by(reference=g.client_subdomain).first()
        
        if client:
            # Rediriger vers la page de login spécifique
            return redirect(url_for('client_login_page', client_reference=client.reference))
    
    return redirect(url_for('public_home'))

