def export_all_cartographie_risques_pdf():
    """Export PDF de TOUS les risques de la cartographie"""
    
    from weasyprint import HTML
    from weasyprint.text.fonts import FontConfiguration
    from datetime import datetime
    
    # Récupérer tous les risques
    if current_user.role == 'super_admin':
        risques = CartographieRisqueFonction.query.order_by(CartographieRisqueFonction.pole, CartographieRisqueFonction.direction).all()
    else:
        risques = CartographieRisqueFonction.query.filter_by(client_id=current_user.client_id).order_by(CartographieRisqueFonction.pole, CartographieRisqueFonction.direction).all()
    
    # Statistiques globales
    stats = {
        'total': len(risques),
        'par_pole': {},
        'par_niveau': {'Faible': 0, 'Moyen': 0, 'Élevé': 0, 'Critique': 0},
        'impact_eleve': len([r for r in risques if r.impact in ['Très fort à éviter', 'Fort à éviter']]),
        'probabilite_eleve': len([r for r in risques if r.probabilite in ['Certain', 'Très probable']]),
        'maitrise_insuffisante': len([r for r in risques if r.niveau_maitrise in ['Faible', 'Insuffisante']])
    }
    
    for r in risques:
        # Par pôle
        if r.pole not in stats['par_pole']:
            stats['par_pole'][r.pole] = 0
        stats['par_pole'][r.pole] += 1
        
        # Par niveau
        niveau, _ = r.get_niveau_risque()
        stats['par_niveau'][niveau] = stats['par_niveau'].get(niveau, 0) + 1
    
