# FICHIER SITEMAP ULTRA COMPLET
# ================================================
@app.route('/sitemap.xml')
def sitemap():
    """Sitemap principal - version tranquille"""
    today = datetime.now().date().isoformat()
    
    # Liste des URLs à indexer
    urls = [
        "https://www.egalyx.com/",
        "https://www.egalyx.com/home",
        "https://www.egalyx.com/fonctionnalites",
        "https://www.egalyx.com/tarifs",
        "https://www.egalyx.com/a-propos",
        "https://www.egalyx.com/contact",
        "https://www.egalyx.com/blog",
        "https://www.egalyx.com/logiciel-audit-interne-ia",
        "https://www.egalyx.com/controle-interne-logiciel-pme",
        "https://www.egalyx.com/gestion-risques-entreprise-ia",
        "https://www.egalyx.com/cartographie-risques-logiciel",
        "https://www.egalyx.com/conformite-ohada-logiciel",
        "https://www.egalyx.com/conformite-rgpd-logiciel",
        "https://www.egalyx.com/indicateurs-risques-kri",
        "https://www.egalyx.com/plan-action-correctif-logiciel",
        "https://www.egalyx.com/audit-interne-automatise",
        "https://www.egalyx.com/gouvernance-entreprise-logiciel",
    ]
    
    # Construction du XML
    xml = '<?xml version="1.0" encoding="UTF-8"?>\n'
    xml += '<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'
    
    for url in urls:
        xml += '    <url>\n'
        xml += f'        <loc>{url}</loc>\n'
        xml += f'        <lastmod>{today}</lastmod>\n'
        xml += '        <changefreq>weekly</changefreq>\n'
        xml += '        <priority>0.8</priority>\n'
        xml += '    </url>\n'
    
    xml += '</urlset>'
    
    return Response(xml, mimetype='application/xml')

@app.route('/admin/poles')
@login_required
def admin_poles():
    """Liste des pôles/filiales"""
    
    if not current_user.has_permission('can_view_departments'):
        flash('Accès refusé : permission de voir les départements requise', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupérer les paramètres de filtre
    resp_filter = request.args.get('resp', 'tous')
    search_query = request.args.get('search', '')
    
    # Récupérer les pôles avec filtrage client
    if current_user.role == 'super_admin':
        query = Pole.query.filter_by(is_archived=False)
    else:
        query = get_client_filter(Pole).filter_by(is_archived=False)
    
    # Appliquer la recherche
    if search_query:
        query = query.filter(Pole.nom.ilike(f'%{search_query}%'))
    
    # Récupérer tous les pôles
    poles = query.order_by(Pole.ordre).all()
    
    # Filtrer par responsable (en Python)
    if resp_filter == 'avec':
        poles = [p for p in poles if p.a_responsable]
    elif resp_filter == 'sans':
        poles = [p for p in poles if not p.a_responsable]
    
    # Statistiques
    stats = {
        'total_poles': len(poles),
        'total_directions': get_client_filter(Direction).filter_by(is_archived=False, is_active=True).count(),
        'total_services': get_client_filter(Service).filter_by(is_archived=False, is_active=True).count(),
        'directions_rattachees': get_client_filter(Direction).filter(
            Direction.pole_id.isnot(None),
            Direction.is_archived==False,
            Direction.is_active==True
        ).count(),
        'taux_couverture': 0
    }
    
    # Calculer le taux de couverture
    if stats['total_directions'] > 0:
        stats['taux_couverture'] = round((stats['directions_rattachees'] / stats['total_directions']) * 100)
    
    # Compter les pôles avec responsable
    poles_avec_resp = len([p for p in poles if p.a_responsable])
    
    return render_template('admin/poles.html',
                         poles=poles,
                         stats=stats,
                         poles_avec_resp=poles_avec_resp,
                         resp_filter=resp_filter,
                         search_query=search_query)



@app.route('/admin/pole/nouveau', methods=['GET', 'POST'])
@login_required
def nouveau_pole():
    """Créer un nouveau pôle/filiale"""
    if not current_user.has_permission('can_manage_departments'):
        flash('Accès refusé', 'error')
        return redirect(url_for('admin_poles'))
    
    form = PoleForm()
    
    # Remplir la liste des utilisateurs
    users = get_client_filter(User).filter_by(is_active=True).all()
    form.responsable_id.choices = [(0, '--- Aucun responsable ---')] + \
                                  [(u.id, u.username) for u in users]
    
    if form.validate_on_submit():
        try:
            pole = Pole(
                nom=form.nom.data,
                description=form.description.data,
                couleur=form.couleur.data,
                ordre=form.ordre.data,
                client_id=current_user.client_id,
                created_by=current_user.id
            )
            
            # Gestion du responsable
            if form.type_responsable.data == 'utilisateur' and form.responsable_id.data > 0:
                pole.responsable_id = form.responsable_id.data
                pole.responsable_nom_manuel = None
                pole.responsable_type = 'utilisateur'
            elif form.type_responsable.data == 'manuel' and form.responsable_nom_manuel.data:
                pole.responsable_id = None
                pole.responsable_nom_manuel = form.responsable_nom_manuel.data
                pole.responsable_type = 'manuel'
            
            db.session.add(pole)
            db.session.commit()
            
            flash(f'✅ Pôle "{pole.nom}" créé avec succès', 'success')
            return redirect(url_for('admin_poles'))
            
        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')
    
    return render_template('admin/pole_form.html', form=form)

@app.route('/admin/pole/<int:id>/editer', methods=['GET', 'POST'])
@login_required
def editer_pole(id):
    """Modifier un pôle/filiale"""
    if not current_user.has_permission('can_manage_departments'):
        flash('Accès refusé', 'error')
        return redirect(url_for('admin_poles'))
    
    pole = Pole.query.get_or_404(id)
    
    if not check_client_access(pole):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('admin_poles'))
    
    form = PoleForm(obj=pole)
    
    # Remplir la liste des utilisateurs
    users = get_client_filter(User).filter_by(is_active=True).all()
    form.responsable_id.choices = [(0, '--- Aucun responsable ---')] + \
                                  [(u.id, u.username) for u in users]
    
    if request.method == 'GET':
        form.nom.data = pole.nom
        form.description.data = pole.description
        form.couleur.data = pole.couleur
        form.ordre.data = pole.ordre
        
        if pole.responsable_id:
            form.type_responsable.data = 'utilisateur'
            form.responsable_id.data = pole.responsable_id
        elif pole.responsable_nom_manuel:
            form.type_responsable.data = 'manuel'
            form.responsable_nom_manuel.data = pole.responsable_nom_manuel
    
    if form.validate_on_submit():
        try:
            pole.nom = form.nom.data
            pole.description = form.description.data
            pole.couleur = form.couleur.data
            pole.ordre = form.ordre.data
            pole.updated_at = datetime.utcnow()
            
            # Gestion du responsable
            if form.type_responsable.data == 'utilisateur' and form.responsable_id.data > 0:
                pole.responsable_id = form.responsable_id.data
                pole.responsable_nom_manuel = None
                pole.responsable_type = 'utilisateur'
            elif form.type_responsable.data == 'manuel' and form.responsable_nom_manuel.data:
                pole.responsable_id = None
                pole.responsable_nom_manuel = form.responsable_nom_manuel.data
                pole.responsable_type = 'manuel'
            else:
                pole.responsable_id = None
                pole.responsable_nom_manuel = None
                pole.responsable_type = 'utilisateur'
            
            db.session.commit()
            flash(f'✅ Pôle "{pole.nom}" modifié avec succès', 'success')
            return redirect(url_for('admin_poles'))
            
        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')
    
    return render_template('admin/pole_form.html', form=form, pole=pole)


@app.route('/admin/pole/<int:id>/supprimer', methods=['DELETE'])
@login_required
def supprimer_pole(id):
    """Supprimer un pôle"""
    if not current_user.has_permission('can_manage_departments'):
        return jsonify({'success': False, 'error': 'Permission non autorisée'}), 403
    
    pole = Pole.query.get_or_404(id)
    
    if not check_client_access(pole):
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403
    
    # Vérifier si le pôle a des directions
    if pole.directions and len([d for d in pole.directions if not d.is_archived]) > 0:
        return jsonify({
            'success': False, 
            'error': 'Ce pôle contient des directions. Veuillez d\'abord les déplacer ou les supprimer.'
        }), 400
    
    try:
        db.session.delete(pole)
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Pôle "{pole.nom}" supprimé avec succès'
        })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

    
