@app.route('/api/admin/auteurs', methods=['POST'])
@login_required
def api_create_auteur():
    """Crée un nouvel auteur"""
    if current_user.role != 'super_admin':
        return jsonify({'error': 'Unauthorized'}), 403
    
    try:
        # Gérer l'upload d'image
        if request.content_type and 'multipart/form-data' in request.content_type:
            # Traitement formulaire multipart (avec fichier)
            prenom = request.form.get('prenom')
            nom = request.form.get('nom')
            email = request.form.get('email')
            fonction = request.form.get('fonction')
            bio_courte = request.form.get('bio_courte')
            bio = request.form.get('bio')
            experience = request.form.get('experience', 0)
            
            # Validation
            if not prenom or not nom:
                return jsonify({'success': False, 'message': 'Prénom et nom requis'}), 400
            
            from models import Auteur
            auteur = Auteur(
                prenom=prenom,
                nom=nom,
                slug=slugify(f"{prenom} {nom}"),
                email=email,
                fonction=fonction,
                bio_courte=bio_courte,
                bio=bio,
                experience=experience
            )
            
            # Gérer l'upload d'image
            if 'image' in request.files:
                file = request.files['image']
                if file and file.filename:
                    filename = secure_filename(file.filename)
                    file.save(f'static/images/authors/{filename}')
                    auteur.image = f'/static/images/authors/{filename}'
            
            db.session.add(auteur)
            db.session.commit()
            
            return jsonify({
                'success': True,
                'auteur': {
                    'id': auteur.id,
                    'nom_complet': auteur.nom_complet
                }
            })
        else:
            # Traitement JSON (sans fichier)
            data = request.get_json()
            
            if not data.get('prenom') or not data.get('nom'):
                return jsonify({'success': False, 'message': 'Prénom et nom requis'}), 400
            
            auteur = Auteur(
                prenom=data['prenom'],
                nom=data['nom'],
                slug=slugify(f"{data['prenom']} {data['nom']}"),
                email=data.get('email'),
                fonction=data.get('fonction'),
                bio_courte=data.get('bio_courte'),
                bio=data.get('bio'),
                experience=data.get('experience', 0)
            )
            
            db.session.add(auteur)
            db.session.commit()
            
            return jsonify({
                'success': True,
                'auteur': {
                    'id': auteur.id,
                    'nom_complet': auteur.nom_complet
                }
            })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(e)}), 500


