@app.route('/admin/articles/nouveau', methods=['GET', 'POST'])
@login_required
def nouvel_article():
    """Créer un nouvel article (super admin uniquement)"""
    if current_user.role != 'super_admin':
        flash('Accès réservé aux super administrateurs', 'error')
        return redirect(url_for('dashboard'))
    
    from models import Categorie, Auteur, Article
    from datetime import datetime
    import os
    from werkzeug.utils import secure_filename
    
    if request.method == 'POST':
        # Récupérer le slug
        slug = request.form['slug'] or slugify(request.form['titre'])
        
        # VÉRIFICATION CRITIQUE : Voir si le slug existe déjà
        article_existant = Article.query.filter_by(slug=slug).first()
        
        if article_existant:
            # Slug existe déjà -> on le rend unique
            base_slug = slug
            compteur = 1
            while Article.query.filter_by(slug=slug).first():
                slug = f"{base_slug}-{compteur}"
                compteur += 1
            flash(f"Le slug '{base_slug}' existait déjà. Nouveau slug généré : '{slug}'", 'warning')
        
        # Créer l'article
        article = Article(
            titre=request.form['titre'],
            slug=slug,  # Utiliser le slug (original ou modifié)
            accroche=request.form.get('accroche'),
            contenu=request.form['contenu'],
            excerpt=request.form.get('excerpt'),
            tags=request.form.get('tags'),
            categorie_id=request.form.get('categorie_id') if request.form.get('categorie_id') else None,
            auteur_id=request.form.get('auteur_id') if request.form.get('auteur_id') else None,
            est_publie=request.form.get('est_publie') == 'on',
            temps_lecture=request.form.get('temps_lecture', 5),
            meta_description=request.form.get('meta_description'),
            date_publication=datetime.utcnow(),
            date_modification=datetime.utcnow(),
            date_creation=datetime.utcnow()
        )
        
        # Gérer l'upload d'image principale
        if 'image' in request.files:
            file = request.files['image']
            if file and file.filename:
                filename = secure_filename(file.filename)
                # S'assurer que le dossier existe
                os.makedirs('static/images/blog', exist_ok=True)
                file.save(f'static/images/blog/{filename}')
                article.image_principale = f'/static/images/blog/{filename}'
        
        # Gérer l'upload d'image Open Graph
        if 'image_og' in request.files:
            file = request.files['image_og']
            if file and file.filename:
                filename = secure_filename(file.filename)
                os.makedirs('static/images/blog', exist_ok=True)
                file.save(f'static/images/blog/{filename}')
                article.image_og = f'/static/images/blog/{filename}'
        
        try:
            db.session.add(article)
            db.session.commit()
            
            # Ping Google pour mise à jour sitemap
            try:
                import requests
                requests.get(f"https://www.google.com/ping?sitemap=https://www.egalyx.com/sitemap.xml", timeout=2)
            except:
                pass
            
            flash('Article créé avec succès !', 'success')
            return redirect(url_for('admin_articles'))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur lors de la création : {str(e)}', 'error')
            # En cas d'erreur, re-afficher le formulaire avec les données
            categories = Categorie.query.all()
            auteurs = Auteur.query.all()
            return render_template('admin/nouvel-article.html', 
                                 categories=categories, 
                                 auteurs=auteurs,
                                 form_data=request.form)
    
    # GET - afficher le formulaire
    categories = Categorie.query.all()
    auteurs = Auteur.query.all()
    
    return render_template('admin/nouvel-article.html', 
                         categories=categories, 
                         auteurs=auteurs)

