@app.route('/api/admin/articles/generer', methods=['POST'])
@login_required
def api_generer_articles():
    """Génère automatiquement des articles (super admin uniquement)"""
    if current_user.role != 'super_admin':
        return jsonify({'error': 'Unauthorized'}), 403
    
    try:
        data = request.get_json()
        nombre = int(data.get('nombre', 5))
        sujet = data.get('sujet', '')
        categorie_id = data.get('categorie_id')
        auteur_id = data.get('auteur_id')
        
        from models import Categorie, Auteur, Article
        from datetime import datetime
        import re
        
        # Vérifier que la catégorie et l'auteur existent
        categorie = Categorie.query.get(categorie_id) if categorie_id else None
        auteur = Auteur.query.get(auteur_id) if auteur_id else None
        
        if not categorie:
            # Prendre la première catégorie disponible
            categorie = Categorie.query.first()
        
        if not auteur:
            # Prendre le premier auteur disponible
            auteur = Auteur.query.first()
        
        if not categorie or not auteur:
            return jsonify({
                'success': False, 
                'message': 'Créez d\'abord une catégorie et un auteur dans l\'administration'
            }), 400
        
        # Fonction slugify interne
        def slugify(text):
            if not text:
                return ''
            text = text.lower()
            # Remplacer les accents
            accents = {
                'à': 'a', 'á': 'a', 'â': 'a', 'ã': 'a', 'ä': 'a',
                'è': 'e', 'é': 'e', 'ê': 'e', 'ë': 'e',
                'ì': 'i', 'í': 'i', 'î': 'i', 'ï': 'i',
                'ò': 'o', 'ó': 'o', 'ô': 'o', 'õ': 'o', 'ö': 'o',
                'ù': 'u', 'ú': 'u', 'û': 'u', 'ü': 'u',
                'ý': 'y', 'ÿ': 'y', 'ç': 'c', 'ñ': 'n'
            }
            for accented, unaccented in accents.items():
                text = text.replace(accented, unaccented)
            # Supprimer les caractères spéciaux
            text = re.sub(r'[^a-z0-9]+', '-', text)
            return text.strip('-')
        
        # Liste de sujets d'articles
        sujets_base = [
            "L'impact de l'IA sur l'audit interne",
            "Guide complet de la cartographie des risques",
            "Les 5 tendances de la gestion des risques en 2024",
            "Comment réduire les risques de non-conformité",
            "OHADA : les nouvelles obligations comptables",
            "RGPD : audit de conformité en 5 étapes",
            "KRI vs KPI : quelles différences ?",
            "L'importance du contrôle interne en entreprise",
            "Audit interne : méthodologie et bonnes pratiques",
            "Les défis de la conformité réglementaire",
            "Intelligence artificielle et gestion des risques",
            "Tableau de bord des indicateurs de risque",
            "Plan d'action correctif : comment le mettre en place",
            "Audit fournisseur : procédure et checklist",
            "Cartographie des risques : erreurs à éviter"
        ]
        
        # Modèles de contenu
        contenus_base = [
            """
            <h2>Introduction</h2>
            <p>Dans un environnement économique en constante évolution, la gestion des risques et l'audit interne sont devenus des piliers essentiels de la gouvernance d'entreprise. Cet article explore les meilleures pratiques et les innovations récentes dans ce domaine.</p>
            
            <h2>1. Les enjeux actuels</h2>
            <p>Les organisations font face à des risques de plus en plus complexes : cybermenaces, conformité réglementaire, instabilité économique, etc. Une approche proactive est nécessaire pour anticiper ces défis.</p>
            
            <h2>2. Méthodologie recommandée</h2>
            <ul>
                <li>Identification des risques potentiels</li>
                <li>Évaluation de leur probabilité et impact</li>
                <li>Mise en place de contrôles adaptés</li>
                <li>Suivi et reporting régulier</li>
            </ul>
            
            <h2>3. L'apport de l'intelligence artificielle</h2>
            <p>L'IA transforme profondément les pratiques d'audit en permettant l'analyse prédictive, la détection précoce d'anomalies et l'automatisation des tâches répétitives.</p>
            
            <h2>Conclusion</h2>
            <p>Investir dans une démarche structurée de gestion des risques est un facteur clé de succès pour toute organisation souhaitant pérenniser ses activités.</p>
            """,
            
            """
            <h2>Introduction</h2>
            <p>La conformité réglementaire est un enjeu majeur pour les entreprises, quelle que soit leur taille. Cet article vous guide à travers les étapes clés pour réussir votre audit de conformité.</p>
            
            <h2>1. Comprendre les obligations</h2>
            <p>RGPD, OHADA, SOX, normes ISO... Le paysage réglementaire est complexe. Une veille réglementaire efficace est indispensable pour rester en conformité.</p>
            
            <h2>2. Audit de conformité : méthodologie</h2>
            <ol>
                <li>Cartographier les exigences applicables</li>
                <li>Évaluer l'existant</li>
                <li>Identifier les écarts</li>
                <li>Définir un plan d'action</li>
                <li>Suivre la mise en œuvre</li>
            </ol>
            
            <h2>3. Outils et bonnes pratiques</h2>
            <p>Les solutions logicielles spécialisées permettent d'automatiser le suivi et de réduire les risques d'erreur.</p>
            
            <h2>Conclusion</h2>
            <p>La conformité n'est pas une contrainte mais un avantage concurrentiel lorsqu'elle est bien gérée.</p>
            """
        ]
        
        articles_crees = 0
        
        for i in range(nombre):
            # Choisir un sujet
            if sujet:
                titre = f"{sujet} - Partie {i+1}"
            else:
                titre = sujets_base[i % len(sujets_base)]
                if nombre > len(sujets_base):
                    titre += f" - Partie {i+1}"
            
            # Générer un slug unique
            base_slug = slugify(titre)
            slug = base_slug
            compteur = 1
            while Article.query.filter_by(slug=slug).first():
                slug = f"{base_slug}-{compteur}"
                compteur += 1
            
            # Choisir un contenu
            contenu = contenus_base[i % len(contenus_base)]
            
            # Créer l'article
            article = Article(
                titre=titre,
                slug=slug,
                accroche=f"Découvrez tout sur {titre.lower()} dans cet article complet rédigé par nos experts.",
                contenu=contenu,
                excerpt=f"Article complet sur {titre.lower()} avec conseils pratiques et analyses d'experts.",
                tags="audit, risques, conformité, IA",
                categorie_id=categorie.id,
                auteur_id=auteur.id,
                est_publie=True,
                temps_lecture=5 + (i % 5),
                meta_description=f"Article complet sur {titre.lower()} - Conseils, bonnes pratiques et analyses d'experts en audit et gestion des risques.",
                date_publication=datetime.utcnow(),
                date_modification=datetime.utcnow(),
                date_creation=datetime.utcnow()
            )
            
            db.session.add(article)
            articles_crees += 1
        
        db.session.commit()
        
        return jsonify({
            'success': True,
            'articles': articles_crees,
            'message': f'{articles_crees} articles générés avec succès'
        })
        
    except Exception as e:
        db.session.rollback()
        print(f"❌ Erreur génération articles: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({
            'success': False,
            'message': f'Erreur: {str(e)}'
        }), 500


