@app.route('/api/admin/articles/export/csv')
@login_required
def export_articles_csv():
    """Exporte les articles au format CSV"""
    if current_user.role != 'super_admin':
        flash('Accès réservé aux super administrateurs', 'error')
        return redirect(url_for('dashboard'))
    
    from models import Article
    import csv
    from io import StringIO
    
    articles = Article.query.all()
    
    si = StringIO()
    cw = csv.writer(si)
    cw.writerow(['ID', 'Titre', 'Slug', 'Catégorie', 'Auteur', 'Date', 'Publié', 'Vues'])
    
    for a in articles:
        cw.writerow([
            a.id,
            a.titre,
            a.slug,
            a.categorie.nom if a.categorie else '',
            a.auteur.nom_complet if a.auteur else '',
            a.date_publication.strftime('%Y-%m-%d'),
            'Oui' if a.est_publie else 'Non',
            a.nb_vues
        ])
    
    output = si.getvalue()
    si.close()
    
    return Response(
        output,
        mimetype='text/csv',
        headers={'Content-Disposition': 'attachment; filename=articles.csv'}
    )


# ================================================
# ==========   FONCTION UTILITAIRE   =============
# ================================================

def slugify(text):
    """Convertit un texte en slug URL-friendly"""
    import re
    if not text:
        return ''
    
    # Normalisation
    text = text.lower()
    
    # Remplacer les accents
    accents = {
        'à': 'a', 'á': 'a', 'â': 'a', 'ã': 'a', 'ä': 'a',
        'è': 'e', 'é': 'e', 'ê': 'e', 'ë': 'e',
        'ì': 'i', 'í': 'i', 'î': 'i', 'ï': 'i',
        'ò': 'o', 'ó': 'o', 'ô': 'o', 'õ': 'o', 'ö': 'o',
        'ù': 'u', 'ú': 'u', 'û': 'u', 'ü': 'u',
        'ý': 'y', 'ÿ': 'y',
        'ç': 'c', 'ñ': 'n'
    }
    
    for accented, unaccented in accents.items():
        text = text.replace(accented, unaccented)
    
    # Remplacer les caractères non-alphanumériques par des tirets
    text = re.sub(r'[^a-z0-9]+', '-', text)
    
    # Enlever les tirets au début et à la fin
    text = text.strip('-')
    
    return text



