def verify_user_permissions(user_id):
    """Vérifie et corrige les permissions problématiques d'un utilisateur"""
    user = User.query.get(user_id)
    if not user or not user.client or not user.client.formule:
        return False
    
    formule = user.client.formule
    problems = []
    
    # Vérifier chaque permission
    for perm_key, is_active in user.permissions.items():
        # Vérifier si la formule permet cette permission
        if perm_key in formule.permissions_template:
            if not formule.permissions_template[perm_key] and is_active:
                problems.append({
                    'permission': perm_key,
                    'user_has': True,
                    'formule_allows': False
                })
        
        # Vérifier les permissions liées aux modules
        permission_module_map = {
            'can_manage_regulatory': 'veille',
            'can_manage_logigram': 'processus'
        }
        
        if perm_key in permission_module_map:
            module = permission_module_map[perm_key]
            if not formule.can_access_module(module) and is_active:
                problems.append({
                    'permission': perm_key,
                    'user_has': True,
                    'module_accessible': False,
                    'module': module
                })
    
    # Si problèmes, corriger automatiquement
    if problems:
        print(f"⚠️ Problèmes détectés pour {user.username}:")
        for problem in problems:
            print(f"  - {problem['permission']}: activée mais non autorisée")
        
        # Corriger
        for problem in problems:
            user.permissions[problem['permission']] = False
        
        user.updated_at = datetime.utcnow()
        
        try:
            db.session.commit()
            print(f"✅ Permissions corrigées pour {user.username}")
            return True
        except Exception as e:
            db.session.rollback()
            print(f"❌ Erreur correction: {e}")
