@app.route('/admin/refresh-sqlalchemy-cache')
@login_required
def refresh_sqlalchemy_cache_route():
    """Route pour réinitialiser manuellement le cache SQLAlchemy"""
    
    # Autoriser super admin et admin client
    if not (current_user.role == 'super_admin' or 
            (current_user.role == 'admin' and current_user.is_client_admin)):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('dashboard'))
    
    try:
        refresh_sqlalchemy_cache()
        
        # Tester une requête sur alertes
        from sqlalchemy import text
        
        try:
            # Vérifier que la requête fonctionne maintenant
            test_result = db.session.execute(text(
                "SELECT id, titre, client_id FROM alertes WHERE created_by = :user_id LIMIT 1"
            ), {'user_id': current_user.id}).fetchone()
            
            test_success = test_result is not None
            
            return jsonify({
                'success': True,
                'message': 'Cache SQLAlchemy réinitialisé avec succès',
                'test_query': 'OK' if test_success else 'Erreur',
                'test_result': str(test_result) if test_result else None
            })
            
        except Exception as test_error:
            return jsonify({
                'success': False,
                'message': 'Cache réinitialisé mais requête test échouée',
                'error': str(test_error)
            })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    
        
@app.route('/admin/utilisateur/<int:id>/supprimer', methods=['POST'])
@login_required
def admin_supprimer_utilisateur(id):
    """Supprimer un utilisateur avec gestion des dépendances"""
    
    # Vérifier la permission
    if not current_user.has_permission('can_edit_users'):
        flash('Permission non autorisée', 'error')
        return redirect(url_for('admin_utilisateurs'))
    
    user = User.query.get_or_404(id)
    
    # Vérifier l'accès
    if current_user.role != 'super_admin':
        if user.client_id != current_user.client_id:
            flash('Accès non autorisé à cet utilisateur', 'error')
            return redirect(url_for('admin_utilisateurs'))
        
        # Empêcher un admin client de supprimer un autre admin client
        if user.is_client_admin and user.id != current_user.id:
            flash('Vous ne pouvez pas supprimer un autre administrateur client', 'error')
            return redirect(url_for('admin_utilisateurs'))
    
    # Empêcher l'utilisateur de se supprimer lui-même
    if user.id == current_user.id:
        flash('Vous ne pouvez pas supprimer votre propre compte', 'error')
        return redirect(url_for('admin_utilisateurs'))
    
    # Utiliser la fonction de suppression sécurisée
    result = delete_user_safely(id, current_user.id)
    
    if result['success']:
        # Journaliser
        log_activity(current_user.id, 'suppression_utilisateur',
                    f"Suppression utilisateur {result['username']}",
                    'utilisateur', id)
        
        flash(f"✅ Utilisateur {result['username']} supprimé avec succès", 'success')
        
        # Afficher les dépendances gérées
        if result.get('dependencies'):
            flash(f"📋 Dépendances gérées: {', '.join(result['dependencies'])}", 'info')
    else:
        flash(f'❌ Erreur lors de la suppression: {result["error"]}', 'error')
    
    return redirect(url_for('admin_utilisateurs'))


def has_permission(self, permission):
    """Vérifie si l'utilisateur a une permission spécifique - VERSION CORRIGÉE"""
    
    # DEBUG logging
    print(f"🔐 [DEBUG] Vérification permission '{permission}' pour {self.username} (rôle: {self.role}, client_admin: {self.is_client_admin})")
    
    # 1. SUPER ADMIN : TOUJOURS AUTORISÉ
    if self.role == 'super_admin':
        print(f"   ✅ Super admin - accès immédiat")
        return True
    
    # 2. Vérifier d'abord les permissions EXPLICITES dans la base (PRIORITÉ MAX)
    if self.permissions and isinstance(self.permissions, dict):
        if permission in self.permissions:
            value = bool(self.permissions[permission])
            print(f"   📋 Permission explicite dans DB: {value}")
            return value
    
    # 3. ADMIN CLIENT : Permissions automatiques étendues
    if self.is_client_admin or self.role == 'admin':
        print(f"   👑 Utilisateur est un ADMIN CLIENT")
        
        # TOUTES les permissions pour admin client (sauf super admin)
        admin_client_permissions = {
            # Tableau de bord et visualisation
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_export_data': True,
            'can_view_notifications': True,  # ← AJOUTÉ
            
            # Gestion des données
            'can_view_departments': True,
            'can_manage_departments': True,
            'can_access_all_departments': True,
            'can_archive_data': True,
            
            # Gestion des utilisateurs (COMPLÈTE)
            'can_view_users_list': True,
            'can_create_users': True,
            'can_edit_users': True,
            'can_deactivate_users': True,
            'can_delete_users': True,
            'can_manage_users': True,
            'can_manage_permissions': True,
            'can_block_users': True,
            
            # Gestion des risques
            'can_manage_risks': True,
            'can_validate_risks': True,
            'can_confirm_evaluations': True,
            'can_manage_kri': True,
            
            # Gestion des audits
            'can_manage_audit': True,
            'can_manage_action_plans': True,  # ← AJOUTÉ
            'can_view_action_plans': True,    # ← AJOUTÉ
            
            # Administration système
            'can_manage_settings': True,
            'can_manage_lists': True,
            'can_manage_fields': True,
            'can_manage_files': True,
            'can_manage_templates': True,
            
            # Autres modules (selon formule)
            'can_manage_regulatory': False,  # Sera mis à jour par sync
            'can_manage_logigram': False,    # Sera mis à jour par sync
            'can_use_ia_analysis': False,    # Sera mis à jour par sync
            
            # Permissions système (JAMAIS pour admin client)
            'can_manage_clients': False,
            'can_provision_servers': False
        }
        
        if permission in admin_client_permissions:
            value = admin_client_permissions[permission]
            print(f"   ✅ Admin client - permission automatique: {value}")
            return value
    
    # 4. GESTIONNAIRE (manager) : Permissions complètes
    if self.role == 'manager' or getattr(self, 'can_manage_users', False):
        print(f"   👤 Utilisateur est un GESTIONNAIRE")
        
        manager_permissions = {
            # Gestion utilisateurs (COMPLÈTE)
            'can_create_users': True,          # ← AJOUTÉ
            'can_edit_users': True,            # ← AJOUTÉ
            'can_deactivate_users': True,      # ← AJOUTÉ
            'can_delete_users': True,          # ← AJOUTÉ
            'can_view_users_list': True,
            'can_manage_users': True,
            'can_manage_permissions': True,
            'can_block_users': True,           # ← AJOUTÉ
            
            # Visualisation
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_export_data': True,
            'can_view_notifications': True,
            'can_view_action_plans': True,      # ← AJOUTÉ
            'can_view_departments': True,
            'can_access_all_departments': True,
            
            # Gestion risques
            'can_manage_risks': True,
            'can_validate_risks': True,
            'can_confirm_evaluations': True,
            'can_manage_kri': True,
            
            # Gestion audit
            'can_manage_audit': True,
            'can_manage_action_plans': True,    # ← AJOUTÉ
            
            # Administration
            'can_archive_data': True,
            
            # Paramétrage (LIMITÉ)
            'can_manage_settings': False,
            'can_manage_departments': False,
            
            # Système (JAMAIS)
            'can_manage_clients': False,
            'can_provision_servers': False,
            'can_delete_data': False
        }
        
        if permission in manager_permissions:
            value = manager_permissions[permission]
            print(f"   ✅ Gestionnaire - permission automatique: {value}")
            return value
    
    # 5. Permissions par DÉFAUT selon le rôle
    role_defaults = {
        'auditeur': {
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_view_notifications': True,
            'can_view_departments': True,
            'can_manage_audit': True,
            'can_view_action_plans': True
        },
        'utilisateur': {
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_view_notifications': True,
            'can_view_departments': True,
            'can_view_users_list': True,       # ← AJOUTÉ
            'can_view_action_plans': True       # ← AJOUTÉ
        },
        'compliance': {
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_view_notifications': True,
            'can_view_departments': True,
            'can_manage_regulatory': True,
            'can_view_action_plans': True
        },
        'consultant': {
            'can_view_dashboard': True,
            'can_view_reports': True,
            'can_view_notifications': True,
            'can_view_departments': True
        }
    }
    
    if self.role in role_defaults and permission in role_defaults[self.role]:
        value = role_defaults[self.role][permission]
        print(f"   📋 Permission par défaut pour rôle '{self.role}': {value}")
        return value
    
    print(f"   ❌ Permission '{permission}' REFUSÉE par défaut")
    return False

@app.route('/api/fix-all-managers-now')
@login_required
@super_admin_required
def fix_all_managers_now():
    """Corrige TOUS les gestionnaires immédiatement"""
    
    try:
        # Trouver tous les gestionnaires
        managers = User.query.filter(
            db.or_(
                User.role == 'manager',
                User.can_manage_users == True
            )
        ).all()
        
        print(f"🔧 Correction de {len(managers)} gestionnaires...")
        
        for manager in managers:
            print(f"  👤 {manager.username} (rôle: {manager.role})")
            
            # Initialiser permissions si nécessaire
            if manager.permissions is None:
                manager.permissions = {}
            
            # Permissions OBLIGATOIRES pour gestionnaire
            required_permissions = {
                'can_create_users': True,
                'can_edit_users': True,
                'can_deactivate_users': True,
                'can_delete_users': True,
                'can_view_users_list': True,
                'can_manage_users': True,
                'can_manage_permissions': True,
                'can_block_users': True,
                'can_manage_risks': True,
                'can_manage_kri': True,
                'can_manage_audit': True,
                'can_manage_action_plans': True,
                'can_view_action_plans': True,
                'can_view_dashboard': True,
                'can_view_reports': True,
                'can_view_departments': True,
                'can_export_data': True,
                'can_archive_data': True
            }
            
            # Appliquer toutes les permissions manquantes
            for perm, value in required_permissions.items():
                if not manager.permissions.get(perm, False):
                    manager.permissions[perm] = value
                    print(f"    ➕ {perm} = {value}")
            
            # Activer le flag
            manager.can_manage_users = True
            
            manager.updated_at = datetime.utcnow()
        
        db.session.commit()
        
        flash(f'✅ {len(managers)} gestionnaires corrigés avec succès !', 'success')
        
        return jsonify({
            'success': True,
            'managers_fixed': len(managers),
            'message': f'{len(managers)} gestionnaires corrigés'
        })
        
    except Exception as e:
        db.session.rollback()
        print(f"❌ Erreur: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e)}), 500

