@app.route('/super-admin/client/nouveau', methods=['GET', 'POST'])
@login_required
@super_admin_required
def super_admin_nouveau_client():
    """Créer un nouveau client avec sous-domaine automatique"""
    
    from forms_admin import NouveauClientForm
    import secrets
    import string
    import re
    from datetime import datetime, timezone
    
    form = NouveauClientForm()
    
    # Récupérer les formules disponibles
    formules_disponibles = FormuleAbonnement.query.filter_by(is_active=True).order_by(FormuleAbonnement.ordre_affichage).all()
    
    # Mettre à jour les choix du champ plan
    form.plan.choices = [(f.code, f"{f.nom} ({f.prix_mensuel}€/mois)") for f in formules_disponibles]
    
    # ===== FONCTION DE GÉNÉRATION DE MOT DE PASSE SÉCURISÉ =====
    def generate_secure_password(length=12):
        """
        Génère un mot de passe conforme aux règles :
        - Au moins une majuscule
        - Au moins une minuscule
        - Au moins un chiffre
        - Au moins un caractère spécial
        """
        lowercase = string.ascii_lowercase
        uppercase = string.ascii_uppercase
        digits = string.digits
        special = "!@#$%^&*()_+-=[]{}|;:,.<>?"
        
        # Garantir au moins un de chaque type
        password = [
            secrets.choice(lowercase),
            secrets.choice(uppercase),
            secrets.choice(digits),
            secrets.choice(special)
        ]
        
        # Remplir le reste
        all_chars = lowercase + uppercase + digits + special
        for _ in range(length - 4):
            password.append(secrets.choice(all_chars))
        
        # Mélanger pour éviter que les caractères garantis soient en début
        secrets.SystemRandom().shuffle(password)
        
        return ''.join(password)
    
    if form.validate_on_submit():
        print("✅ Formulaire validé")
        print(f"📋 Données reçues - sous_domaine: {form.sous_domaine.data}")
        print(f"📧 Email contact saisi: {form.contact_email.data}")
        
        try:
            # ===== VALIDATIONS PRÉALABLES =====
            
            # 1. Vérifier si la référence existe déjà
            existing_client_ref = Client.query.filter_by(reference=form.reference.data).first()
            if existing_client_ref:
                flash(f'❌ La référence "{form.reference.data}" est déjà utilisée par un autre client', 'error')
                return render_template('super_admin/nouveau_client.html', form=form, formules=formules_disponibles)
            
            # Trouver la formule sélectionnée
            formule_selectionnee = FormuleAbonnement.query.filter_by(code=form.plan.data).first()
            if not formule_selectionnee:
                flash('Formule sélectionnée introuvable', 'error')
                return redirect(url_for('super_admin_nouveau_client'))
            
            # ===== 1. CRÉER LE CLIENT =====
            client = Client(
                nom=form.nom.data,
                reference=form.reference.data,
                description=form.description.data,
                contact_nom=form.contact_nom.data,
                contact_email=form.contact_email.data,
                contact_telephone=form.contact_telephone.data,
                domaine=form.domaine.data if form.domaine.data else None,
                plan=form.plan.data,
                formule_id=formule_selectionnee.id,
                max_utilisateurs=formule_selectionnee.max_utilisateurs,
                max_risques=formule_selectionnee.max_risques,
                max_audits=formule_selectionnee.max_audits,
                date_activation=datetime.now(timezone.utc).date(),
                is_active=True
            )
            
            # Générer les identifiants API
            client.generer_identifiants_api()
            
            db.session.add(client)
            db.session.flush()  # Pour obtenir l'ID du client
            print(f"✅ Client créé avec ID: {client.id}")
            
            # ===== 2. DÉTERMINER LE SOUS-DOMAINE =====
            sous_domaine_value = form.sous_domaine.data
            
            # Si le formulaire a un sous-domaine complet (ex: client1.egalyx.com)
            if sous_domaine_value and '.' in sous_domaine_value:
                match = re.match(r'^([a-z0-9][a-z0-9-]*[a-z0-9])\.', sous_domaine_value)
                if match:
                    sous_domaine_value = match.group(1)
                else:
                    # Nettoyer le sous-domaine
                    sous_domaine_value = sous_domaine_value.split('.')[0]
            
            # Si pas de sous-domaine fourni, en générer un automatiquement
            if not sous_domaine_value:
                # Générer à partir de la référence ou du nom
                base = form.reference.data.lower().replace('_', '-').replace(' ', '-')
                # Nettoyer les caractères spéciaux
                base = re.sub(r'[^a-z0-9-]', '', base)
                
                if not base:
                    base = f"client-{client.id}"
                
                sous_domaine_value = base
            
            print(f"🌐 Sous-domaine à utiliser: {sous_domaine_value}")
            
            # Vérifier si le sous-domaine existe déjà
            existing_env = EnvironnementClient.query.filter_by(sous_domaine=sous_domaine_value).first()
            if existing_env:
                # Ajouter un suffixe pour le rendre unique
                base = sous_domaine_value
                compteur = 1
                while EnvironnementClient.query.filter_by(sous_domaine=f"{base}-{compteur}").first():
                    compteur += 1
                sous_domaine_value = f"{base}-{compteur}"
                print(f"🔄 Sous-domaine déjà pris, nouveau: {sous_domaine_value}")
            
            # ===== 3. CRÉER L'ENVIRONNEMENT AVEC LE SOUS-DOMAINE =====
            env = EnvironnementClient(
                client_id=client.id,
                nom=form.environnement_nom.data or f"Production - {client.nom}",
                sous_domaine=sous_domaine_value,
                url_acces=f"https://{sous_domaine_value}.egalyx.com",
                statut='actif',
                created_at=datetime.now(timezone.utc),
                updated_at=datetime.now(timezone.utc)
            )
            
            db.session.add(env)
            print(f"✅ Environnement créé: {env.nom} avec sous-domaine {sous_domaine_value}")
            
            # ===== 4. CRÉER L'ABONNEMENT =====
            abonnement = AbonnementClient(
                client_id=client.id,
                formule_id=formule_selectionnee.id,
                date_debut=datetime.now(timezone.utc).date(),
                periode='mensuel',
                statut='actif',
                is_renouvellement_auto=True,
                montant=formule_selectionnee.prix_mensuel,
                methode_paiement='manuel',
                reference_paiement=f"CREATION-{client.reference}"
            )
            db.session.add(abonnement)
            
            # ===== 5. CRÉER L'ADMIN CLIENT AVEC LE BON EMAIL =====
            admin_password = generate_secure_password(12)
            
            # ✅ DÉTERMINER L'EMAIL DE L'ADMIN (CORRECTION ICI)
            admin_email = None
            email_source = "généré automatiquement"
            
            if form.contact_email.data:
                # Vérifier si l'email saisi est déjà utilisé
                existing_user = User.query.filter_by(email=form.contact_email.data).first()
                if existing_user:
                    # Email déjà pris → générer un email unique
                    admin_email = f"admin.{client.reference}@{sous_domaine_value}.egalyx.com"
                    email_source = "généré automatiquement (email déjà utilisé)"
                    flash(f'⚠️ L\'email "{form.contact_email.data}" est déjà utilisé. Email généré automatiquement: {admin_email}', 'warning')
                    print(f"⚠️ Email déjà utilisé: {form.contact_email.data} -> utilisation de {admin_email}")
                else:
                    # Email disponible → l'utiliser
                    admin_email = form.contact_email.data
                    email_source = "email saisi"
                    print(f"✅ Utilisation de l'email saisi: {admin_email}")
            else:
                # Aucun email saisi → générer automatiquement
                admin_email = f"admin.{client.reference}@{sous_domaine_value}.egalyx.com"
                email_source = "généré automatiquement (aucun email saisi)"
                print(f"ℹ️ Aucun email saisi, génération automatique: {admin_email}")
            
            # Créer l'admin avec le bon email
            admin = User(
                username=f"admin_{client.reference}",
                email=admin_email,
                role='admin',
                client_id=client.id,
                is_client_admin=True,
                is_active=True,
                department='Administration',
                permissions=formule_selectionnee.get_role_permissions('admin') if hasattr(formule_selectionnee, 'get_role_permissions') else {}
            )
            admin.set_password(admin_password)
            db.session.add(admin)
            
            # ===== 6. METTRE À JOUR LES MÉTRIQUES =====
            client.nb_utilisateurs = 1
            
            # ===== 7. CONFIGURER LE SERVEUR DÉDIÉ SI DEMANDÉ =====
            if form.provisionner_serveur.data:
                env.server_ip = f"10.0.0.{client.id}"
                env.server_port = 22
                env.server_ssh_user = f"client_{client.reference}"
                env.cpu_alloue = '2 cores'
                env.ram_alloue = '4GB'
                env.stockage_alloue = '50GB'
                env.date_provision = datetime.now(timezone.utc)
            
            # ===== 8. JOURNALISER =====
            journal = JournalActiviteClient(
                client_id=client.id,
                utilisateur_id=current_user.id,
                action='creation_client',
                details={
                    'nom': client.nom,
                    'reference': client.reference,
                    'formule': formule_selectionnee.nom,
                    'sous_domaine': sous_domaine_value,
                    'admin_username': admin.username,
                    'admin_email': admin.email,
                    'email_source': email_source
                }
            )
            db.session.add(journal)
            
            # ===== 9. COMMIT FINAL =====
            db.session.commit()
            
            # ===== 10. ENVOI DES EMAILS =====
            try:
                # Récupérer l'environnement pour l'email
                env = EnvironnementClient.query.filter_by(client_id=client.id).first()
                
                # Appel à la fonction d'envoi d'email
                send_client_creation_email(client, admin, admin_password, env)
                print(f"📧 Email de confirmation envoyé à {admin.email}")
                flash('📧 Email de confirmation envoyé au client', 'info')
            except Exception as e:
                print(f"⚠️ Erreur envoi email client: {e}")
                flash('⚠️ Client créé mais échec de l\'envoi d\'email', 'warning')
            
            # ===== 11. AFFICHAGE DES INFORMATIONS =====
            print(f"""
            ===========================================
            ✅ CLIENT CRÉÉ AVEC SUCCÈS
            ===========================================
            Client: {client.nom}
            Référence: {client.reference}
            Sous-domaine: {sous_domaine_value}.egalyx.com
            URL: https://{sous_domaine_value}.egalyx.com
            
            ADMIN:
            Username: {admin.username}
            Password: {admin_password}
            Email: {admin.email} ({email_source})
            ===========================================
            """)
            
            flash(f'✅ Client {client.nom} créé avec succès !', 'success')
            flash(f'🌐 URL: https://{sous_domaine_value}.egalyx.com', 'info')
            flash(f'👤 Admin: {admin.username} / {admin_password}', 'warning')
            
            return redirect(url_for('super_admin_client_detail', id=client.id))
            
        except Exception as e:
            db.session.rollback()
            print(f"❌ Erreur création client: {str(e)}")
            import traceback
            traceback.print_exc()
            
            # Messages d'erreur plus clairs
            error_msg = str(e)
            if "UNIQUE constraint failed: user.email" in error_msg:
                flash('❌ Erreur: Cet email est déjà utilisé par un autre utilisateur. Veuillez utiliser un email différent.', 'error')
            elif "UNIQUE constraint failed: client.reference" in error_msg:
                flash('❌ Erreur: Cette référence est déjà utilisée par un autre client.', 'error')
            else:
                flash(f'❌ Erreur création client: {error_msg}', 'error')
    else:
        # Afficher les erreurs de validation
        if form.errors:
            print("❌ Erreurs de validation:")
            for field, errors in form.errors.items():
                for error in errors:
                    flash(f'❌ {getattr(form, field).label.text}: {error}', 'error')
                print(f"  {field}: {errors}")
    
    return render_template('super_admin/nouveau_client.html', 
                         form=form, 
                         formules=formules_disponibles)



