@app.route('/api/client/<int:client_id>/reset-admin-password', methods=['POST'])
@login_required
@super_admin_required
@csrf.exempt  # Désactiver CSRF pour cette API
def api_reset_client_admin_password(client_id):
    """Réinitialiser le mot de passe admin d'un client"""
    try:
        client = Client.query.get_or_404(client_id)
        
        # Trouver l'admin client (le premier admin créé pour ce client)
        admin_user = User.query.filter_by(
            client_id=client_id,
            is_client_admin=True
        ).first()
        
        if not admin_user:
            # Chercher aussi par rôle admin
            admin_user = User.query.filter_by(
                client_id=client_id,
                role='admin'
            ).first()
            
        if not admin_user:
            return jsonify({
                'success': False,
                'error': 'Admin client non trouvé'
            }), 404
        
        # Générer un nouveau mot de passe
        import secrets
        new_password = secrets.token_urlsafe(12)
        admin_user.set_password(new_password)
        admin_user.updated_at = datetime.utcnow()
        
        # Journaliser
        journal = JournalActiviteClient(
            client_id=client_id,
            utilisateur_id=current_user.id,
            action='reset_admin_password',
            details={
                'admin_username': admin_user.username,
                'by': current_user.username,
                'timestamp': datetime.utcnow().isoformat()
            },
            ip_address=request.remote_addr if request else None,
            user_agent=request.user_agent.string if request else None
        )
        db.session.add(journal)
        
        db.session.commit()
        
        print(f"✅ Mot de passe réinitialisé pour admin client: {admin_user.username}")
        
        return jsonify({
            'success': True,
            'username': admin_user.username,
            'email': admin_user.email,
            'password': new_password,  # À utiliser immédiatement puis effacer
            'message': f'Mot de passe réinitialisé pour {admin_user.username}',
            'warning': 'Notez ce mot de passe car il ne sera plus affiché'
        })
        
    except Exception as e:
        db.session.rollback()
        print(f"❌ Erreur réinitialisation mot de passe: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500




