@app.route('/api/super-admin/<int:admin_id>/toggle', methods=['POST'])
@login_required
def api_toggle_super_admin(admin_id):
    """Activer/désactiver un super admin"""
    if current_user.role != 'super_admin':
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    # On ne peut pas se désactiver soi-même
    if admin_id == current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas vous désactiver vous-même'}), 400
    
    admin = User.query.get_or_404(admin_id)
    
    # Vérifier que c'est bien un super admin
    if admin.role != 'super_admin':
        return jsonify({'error': 'Cet utilisateur n\'est pas un super admin'}), 400
    
    try:
        admin.is_active = not admin.is_active
        new_status = 'activé' if admin.is_active else 'désactivé'
        
        db.session.commit()
        
        # Journaliser
        log_activity(current_user.id, 'toggle_super_admin',
                    f"Super admin {admin.username} {new_status}",
                    'user', admin.id)
        
        return jsonify({
            'success': True,
            'message': f'Super admin {admin.username} {new_status}',
            'is_active': admin.is_active
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

@app.route('/api/super-admin/<int:admin_id>/reset-password', methods=['POST'])
@login_required
def api_reset_super_admin_password(admin_id):
    """Réinitialiser le mot de passe d'un super admin"""
    if current_user.role != 'super_admin':
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    admin = User.query.get_or_404(admin_id)
    
    # Vérifier que c'est bien un super admin
    if admin.role != 'super_admin':
        return jsonify({'error': 'Cet utilisateur n\'est pas un super admin'}), 400
    
    try:
        data = request.get_json()
        new_password = data.get('password')
        
        if not new_password or len(new_password) < 8:
            return jsonify({'error': 'Le mot de passe doit avoir au moins 8 caractères'}), 400
        
        admin.set_password(new_password)
        db.session.commit()
        
        # Journaliser (sans le mot de passe)
        log_activity(current_user.id, 'reset_super_admin_password',
                    f"Mot de passe réinitialisé pour {admin.username}",
                    'user', admin.id)
        
        return jsonify({
            'success': True,
            'message': f'Mot de passe réinitialisé pour {admin.username}'
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

@app.route('/api/super-admin/<int:admin_id>', methods=['DELETE'])
@login_required
def api_delete_super_admin(admin_id):
    """Supprimer un super admin"""
    if current_user.role != 'super_admin':
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    # On ne peut pas se supprimer soi-même
    if admin_id == current_user.id:
        return jsonify({'error': 'Vous ne pouvez pas vous supprimer vous-même'}), 400
    
    admin = User.query.get_or_404(admin_id)
    
    # Vérifier que c'est bien un super admin
    if admin.role != 'super_admin':
        return jsonify({'error': 'Cet utilisateur n\'est pas un super admin'}), 400
    
    try:
        # Journaliser avant suppression
        log_activity(current_user.id, 'delete_super_admin',
                    f"Suppression super admin {admin.username}",
                    'user', admin.id)
        
        db.session.delete(admin)
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Super admin {admin.username} supprimé'
        })
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

@app.route('/client-admin/utilisateur/<int:id>/editer', methods=['GET', 'POST'])
@login_required
def client_admin_editer_utilisateur(id):
    """Éditer un utilisateur - version admin client"""
    
    # Vérifier que c'est un admin client
    if not current_user.is_client_admin:
        flash('Accès réservé aux administrateurs client', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupérer l'utilisateur
    user = User.query.get_or_404(id)
    client = current_user.client
    
    # Vérifications spécifiques admin client
    if not client:
        flash('Aucun client associé à votre compte', 'error')
        return redirect(url_for('dashboard'))
    
    # Vérifier que l'utilisateur appartient au même client
    if user.client_id != client.id:
        flash('Accès non autorisé à cet utilisateur', 'error')
        return redirect(url_for('client_admin_utilisateurs'))
    
    # Empêcher un admin client de modifier un autre admin client (sauf lui-même)
    if user.is_client_admin and user.id != current_user.id:
        flash('Vous ne pouvez pas modifier un autre administrateur client', 'error')
        return redirect(url_for('client_admin_utilisateurs'))
    
    # Créer le formulaire spécifique pour admin client
    from flask_wtf import FlaskForm
    from wtforms import StringField, PasswordField, SelectField, BooleanField, SubmitField, TextAreaField
    from wtforms.validators import DataRequired, Email, Length, EqualTo, Optional
    
    class EditerUtilisateurClientForm(FlaskForm):
        username = StringField('Nom d\'utilisateur', validators=[
            DataRequired(message='Le nom d\'utilisateur est requis'),
            Length(min=3, max=50, message='Le nom d\'utilisateur doit contenir entre 3 et 50 caractères')
        ])
        email = StringField('Email', validators=[
            DataRequired(message='L\'email est requis'),
            Email(message='Format d\'email invalide'),
            Length(max=120, message='L\'email ne peut pas dépasser 120 caractères')
        ])
        password = PasswordField('Nouveau mot de passe', validators=[
            Optional(),
            Length(min=6, message='Le mot de passe doit avoir au moins 6 caractères')
        ])
        confirm_password = PasswordField('Confirmer le mot de passe', validators=[
            Optional(),
            EqualTo('password', message='Les mots de passe doivent correspondre')
        ])
        role = SelectField('Rôle', choices=[
            ('utilisateur', 'Utilisateur Standard'),
            ('auditeur', 'Auditeur'),
            ('compliance', 'Responsable Conformité'),
            ('manager', 'Manager'),
            ('consultant', 'Consultant')
        ], validators=[DataRequired(message='Le rôle est requis')])
        department = StringField('Département/Service', validators=[
            Optional(),
            Length(max=100, message='Le département ne peut pas dépasser 100 caractères')
        ])
        is_active = BooleanField('Activer le compte', default=True)
        
        # Template de permissions - limité aux templates du client
        template_permissions = SelectField('Template de permissions', 
            choices=[],  # Rempli dynamiquement
            coerce=int, 
            default=0,
            validators=[Optional()])
        
        submit = SubmitField('Mettre à jour')
    
    # Déterminer si c'est l'admin client qui modifie son propre compte
    is_self_edit = (user.id == current_user.id)
    
    # Créer l'instance du formulaire avec les données actuelles
    form = EditerUtilisateurClientForm(
        username=user.username,
        email=user.email,
        role=user.role,
        department=user.department or '',
        is_active=user.is_active
    )
    
    # Remplir les templates de permissions disponibles pour ce client
    try:
        # Récupérer les templates du client ou globaux
        templates = PermissionTemplate.query.filter(
            db.or_(
                PermissionTemplate.client_id == client.id,
                PermissionTemplate.client_id == None,  # Templates globaux
                db.and_(
                    PermissionTemplate.client_id == None,
                    PermissionTemplate.role.in_(['utilisateur', 'auditeur', 'manager', 'compliance', 'consultant'])
                )
            )
        ).all()
        
        form.template_permissions.choices = [(0, 'Aucun template (garder permissions actuelles)')]
        for template in templates:
            form.template_permissions.choices.append((template.id, f"{template.name} ({template.role})"))
        
        # Définir la valeur actuelle si un template est appliqué
        if user.permissions:
            # Chercher si les permissions correspondent à un template
            for template in templates:
                if template.permissions == user.permissions:
                    form.template_permissions.data = template.id
                    break
    
    except Exception as e:
        print(f"⚠️ Erreur chargement templates: {e}")
        form.template_permissions.choices = [(0, 'Erreur chargement templates')]
    
    if form.validate_on_submit():
        try:
            # Vérifier si c'est un self-edit
            if is_self_edit:
                # Pour un self-edit, ne permettre que certains changements
                # Empêcher la modification du rôle et des templates
                if form.role.data != user.role:
                    flash('Vous ne pouvez pas modifier votre propre rôle', 'error')
                    return redirect(url_for('client_admin_editer_utilisateur', id=user.id))
                
                if form.template_permissions.data != 0:
                    # Empêcher l'application d'un template à soi-même
                    flash('Vous ne pouvez pas modifier les templates de permissions sur votre propre compte', 'error')
                    return redirect(url_for('client_admin_editer_utilisateur', id=user.id))
            
            # Mettre à jour les champs de base
            user.username = form.username.data
            user.email = form.email.data
            
            # Ne pas modifier le rôle pour un self-edit
            if not is_self_edit:
                user.role = form.role.data
            
            user.department = form.department.data
            user.is_active = form.is_active.data
            
            # Mettre à jour le mot de passe si fourni
            if form.password.data and form.password.data.strip():
                user.set_password(form.password.data)
            
            # Appliquer template de permissions si sélectionné (uniquement si pas self-edit)
            if not is_self_edit and form.template_permissions.data and int(form.template_permissions.data) != 0:
                template = PermissionTemplate.query.get(form.template_permissions.data)
                if template:
                    user.permissions = template.permissions
            elif form.template_permissions.data == 0:
                # Si "Aucun template" est sélectionné, ne pas modifier les permissions
                pass
            
            user.updated_at = datetime.utcnow()
            
            db.session.commit()
            
            # Journaliser l'action
            journal = JournalActiviteClient(
                client_id=client.id,
                utilisateur_id=current_user.id,
                action='modification_utilisateur',
                details={
                    'user_id': user.id,
                    'username': user.username,
                    'role': user.role,
                    'modifie_par': current_user.username,
                    'is_self_edit': is_self_edit
                }
            )
            db.session.add(journal)
            db.session.commit()
            
            flash(f'✅ Utilisateur {user.username} mis à jour avec succès', 'success')
            return redirect(url_for('client_admin_utilisateurs'))
            
        except Exception as e:
            db.session.rollback()
            print(f"❌ Erreur mise à jour utilisateur: {str(e)}")
            import traceback
            traceback.print_exc()
            flash(f'❌ Erreur lors de la mise à jour: {str(e)}', 'error')
    
    return render_template('client_admin/editer_utilisateur.html', 
                         form=form, 
                         user=user,
                         client=client,
                         current_user=current_user,
                         is_self_edit=is_self_edit)  # <-- Ajouter cette variable


@app.route('/client-admin/utilisateur/creer-gestionnaire', methods=['GET', 'POST'])
@login_required
def client_admin_creer_gestionnaire():
    """Créer un gestionnaire d'utilisateurs - version admin client CORRIGÉE"""
    
    from datetime import datetime, timezone
    
    print(f"🔍 DEBUG: Route appelée - client_admin_creer_gestionnaire")
    
    if not current_user.is_client_admin:
        flash('Accès réservé aux administrateurs client', 'error')
        return redirect(url_for('dashboard'))
    
    client = current_user.client
    if not client:
        flash('Aucun client associé à votre compte', 'error')
        return redirect(url_for('dashboard'))
    
    # Vérifier la limite d'utilisateurs
    current_count = User.query.filter_by(client_id=client.id, is_active=True).count()
    max_users = client.formule.max_utilisateurs if client.formule else 10
    
    if current_count >= max_users:
        flash(f'Limite d\'utilisateurs atteinte ({max_users}). Veuillez mettre à jour votre formule.', 'error')
        return redirect(url_for('client_admin_utilisateurs'))
    
    # Formulaire spécifique pour les gestionnaires
    from flask_wtf import FlaskForm
    from wtforms import StringField, PasswordField, SelectField, BooleanField, SubmitField
    from wtforms.validators import DataRequired, Email, Length, EqualTo
    
    class CreerGestionnaireForm(FlaskForm):
        username = StringField('Nom d\'utilisateur', validators=[
            DataRequired(message='Le nom d\'utilisateur est requis')
        ])
        email = StringField('Email', validators=[
            DataRequired(message='L\'email est requis'),
            Email(message='Format d\'email invalide')
        ])
        password = PasswordField('Mot de passe', validators=[
            DataRequired(message='Le mot de passe est requis'),
            Length(min=6, message='Le mot de passe doit avoir au moins 6 caractères')
        ])
        confirm_password = PasswordField('Confirmer le mot de passe', validators=[
            DataRequired(message='Veuillez confirmer le mot de passe'),
            EqualTo('password', message='Les mots de passe doivent correspondre')
        ])
        
        # Rôles possibles pour les gestionnaires (pas admin)
        role = SelectField('Rôle', 
            choices=[
                ('manager', 'Manager'),
                ('auditeur', 'Auditeur'),
                ('compliance', 'Responsable Conformité'),
                ('consultant', 'Consultant'),
                ('utilisateur', 'Utilisateur Standard')
            ],
            default='manager',
            validators=[DataRequired()]
        )
        
        # Permissions de gestion d'utilisateurs
        can_view_users_list = BooleanField('Peut voir la liste des utilisateurs', default=True)
        can_edit_users = BooleanField('Peut éditer les utilisateurs (sauf admin)', default=True)
        can_create_users = BooleanField('Peut créer de nouveaux utilisateurs', default=True)
        can_deactivate_users = BooleanField('Peut activer/désactiver les comptes', default=True)
        can_delete_users = BooleanField('Peut supprimer (désactiver) les utilisateurs', default=True)
        
        # Permissions métier
        can_manage_risks = BooleanField('Peut gérer les risques', default=True)
        can_validate_risks = BooleanField('Peut valider les risques', default=True)
        can_confirm_evaluations = BooleanField('Peut confirmer les évaluations', default=True)
        can_manage_kri = BooleanField('Peut gérer les KRI', default=True)
        can_manage_audit = BooleanField('Peut gérer les audits', default=True)
        can_manage_regulatory = BooleanField('Peut gérer la veille réglementaire', default=False)
        can_manage_logigram = BooleanField('Peut gérer les logigrammes', default=False)
        can_manage_departments = BooleanField('Peut gérer les directions/services', default=False)
        can_access_all_departments = BooleanField('Peut accéder à tous les départements', default=True)
        can_export_data = BooleanField('Peut exporter des données', default=True)
        can_archive_data = BooleanField('Peut archiver des données', default=True)
        
        department = StringField('Département')
        is_active = BooleanField('Activer le compte immédiatement', default=True)
        submit = SubmitField('Créer le gestionnaire')
    
    form = CreerGestionnaireForm()
    
    if form.validate_on_submit():
        print("✅ Formulaire de création gestionnaire validé avec succès!")
        
        try:
            # Vérifier les limites
            if client.formule:
                current_count = User.query.filter_by(
                    client_id=client.id, 
                    is_active=True
                ).count()
                
                if current_count >= client.formule.max_utilisateurs:
                    flash(f'❌ Limite atteinte pendant la création. Veuillez réessayer.', 'error')
                    return redirect(url_for('client_admin_creer_gestionnaire'))
            
            # Vérifier si l'utilisateur existe déjà
            existing_user = User.query.filter(
                db.or_(
                    User.username == form.username.data,
                    User.email == form.email.data
                ),
                User.client_id == client.id
            ).first()
            
            if existing_user:
                flash(f'Un utilisateur avec ce nom ou email existe déjà dans votre client', 'error')
                return redirect(url_for('client_admin_creer_gestionnaire'))
            
            now_utc = datetime.now(timezone.utc)
            
            # Créer l'utilisateur
            user = User(
                username=form.username.data,
                email=form.email.data,
                role=form.role.data,
                department=form.department.data or '',
                is_active=form.is_active.data,
                client_id=client.id,
                is_client_admin=False,
                can_view_users_list=True,
                can_manage_users=True,
                created_at=now_utc
            )
            
            # Définir le mot de passe
            user.set_password(form.password.data)
            
            # Fonction helper pour récupérer les valeurs des champs BooleanField
            def get_bool_field(field_name, default=True):
                if hasattr(form, field_name):
                    field = getattr(form, field_name)
                    if hasattr(field, 'data'):
                        return field.data
                return default
            
            permissions = {
                # Permissions de base
                'can_view_dashboard': True,
                'can_view_reports': True,
                'can_export_data': get_bool_field('can_export_data', True),
                'can_view_departments': True,
                'can_view_users_list': True,
                'can_view_notifications': True,
                'can_view_action_plans': True,
                
                # Permissions de gestion d'utilisateurs
                'can_edit_users': get_bool_field('can_edit_users', True),
                'can_create_users': get_bool_field('can_create_users', True),
                'can_deactivate_users': get_bool_field('can_deactivate_users', True),
                'can_delete_users': get_bool_field('can_delete_users', True),
                'can_manage_users': True,
                'can_manage_permissions': True,
                'can_block_users': True,
                
                # Permissions métier
                'can_manage_risks': get_bool_field('can_manage_risks', True),
                'can_validate_risks': get_bool_field('can_validate_risks', True),
                'can_confirm_evaluations': get_bool_field('can_confirm_evaluations', True),
                'can_manage_kri': get_bool_field('can_manage_kri', True),
                'can_manage_audit': get_bool_field('can_manage_audit', True),
                'can_manage_action_plans': True,
                
                # Permissions optionnelles
                'can_manage_regulatory': get_bool_field('can_manage_regulatory', False),
                'can_manage_logigram': get_bool_field('can_manage_logigram', False),
                'can_manage_departments': get_bool_field('can_manage_departments', False),
                'can_access_all_departments': get_bool_field('can_access_all_departments', True),
                'can_archive_data': get_bool_field('can_archive_data', True),
                
                # Permissions désactivées pour gestionnaires
                'can_manage_settings': False,
                'can_delete_data': False,
                'can_manage_clients': False,
                'can_provision_servers': False
            }
            
            # Vérifier la cohérence avec la formule du client
            if client.formule:
                formule = client.formule
                
                # Désactiver les permissions non incluses dans la formule
                for perm in list(permissions.keys()):
                    if perm.startswith('can_') and perm not in formule.permissions_template:
                        permissions[perm] = False
            
            user.permissions = permissions
            
            print(f"📊 DEBUG: Permissions du gestionnaire créé:")
            for perm, value in permissions.items():
                if value:
                    print(f"  ✓ {perm}")
            
            # Sauvegarder
            db.session.add(user)
            
            # Mettre à jour les statistiques du client
            client.nb_utilisateurs = User.query.filter_by(
                client_id=client.id, 
                is_active=True
            ).count()
            
            # Journaliser
            journal = JournalActiviteClient(
                client_id=client.id,
                utilisateur_id=current_user.id,
                action='creation_gestionnaire',
                details={
                    'username': user.username,
                    'email': user.email,
                    'role': user.role,
                    'is_gestionnaire': True,
                    'permissions': {
                        'view_users': permissions.get('can_view_users_list', False),
                        'edit_users': permissions.get('can_edit_users', False),
                        'create_users': permissions.get('can_create_users', False),
                        'deactivate_users': permissions.get('can_deactivate_users', False),
                        'delete_users': permissions.get('can_delete_users', False),
                        'manage_users': True
                    },
                    'created_by': current_user.username
                }
            )
            db.session.add(journal)
            
            # ===== COMMIT =====
            db.session.commit()
            
            # ===== ENVOI EMAIL (après commit) =====
            try:
                send_gestionnaire_creation_email(user, current_user, form.password.data)
                flash('📧 Email envoyé au nouveau gestionnaire', 'info')
            except Exception as e:
                print(f"⚠️ Erreur envoi email gestionnaire: {e}")
                flash('⚠️ Gestionnaire créé mais échec de l\'envoi d\'email', 'warning')
            
            flash(f'✅ Gestionnaire {user.username} créé avec succès', 'success')
            return redirect(url_for('client_admin_utilisateurs'))
            
        except Exception as e:
            db.session.rollback()
            print(f"❌ Erreur création gestionnaire: {str(e)}")
            import traceback
            traceback.print_exc()
            flash(f'❌ Erreur lors de la création: {str(e)}', 'error')
    else:
        # Afficher les erreurs de validation
        if form.errors:
            print("❌ Erreurs de validation du formulaire gestionnaire:")
            for field, errors in form.errors.items():
                print(f"  {field}: {errors}")
            
            # Afficher les messages d'erreur
            for field, errors in form.errors.items():
                if errors:
                    flash(f'Erreur {field}: {errors[0]}', 'error')
    
    # Calculer le pourcentage d'utilisation
    pourcentage = (current_count / max_users * 100) if max_users > 0 else 0
    
    return render_template('client_admin/creer_gestionnaire.html',
                         form=form,
                         client=client,
                         limite=max_users,
                         utilisateurs_actuels=current_count,
                         pourcentage=pourcentage)

@app.route('/gestionnaire/utilisateurs')
@login_required
def gestionnaire_utilisateurs():
    """Gestion des utilisateurs pour les gestionnaires"""
    
    # Vérifier que l'utilisateur est un gestionnaire
    if not current_user.can_manage_users:
        flash('Accès réservé aux gestionnaires', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupérer les utilisateurs du même client
    users = User.query.filter_by(
        client_id=current_user.client_id
    ).filter(
        User.role != 'super_admin'  # Exclure les super admins
    ).order_by(User.username).all()
    
    # Filtrer pour ne pas montrer les autres gestionnaires (sauf lui-même)
    filtered_users = []
    for user in users:
        if not user.can_manage_users or user.id == current_user.id:
            filtered_users.append(user)
    
    # Calculer les statistiques
    stats = {
        'total': len(filtered_users),
        'actifs': len([u for u in filtered_users if u.is_active]),
        'admin_count': len([u for u in filtered_users if u.role == 'admin']),
        'limite': current_user.client.formule.max_utilisateurs if current_user.client and current_user.client.formule else 10,
        'pourcentage': 0
    }
    
    if stats['limite'] > 0:
        stats['pourcentage'] = (stats['total'] / stats['limite']) * 100
    
    return render_template('gestionnaire/utilisateurs.html',
                         users=filtered_users,
                         stats=stats,
                         now=datetime.utcnow())
@app.route('/fix-gestionnaire-permissions')
@login_required
def fix_gestionnaire_permissions():
    """Active toutes les permissions de gestionnaire pour l'utilisateur courant"""
    
    if current_user.role != 'manager':
        flash('Cette fonction est réservée aux gestionnaires', 'error')
        return redirect(url_for('dashboard'))
    
    try:
        # Activer le flag can_manage_users
        current_user.can_manage_users = True
        
        # Ajouter les permissions manquantes
        if current_user.permissions is None:
            current_user.permissions = {}
        
        gestionnaire_permissions = {
            'can_create_users': True,
            'can_edit_users': True,
            'can_deactivate_users': True,
            'can_delete_users': True,
            'can_view_users_list': True,
            'can_manage_permissions': True,
            'can_manage_risks': True,
            'can_manage_kri': True,
            'can_manage_audit': True,
            'can_manage_action_plans': True,
            'can_view_action_plans': True
        }
        
        for perm, value in gestionnaire_permissions.items():
            current_user.permissions[perm] = value
        
        db.session.commit()
        
        flash('✅ Permissions de gestionnaire activées avec succès! Vous pouvez maintenant :', 'success')
        flash('• Créer des utilisateurs', 'info')
        flash('• Modifier des utilisateurs', 'info')
        flash('• Bloquer/débloquer des utilisateurs', 'info')
        flash('• Supprimer des utilisateurs', 'info')
        flash('• Gérer les permissions', 'info')
        
        # Rediriger vers la page de gestion des utilisateurs
        return redirect(url_for('gestionnaire_utilisateurs'))
        
    except Exception as e:
        db.session.rollback()
        flash(f'❌ Erreur: {str(e)}', 'error')
        return redirect(url_for('dashboard'))


