@app.route('/admin/save-parametres', methods=['POST'])
@csrf.exempt
@login_required
@admin_required
def admin_save_parametres():
    """Sauvegarde les paramètres d'évaluation"""
    
    categorie = request.form.get('categorie')
    
    try:
        # Récupérer tous les paramètres de cette catégorie
        parametres = ParametreEvaluation.query.filter_by(categorie=categorie).all()
        
        for param in parametres:
            param_id = str(param.id)
            
            # Mettre à jour les champs
            param.nom_court = request.form.get(f'nom_court_{param_id}', param.nom_court)
            param.description_longue = request.form.get(f'description_{param_id}', '')
            param.couleur_hex = request.form.get(f'couleur_{param_id}', param.couleur_hex)
            param.est_actif = bool(request.form.get(f'actif_{param_id}'))
            
            if categorie == 'maitrise':
                param.ordre = int(request.form.get(f'ordre_{param_id}', param.ordre))
            
            param.updated_at = datetime.utcnow()
        
        db.session.commit()
        
        # SUPPRIMER TOUT CACHE (pas juste une variable)
        if hasattr(app, 'config'):
            app.config.pop('PARAMETRES_CACHE', None)
        
        # Nettoyer le cache de session si nécessaire
        try:
            from flask import session
            session.pop('parametres_cache', None)
        except:
            pass
        
        # FORCER un commit de la session SQLAlchemy pour s'assurer que les données sont persistées
        db.session.flush()
        
        flash(f'✅ Paramètres {categorie} mis à jour avec succès', 'success')
        
        # Journaliser
        log_activity(current_user.id, 'modification_parametres', 
                    f'Modification des paramètres {categorie}', 
                    'parametres_evaluation', None)
        
    except Exception as e:
        db.session.rollback()
        flash(f'❌ Erreur lors de la sauvegarde: {str(e)}', 'error')
    
    return redirect(url_for('admin_parametres_evaluation', _anchor=f'{categorie}-tab'))


