@app.route('/api/parametres-evaluation')
@login_required
def api_parametres_evaluation():
    """API pour récupérer les paramètres d'évaluation (AJAX)"""
    try:
        parametres = ParametreEvaluation.query.filter_by(est_actif=True).all()
        
        result = {
            'impact': {},
            'probabilite': {},
            'maitrise': {},
            'couleurs': {}
        }
        
        for param in parametres:
            result[param.categorie][param.niveau] = {
                'nom_court': param.nom_court,
                'description': param.description_longue,
                'couleur': param.couleur_hex
            }
        
        return jsonify(result)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

