def get_niveau_description(categorie, niveau):
    """Retourne la description d'un niveau spécifique"""
    try:
        param = ParametreEvaluation.query.filter_by(
            categorie=categorie, 
            niveau=niveau,
            est_actif=True
        ).first()
        
        if param and param.description_longue:
            return param.description_longue
    except:
        pass
    
    # Valeurs par défaut
    defaults = {
        'impact': {
            1: "Impact minime sur les objectifs - Pertes < 1% du CA",
            2: "Impact limité sur les objectifs - Pertes 1-5% CA",
            3: "Impact significatif sur les objectifs - Pertes 5-10% CA",
            4: "Impact majeur sur les objectifs - Pertes 10-20% CA",
            5: "Impact catastrophique sur les objectifs - Pertes > 20% CA"
        },
        'probabilite': {
            1: "Moins d'une fois tous les 5 ans - Probabilité < 5%",
            2: "Une fois tous les 1-2 ans - Probabilité 5-20%",
            3: "Plusieurs fois par an - Probabilité 20-50%",
            4: "Une fois par mois - Probabilité 50-80%",
            5: "Une fois par semaine ou plus - Probabilité > 80%"
        },
        'maitrise': {
            1: "Contrôles inexistants ou inefficaces - Aucune documentation",
            2: "Contrôles basiques - Couverture limitée - Documentation incomplète",
            3: "Contrôles standard - Couverture acceptable - Documentation de base",
            4: "Contrôles robustes - Couverture étendue - Documentation complète",
            5: "Contrôles optimisés - Couverture complète - Documentation exemplaire"
        }
    }
    
    return defaults.get(categorie, {}).get(niveau, "Description non disponible")


def get_niveau_nom_court(categorie, niveau):
    """Retourne le nom court d'un niveau"""
    try:
        param = ParametreEvaluation.query.filter_by(
            categorie=categorie, 
            niveau=niveau,
            est_actif=True
        ).first()
        
        if param:
            return param.nom_court
    except:
        pass
    
    # Valeurs par défaut
    defaults = {
        'impact': {1: 'Négligeable', 2: 'Mineur', 3: 'Modéré', 4: 'Important', 5: 'Critique'},
        'probabilite': {1: 'Très rare', 2: 'Rare', 3: 'Possible', 4: 'Probable', 5: 'Très probable'},
        'maitrise': {1: 'Insuffisant', 2: 'Partiel', 3: 'Adéquat', 4: 'Bon', 5: 'Excellent'}
    }
    
    return defaults.get(categorie, {}).get(niveau, f"Niveau {niveau}")


def get_niveau_couleur(categorie, niveau):
    """Retourne la couleur d'un niveau"""
    try:
        param = ParametreEvaluation.query.filter_by(
            categorie=categorie, 
            niveau=niveau,
            est_actif=True
        ).first()
        
        if param and param.couleur_hex:
            return param.couleur_hex
    except:
        pass
    
    # Couleurs par défaut (vert au rouge)
    couleurs = {
        'impact': ['#28a745', '#7ebf45', '#ffc107', '#fd7e14', '#dc3545'],
        'probabilite': ['#28a745', '#7ebf45', '#ffc107', '#fd7e14', '#dc3545'],
        'maitrise': ['#dc3545', '#fd7e14', '#ffc107', '#7ebf45', '#28a745'],  # Inversé
        'phase': {
            'phase1': '#007bff',
            'phase2': '#ffc107', 
            'phase3': '#28a745'
        }
    }
    
    if categorie == 'phase' and niveau in couleurs['phase']:
        return couleurs['phase'][niveau]
    
    if categorie in couleurs and 1 <= niveau <= 5:
        return couleurs[categorie][niveau - 1]
    
    return '#28a745'


def get_parametres_evaluation():
    """Retourne tous les paramètres d'évaluation"""
    return {
        'maitrise_inverse': True  # Pour l'inversion des couleurs de maîtrise
    }


