@app.route('/dispositifs/archives')
@login_required
def dispositifs_archives():
    """Lister tous les dispositifs de maîtrise archivés"""
    
    # Vérifier la permission
    if not current_user.has_permission('can_archive_data'):
        flash('Permission non autorisée', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupérer l'URL de retour
    retour_url = request.args.get('retour', url_for('dashboard'))
    risque_id = request.args.get('risque_id')
    
    # Récupérer les dispositifs archivés avec filtrage client
    query = DispositifMaitrise.query.filter_by(is_archived=True)
    
    if risque_id:
        query = query.filter_by(risque_id=risque_id)
    
    if current_user.role != 'super_admin':
        query = query.filter_by(client_id=current_user.client_id)
    
    dispositifs_archives = query.order_by(DispositifMaitrise.archived_at.desc()).all()
    
    # ========== CALCUL DES STATISTIQUES ==========
    # Compter par type
    stats = {
        'preventifs': sum(1 for d in dispositifs_archives if d.type_dispositif == 'Préventif'),
        'detectifs': sum(1 for d in dispositifs_archives if d.type_dispositif == 'Détectif'),
        'correctifs': sum(1 for d in dispositifs_archives if d.type_dispositif == 'Correctif'),
        'avec_risque': sum(1 for d in dispositifs_archives if d.risque_id is not None),
        # CORRECTION : 'archiveur' -> 'archive_user'
        'avec_archiveur': sum(1 for d in dispositifs_archives if d.archive_user is not None)
    }
    
    # Calculer les dates min et max
    dates_archive = [d.archived_at for d in dispositifs_archives if d.archived_at is not None]
    
    if dates_archive:
        date_plus_ancienne = min(dates_archive)
        date_plus_recente = max(dates_archive)
    else:
        date_plus_ancienne = None
        date_plus_recente = None
    
    # Calculer la répartition par type pourcentage
    total = len(dispositifs_archives)
    if total > 0:
        stats['pourcent_preventifs'] = round((stats['preventifs'] / total) * 100)
        stats['pourcent_detectifs'] = round((stats['detectifs'] / total) * 100)
        stats['pourcent_correctifs'] = round((stats['correctifs'] / total) * 100)
    else:
        stats['pourcent_preventifs'] = 0
        stats['pourcent_detectifs'] = 0
        stats['pourcent_correctifs'] = 0
    
    return render_template('dispositifs/archives.html', 
                         dispositifs=dispositifs_archives,
                         retour_url=retour_url,
                         risque_id=risque_id,
                         stats=stats,
                         date_plus_ancienne=date_plus_ancienne,
                         date_plus_recente=date_plus_recente,
                         total=total)

@app.route('/dispositif/<int:dispositif_id>/supprimer-definitivement', methods=['POST'])
@login_required
def supprimer_definitivement_dispositif(dispositif_id):
    """Supprimer définitivement un dispositif archivé"""
    dispositif = DispositifMaitrise.query.get_or_404(dispositif_id)
    
    if not check_client_access(dispositif):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('dispositifs_archives'))
    
    # Vérifier que c'est bien archivé
    if not dispositif.is_archived:
        flash('Seuls les dispositifs archivés peuvent être supprimés définitivement', 'error')
        return redirect(url_for('dispositifs_archives'))
    
    try:
        # Supprimer les documents associés physiquement
        for doc in dispositif.documents:
            if os.path.exists(doc.chemin_fichier):
                os.remove(doc.chemin_fichier)
            db.session.delete(doc)
        
        # Supprimer les vérifications associées
        VerificationDispositif.query.filter_by(dispositif_id=dispositif_id).delete()
        
        # Supprimer le dispositif
        db.session.delete(dispositif)
        db.session.commit()
        
        flash('Dispositif supprimé définitivement', 'success')
        
    except Exception as e:
        db.session.rollback()
        flash(f'Erreur: {str(e)}', 'error')
    
    return redirect(url_for('dispositifs_archives'))


@app.route('/dispositif/document/<int:doc_id>/telecharger')
@login_required
def telecharger_document_dispositif(doc_id):
    """Télécharger un document attaché à un dispositif"""
    document = DocumentDispositif.query.get_or_404(doc_id)
    dispositif = document.dispositif
    
    if not check_client_access(dispositif):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('detail_dispositif', dispositif_id=dispositif.id))
    
