@app.route('/dispositif/<int:dispositif_id>/changer-statut', methods=['POST'])
@login_required
def changer_statut_dispositif(dispositif_id):
    """Changer le statut d'un dispositif (actif/inactif)"""
    dispositif = DispositifMaitrise.query.get_or_404(dispositif_id)
    
    if not check_client_access(dispositif):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('detail_dispositif', dispositif_id=dispositif_id))
    
    # Vérifier les permissions
    if (current_user.id != dispositif.created_by and 
        not current_user.has_permission('can_manage_controls')):
        flash('Vous n\'êtes pas autorisé à modifier ce dispositif', 'error')
        return redirect(url_for('detail_dispositif', dispositif_id=dispositif_id))
    
    nouveau_statut = request.form.get('statut')
    justification = request.form.get('justification', '')
    
    if nouveau_statut in ['actif', 'inactif', 'en_cours', 'obsolete']:
        ancien_statut = dispositif.statut
        dispositif.statut = nouveau_statut
        dispositif.justification_statut = justification
        dispositif.updated_at = datetime.utcnow()
        
        db.session.commit()
        
        flash(f'Statut du dispositif changé de "{ancien_statut}" à "{nouveau_statut}"', 'success')
    else:
        flash('Statut invalide', 'error')
    
    return redirect(url_for('detail_dispositif', dispositif_id=dispositif_id))

    
@app.route('/risque/<int:risque_id>/plans-action/liste')
@login_required
def voir_plans_action_risque(risque_id):
    """Voir tous les plans d'action d'un risque - VERSION CORRIGÉE"""
    risque = Risque.query.get_or_404(risque_id)
    
    if not check_client_access(risque):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('detail_risque', id=risque_id))
    
    # Vérifier si on veut voir les archives ou non
    voir_archives = request.args.get('archives', 'non') == 'oui'
    
    # Construire la requête
    query = get_client_filter(PlanAction)\
        .filter_by(risque_id=risque_id)
    
    # Filtrer selon statut_archive
    if voir_archives:
        plans_action = query.filter(PlanAction.statut_archive == 'archive')\
                           .order_by(PlanAction.updated_at.desc())\
                           .all()
    else:
        plans_action = query.filter(PlanAction.statut_archive == 'actif')\
                           .order_by(PlanAction.created_at.desc())\
                           .all()
    
    # Préparer les données pour le template
    plans_with_attrs = []
    for plan in plans_action:
        # Assurez-vous que statut_archive existe
        statut_archive_value = getattr(plan, 'statut_archive', 'actif')
        plans_with_attrs.append({
            'plan': plan,
            'statut_archive': statut_archive_value,
            'has_statut_archive': hasattr(plan, 'statut_archive')
        })
    
    # Récupérer TOUS les plans pour calculer les statistiques
    tous_plans = get_client_filter(PlanAction)\
        .filter_by(risque_id=risque_id)\
        .all()
    
    # Calcul des statistiques
    plans_actifs = [p for p in tous_plans if getattr(p, 'statut_archive', 'actif') == 'actif']
    plans_archives = [p for p in tous_plans if getattr(p, 'statut_archive', 'actif') == 'archive']
    
    stats = {
        'total': len(plans_actifs),
        'en_cours': len([p for p in plans_actifs if p.statut == 'en_cours']),
        'termines': len([p for p in plans_actifs if p.statut == 'termine']),
        'en_retard': len([p for p in plans_actifs if getattr(p, 'est_en_retard', False)]),
        'archives': len(plans_archives)
    }
    
    # Récupérer les responsables uniques
    responsables_uniques = []
    for plan in plans_action:
        if plan.responsable and plan.responsable not in responsables_uniques:
            responsables_uniques.append(plan.responsable)
    
    # Convertir en JSON pour les graphiques
    plans_action_json = [plan.to_dict() for plan in plans_action]
    
    return render_template('plans_action/liste_risque.html',
                         risque=risque,
                         plans_with_attrs=plans_with_attrs,  # Changé ici
                         plans_action=plans_action,  # Garder pour compatibilité
                         plans_action_json=plans_action_json,
                         stats=stats,
                         responsables_uniques=responsables_uniques,
                         voir_archives=voir_archives)

@app.template_filter('average')
def average_filter(values):
    """Calculate average of a list, ignoring None values"""
    if not values:
        return 0
    valid_values = [v for v in values if v is not None]
    if not valid_values:
        return 0
    return sum(valid_values) / len(valid_values)

@app.template_filter('default_if_none')
def default_if_none(value, default=0):
    """Return default value if value is None"""
    return value if value is not None else default

@app.route('/dispositif/<int:dispositif_id>/evaluer', methods=['GET', 'POST'])
@login_required
def evaluer_dispositif(dispositif_id):
    """Évaluer l'efficacité d'un dispositif de maîtrise"""
    dispositif = DispositifMaitrise.query.get_or_404(dispositif_id)
    
    if not check_client_access(dispositif):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('liste_dispositifs_risque', risque_id=dispositif.risque_id))
    
    form = EvaluationDispositifForm()
    
    if form.validate_on_submit():
        # Sauvegarder l'ancienne efficacité pour comparer
        ancienne_efficacite = dispositif.efficacite_reelle
        
        # Mettre à jour les valeurs d'évaluation
        dispositif.efficacite_reelle = form.efficacite_reelle.data
        dispositif.couverture = form.couverture.data
        dispositif.date_derniere_verification = datetime.utcnow().date()
        dispositif.prochaine_verification = form.prochaine_verification.data
        dispositif.commentaire_evaluation = form.commentaire.data
        dispositif.updated_at = datetime.utcnow()
        
        # CORRECTION : Gérer les valeurs None
        efficacite_reelle = dispositif.efficacite_reelle or 0
        efficacite_attendue = dispositif.efficacite_attendue or 0
        
        # Déterminer le résultat de la vérification
        if efficacite_attendue == 0:
            resultat = 'Non évalué'
        elif efficacite_reelle < efficacite_attendue:
            resultat = 'À améliorer'
        elif efficacite_reelle > efficacite_attendue:
            resultat = 'Supérieur aux attentes'
        else:
            resultat = 'Conforme'
        
        # 1. Créer une vérification d'évaluation
        verification = VerificationDispositif(
            dispositif_id=dispositif.id,
            date_verification=datetime.utcnow().date(),
            type_verification='Évaluation périodique',
            resultat=resultat,
            commentaire=form.commentaire.data or f"Évaluation: {efficacite_reelle}/5 (attendu: {efficacite_attendue}/5)",
            verificateur_id=current_user.id,
            client_id=current_user.client_id
        )
        db.session.add(verification)
        
        # 2. CALCULER LA RÉDUCTION THÉORIQUE DU RISQUE (méthode conforme ISO 31000)
        if dispositif.efficacite_reelle and dispositif.couverture:
            # Utiliser la méthode de la classe pour un calcul standardisé
            dispositif.reduction_risque_pourcentage = dispositif.get_reduction_risque_conforme()
            
            # Optionnel : Mettre à jour le risque parent avec la réduction cumulée
            if dispositif.risque:
                # Calculer la réduction totale de tous les dispositifs du risque
                dispositifs_actifs = DispositifMaitrise.query.filter_by(
                    risque_id=dispositif.risque_id,
                    is_archived=False
                ).all()
                
                # La réduction totale n'est pas cumulative simple (loi de probabilité)
                # Formule: 1 - (1-r1)*(1-r2)*...
                reduction_totale = 0
                reduction_combinée = 1.0
                
                for d in dispositifs_actifs:
                    if d.reduction_risque_pourcentage:
                        # Convertir le pourcentage en facteur (ex: 30% -> 0.3)
                        facteur = d.reduction_risque_pourcentage / 100
                        reduction_combinée *= (1 - facteur)
                
                reduction_totale = (1 - reduction_combinée) * 100
                
                # Stocker dans le risque (si vous avez un champ pour ça)
                # dispositif.risque.reduction_totale = round(reduction_totale, 1)
        
        # 3. GÉRER LE CHANGEMENT DE STATUT AUTOMATIQUE
        if dispositif.statut != 'actif' and efficacite_reelle > 0:
            # Si le dispositif est évalué, le passer en actif automatiquement
            dispositif.statut = 'actif'
            dispositif.justification_statut = "Activé automatiquement suite à l'évaluation"
        
        # 4. CRÉER UN PLAN D'ACTION SI NÉCESSAIRE (version compatible)
        creer_plan = request.form.get('creer_plan_action') == 'on'
        
        # Vérifier si un plan d'action existe déjà (compatible local/production)
        a_deja_plan = False
        
        # Méthode 1: Vérifier via plan_action_id (si la colonne existe)
        if hasattr(dispositif, 'plan_action_id') and dispositif.plan_action_id:
            a_deja_plan = True
        # Méthode 2: Vérifier via la relation plans_action
        elif hasattr(dispositif, 'plans_action'):
            try:
                if hasattr(dispositif.plans_action, 'count'):
                    a_deja_plan = dispositif.plans_action.count() > 0
                elif isinstance(dispositif.plans_action, list):
                    a_deja_plan = len(dispositif.plans_action) > 0
            except:
                a_deja_plan = False
        
        if (creer_plan or (efficacite_attendue > 0 and efficacite_reelle < efficacite_attendue)) and not a_deja_plan:
            try:
                from datetime import timedelta
                
                # Calculer l'écart
                ecart = efficacite_attendue - efficacite_reelle
                
                # Définir la priorité en fonction de l'écart
                if ecart >= 2:
                    priorite = 'haute'
                    echeance_jours = 15
                elif ecart == 1:
                    priorite = 'moyenne'
                    echeance_jours = 30
                else:
                    priorite = 'basse'
                    echeance_jours = 45
                
                # Créer un plan d'action
                plan = PlanAction(
                    reference=f"PA-{dispositif.reference}-{datetime.utcnow().strftime('%Y%m%d')}",
                    nom=f"Amélioration du dispositif {dispositif.reference}",
                    description=f"Plan d'action suite à l'évaluation du {datetime.utcnow().strftime('%d/%m/%Y')}\n\n"
                               f"Efficacité actuelle: {efficacite_reelle}/5\n"
                               f"Efficacité attendue: {efficacite_attendue}/5\n"
                               f"Écart: {ecart} point(s)\n\n"
                               f"Commentaire de l'évaluation: {form.commentaire.data or 'Non spécifié'}",
                    risque_id=dispositif.risque_id,
                    dispositif_id=dispositif.id,
                    responsable_id=dispositif.responsable_id or current_user.id,
                    date_debut=datetime.utcnow().date(),
                    date_fin_prevue=datetime.utcnow().date() + timedelta(days=echeance_jours),
                    statut='en_cours',
                    priorite=priorite,
                    client_id=current_user.client_id,
                    created_by=current_user.id
                )
                db.session.add(plan)
                db.session.flush()  # Pour obtenir l'ID du plan
                
                # Lier le plan au dispositif (de manière compatible)
                if hasattr(dispositif, 'plan_action_id'):
                    # Si la colonne existe, l'utiliser
                    dispositif.plan_action_id = plan.id
                elif hasattr(dispositif, 'plans_action'):
                    # Sinon, utiliser la relation
                    if hasattr(dispositif.plans_action, 'append'):
                        dispositif.plans_action.append(plan)
                
                flash(f'Plan d\'action créé automatiquement (priorité {priorite})', 'warning')
                
            except Exception as e:
                print(f"⚠️ Erreur création plan d'action: {e}")
                flash('Impossible de créer le plan d\'action automatique', 'error')
        
        # 5. AJOUTER UNE NOTIFICATION
        try:
            from models import Notification
            
            # Créer une notification pour le responsable
            if dispositif.responsable_id and dispositif.responsable_id != current_user.id:
                notif = Notification(
                    titre=f"Nouvelle évaluation: {dispositif.reference}",
                    message=f"Le dispositif {dispositif.reference} a été évalué: {efficacite_reelle}/5",
                    type_notification='info',
                    destinataire_id=dispositif.responsable_id,
                    entite_type='dispositif',
                    entite_id=dispositif.id,
                    client_id=current_user.client_id
                )
                db.session.add(notif)
        except Exception as e:
            print(f"⚠️ Erreur notification: {e}")
        
        # Tout valider
        db.session.commit()
        
        # 6. MESSAGE DE SUCCÈS AVEC RÉSUMÉ
        reduction_msg = ""
        if dispositif.reduction_risque_pourcentage:
            reduction_msg = f" Réduction théorique du risque: {dispositif.reduction_risque_pourcentage:.1f}%"
        
        evolution_msg = ""
        if ancienne_efficacite and ancienne_efficacite != efficacite_reelle:
            if efficacite_reelle > ancienne_efficacite:
                evolution_msg = f" (+{efficacite_reelle - ancienne_efficacite} point)"
            else:
                evolution_msg = f" ({efficacite_reelle - ancienne_efficacite} point)"
        
        flash(f'✅ Évaluation enregistrée: {efficacite_reelle}/5{evolution_msg}.{reduction_msg}', 'success')
        return redirect(url_for('detail_dispositif', dispositif_id=dispositif_id))
    
    # PRÉ-REMPLIR LE FORMULAIRE (GET request)
    if request.method == 'GET':
        form.efficacite_reelle.data = dispositif.efficacite_reelle
        form.couverture.data = dispositif.couverture
        form.commentaire.data = dispositif.commentaire_evaluation
        
        # Suggérer une prochaine vérification si non définie
        if dispositif.prochaine_verification:
            form.prochaine_verification.data = dispositif.prochaine_verification
        else:
            # Par défaut, proposer dans 1 an
            from datetime import timedelta
            form.prochaine_verification.data = datetime.utcnow().date() + timedelta(days=365)
    
    # Statistiques pour le template
    stats = {
        'efficacite_moyenne': dispositif.efficacite_reelle,
        'couverture_moyenne': dispositif.couverture,
        'ecart': (dispositif.efficacite_attendue or 0) - (dispositif.efficacite_reelle or 0)
    }
    
    return render_template('dispositifs/evaluation.html',
                         form=form,
                         dispositif=dispositif,
                         stats=stats,
                         now=datetime.utcnow())

def get_reduction_risque_conforme(self):
    """
    Calcule la réduction théorique du risque selon ISO 31000
    """
    if not self.efficacite_reelle or not self.couverture:
        return 0.0
    
    # Coefficients selon le type de dispositif
    coeff_type = {
        'Préventif': 0.35,  # 35% max de réduction
        'Détectif': 0.25,   # 25% max
        'Correctif': 0.20,  # 20% max
        'Dirigeant': 0.15,  # 15% max
    }
    
    type_dispo = self.type_dispositif or 'Correctif'
    coeff = coeff_type.get(type_dispo, 0.20)
    
    # Pondération efficacité (60%) / couverture (40%)
    efficacite_norm = self.efficacite_reelle / 5.0
    couverture_norm = self.couverture / 5.0
    
    score_pondere = (efficacite_norm * 0.6) + (couverture_norm * 0.4)
    
    # Facteur de fréquence
    facteur_frequence = {
        'Permanente': 1.0,
        'Continue': 0.95,
        'Quotidienne': 0.9,
        'Hebdomadaire': 0.8,
        'Mensuelle': 0.7,
        'Trimestrielle': 0.6,
        'Annuelle': 0.5,
        None: 0.7
    }.get(self.frequence, 0.7)
    
    # Calcul final
    reduction = score_pondere * coeff * 100 * facteur_frequence
    
    return round(min(reduction, coeff * 100), 1)

@app.route('/dispositifs/benchmark')
@login_required
def benchmark_dispositifs():
    """Tableau de bord stratégique des dispositifs"""
    stats = DispositifMaitrise.get_benchmark_dispositifs(client_id=current_user.client_id)
    
    # Enrichir les stats avec plus de détails pour l'affichage
    dispositifs = DispositifMaitrise.query.filter_by(
        client_id=current_user.client_id,
        is_archived=False
    ).all()
    
    # Enrichir top_performers
    stats['top_performers'] = []
    stats['a_ameliorer'] = []
    stats['sans_evaluation'] = []
    
    for d in dispositifs:
        item = {
            'id': d.id,
            'reference': d.reference,
            'nom': d.nom,
            'type': d.type_dispositif,
            'statut': d.statut,
            'responsable': d.responsable.username if d.responsable else None,
            'derniere_verif': d.date_derniere_verification.strftime('%d/%m/%Y') if d.date_derniere_verification else None
        }
        
        if d.efficacite_reelle:
            item['efficacite'] = d.efficacite_reelle
            item['attendu'] = d.efficacite_attendue or 3
            item['ecart'] = max(0, (d.efficacite_attendue or 3) - d.efficacite_reelle)
            item['reduction'] = d.get_reduction_risque_detaille()['reduction_finale']
            
            if d.efficacite_reelle >= 4:
                stats['top_performers'].append(item)
            elif d.efficacite_reelle < 3:
                stats['a_ameliorer'].append(item)
        else:
            stats['sans_evaluation'].append(item)
    
    return render_template('benchmark_dispositifs.html', 
                         stats=stats, 
                         dispositifs=dispositifs,
                         datetime=datetime)

@app.route('/dispositif/<int:dispositif_id>/stress-test', methods=['GET', 'POST'])
@login_required
def stress_test_dispositif(dispositif_id):
    """Page de stress test pour un dispositif"""
    from models import DispositifMaitrise
    
    dispositif = DispositifMaitrise.query.get_or_404(dispositif_id)
    
    if not check_client_access(dispositif):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('detail_dispositif', dispositif_id=dispositif_id))
    
    resultats = None
    scenario = 'cyber_ransomware'  # Valeur par défaut
    
    if request.method == 'POST':
        scenario = request.form.get('scenario', 'cyber_ransomware')
        
        # Récupérer les stress tests
        stress_tests = dispositif.stress_test_avance()
        
        if scenario in stress_tests:
            test = stress_tests[scenario]
            
            # Calculer des métriques supplémentaires
            efficacite_normale = dispositif.efficacite_reelle or 0
            perte = ((efficacite_normale - test['efficacite']) / efficacite_normale * 100) if efficacite_normale > 0 else 0
            
            # Déterminer la couleur et la résilience
            if test['efficacite'] >= 4:
                couleur = 'success'
                resilience = "🟢 EXCELLENTE"
                conseil = "Le dispositif résiste très bien à ce scénario de stress. Aucune action immédiate requise."
            elif test['efficacite'] >= 3:
                couleur = 'warning'
                resilience = "🟡 BONNE"
                conseil = "Le dispositif résiste bien, mais des améliorations mineures sont possibles."
            elif test['efficacite'] >= 2:
                couleur = 'danger'
                resilience = "🟠 MODÉRÉE"
                conseil = "Le dispositif montre des faiblesses dans ce scénario. Des actions correctives sont recommandées."
            else:
                couleur = 'dark'
                resilience = "🔴 FAIBLE"
                conseil = "Le dispositif est vulnérable dans ce scénario. Un plan d'action prioritaire est nécessaire."
            
            # Calcul du risque résiduel (estimation)
            risque_residuel = max(1, min(5, round(5 - (test['efficacite'] * 0.8))))
            
            resultats = {
                'scenario': test['scenario'],
                'description_scenario': test.get('description', 'Scénario de stress test'),
                'duree': test['duree'],
                'efficacite_normale': efficacite_normale,
                'efficacite_stress': test['efficacite'],
                'facteur_global': test['facteur'],
                'perte': round(perte, 1),
                'reduction_stress': round((test['efficacite'] / 5) * 75, 1),
                'resilience': resilience,
                'conseil': conseil,
                'couleur': couleur,
                'risque_residuel': risque_residuel  # <-- AJOUT ICI
            }
    
    return render_template('dispositifs/stress_test.html',
                         dispositif=dispositif,
                         resultats=resultats,
                         scenario=scenario)



