@app.route('/plan-action/<int:plan_id>/espace-travail')
@login_required
def espace_travail_plan_action(plan_id):
    """Espace de travail pour un plan d'action (risque)"""
    plan_action = PlanAction.query.get_or_404(plan_id)
    
    if not check_client_access(plan_action):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupérer les sous-actions du plan - CORRIGÉ (sans .ordre)
    sous_actions = SousAction.query.filter_by(
        plan_action_id=plan_id,
        client_id=current_user.client_id
    ).order_by(SousAction.created_at.asc()).all()  # Tri par date de création
    
    # Récupérer les commentaires globaux du plan
    commentaires = CommentairePlanAction.query\
        .filter_by(plan_action_id=plan_id, sous_action_id=None)\
        .order_by(CommentairePlanAction.created_at.desc())\
        .all()
    
    # Récupérer les fichiers du plan
    fichiers = FichierPlanAction.query\
        .filter_by(plan_action_id=plan_id)\
        .order_by(FichierPlanAction.created_at.desc())\
        .all()
    
    # Statistiques d'avancement
    total_sous_actions = len(sous_actions)
    sous_actions_terminees = sum(1 for sa in sous_actions if sa.statut == 'termine')
    progression = (sous_actions_terminees / total_sous_actions * 100) if total_sous_actions > 0 else plan_action.pourcentage_realisation or 0
    
    return render_template('plans_action/espace_travail_plan.html',
                         plan=plan_action,
                         sous_actions=sous_actions,
                         commentaires=commentaires,
                         fichiers=fichiers,
                         progression=progression,
                         total_sous_actions=total_sous_actions,
                         sous_actions_terminees=sous_actions_terminees,
                         current_user=current_user)

