@app.route('/plan-action-independant/<int:plan_id>/terminer', methods=['POST'])
@login_required
def terminer_plan_action_independant(plan_id):
    """Terminer un plan indépendant et toutes ses sous-actions"""
    try:
        plan = PlanAction.query.get_or_404(plan_id)
        
        if not check_client_access(plan):
            return jsonify({'error': 'Accès non autorisé'}), 403
        
        # Vérifier que c'est un plan indépendant
        if plan.risque_id or plan.audit_id:
            return jsonify({'error': 'Ce plan n\'est pas un plan indépendant'}), 400
        
        # Terminer toutes les sous-actions
        for sous_action in plan.sous_actions:
            sous_action.statut = 'termine'
            sous_action.pourcentage_realisation = 100
            sous_action.date_fin_reelle = datetime.utcnow().date()
            sous_action.updated_at = datetime.utcnow()
        
        # Terminer le plan
        plan.statut = 'termine'
        plan.pourcentage_realisation = 100
        plan.date_fin_reelle = datetime.utcnow().date()
        plan.updated_at = datetime.utcnow()
        
        db.session.commit()
        
        return jsonify({'success': True, 'message': 'Plan terminé avec succès'})
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

