@app.route('/sous-action-independant/<int:sous_action_id>/changer-progression', methods=['POST'])
@login_required
def changer_progression_sous_action_independant(sous_action_id):
    """Changer la progression d'une sous-action"""
    try:
        sous_action = SousAction.query.get_or_404(sous_action_id)
        plan = sous_action.plan_action
        
        if not check_client_access(plan):
            return jsonify({'error': 'Accès non autorisé'}), 403
        
        # Vérifier que c'est un plan indépendant
        if plan.risque_id or plan.audit_id:
            return jsonify({'error': 'Le plan parent n\'est pas un plan indépendant'}), 400
        
        data = request.get_json()
        nouvelle_progression = data.get('progression', 0)
        
        if not isinstance(nouvelle_progression, (int, float)) or nouvelle_progression < 0 or nouvelle_progression > 100:
            return jsonify({'error': 'Progression invalide (0-100)'}), 400
        
        sous_action.pourcentage_realisation = nouvelle_progression
        
        # Ajuster le statut en fonction de la progression
        if nouvelle_progression >= 100:
            sous_action.statut = 'termine'
            sous_action.date_fin_reelle = datetime.utcnow().date()
        elif nouvelle_progression >= 50:
            sous_action.statut = 'en_cours'
        else:
            sous_action.statut = 'a_faire'
        
        sous_action.updated_at = datetime.utcnow()
        db.session.commit()
        
        return jsonify({'success': True, 'statut': sous_action.statut})
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500



