@app.route('/plan-action-independant/<int:plan_id>/set-progression-fixe', methods=['POST'])
@login_required
def set_progression_fixe_plan_independant(plan_id):
    """Définir une progression fixe pour tout le plan"""
    try:
        plan = PlanAction.query.get_or_404(plan_id)
        
        if not check_client_access(plan):
            return jsonify({'error': 'Accès non autorisé'}), 403
        
        # Vérifier que c'est un plan indépendant
        if plan.risque_id or plan.audit_id:
            return jsonify({'error': 'Ce plan n\'est pas un plan indépendant'}), 400
        
        data = request.get_json()
        progression = data.get('progression', 0)
        
        if not isinstance(progression, (int, float)) or progression < 0 or progression > 100:
            return jsonify({'error': 'Progression invalide (0-100)'}), 400
        
        # Ajuster les sous-actions proportionnellement
        if plan.sous_actions:
            for sous_action in plan.sous_actions:
                # Logique simple : si progression globale est X%, chaque sous-action tend vers X%
                # mais sans dépasser 100%
                nouvelle_progression = min(progression, 100)
                sous_action.pourcentage_realisation = nouvelle_progression
                
                # Ajuster le statut en fonction de la progression
                if nouvelle_progression >= 100:
                    sous_action.statut = 'termine'
                elif nouvelle_progression >= 50:
                    sous_action.statut = 'en_cours'
                else:
                    sous_action.statut = 'a_faire'
                
                sous_action.updated_at = datetime.utcnow()
        
        # Mettre à jour le plan
        plan.pourcentage_realisation = progression
        
        # Déterminer le statut en fonction de la progression
        if progression >= 100:
            plan.statut = 'termine'
            plan.date_fin_reelle = datetime.utcnow().date()
        elif progression >= 50:
            plan.statut = 'en_cours'
        elif progression == 0:
            plan.statut = 'en_attente'
        
        plan.updated_at = datetime.utcnow()
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Progression définie à {progression}%',
            'statut': plan.statut
        })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'error': str(e)}), 500

