def calculer_niveau_risque(impact, probabilite):
    """Calculer le niveau de risque basé sur l'impact et la probabilité"""
    score = impact * probabilite
    
    if score <= 4:
        return 'Faible', 'success'
    elif score <= 9:
        return 'Moyen', 'warning'
    elif score <= 16:
        return 'Élevé', 'danger'
    else:
        return 'Critique', 'dark'


