                destinataire_id=current_user.id,
                type_notification=Notification.TYPE_RISQUE_EVALUE,
                titre=f"Nouvelle évaluation démarrée pour {risque.reference}",
                message=f"Une nouvelle évaluation vierge a été créée pour le risque '{risque.intitule}'.",
                urgence=Notification.URGENCE_NORMAL,
                entite_type='risque',
