# Dans app.py, après la création de l'app
@app.template_filter('add_days')
def add_days_filter(date, days):
    """Ajouter des jours à une date dans les templates"""
    if not date:
        return None
    return date + timedelta(days=days)

@app.template_filter('days_until')
def days_until_filter(date):
    """Nombre de jours jusqu'à une date"""
    if not date:
        return None
    return (date - datetime.now().date()).days

@app.route('/veille/supprimer/<int:id>')
@login_required
def supprimer_veille(id):
    """Supprimer définitivement une veille avec isolation"""
    veille = VeilleReglementaire.query.get_or_404(id)
    
    # CORRECTION : Vérifier l'accès
    if not check_client_access(veille):
        flash('Accès non autorisé à cette veille', 'error')
        return redirect(url_for('veille_archives'))
    
    # Vérifier qu'elle est bien archivée
    if not veille.is_archived:
        flash('Impossible de supprimer une veille non archivée', 'error')
        return redirect(url_for('veille_reglementaire'))
    
    # Supprimer d'abord les documents associés
    for doc in veille.documents:
        # Supprimer le fichier physique
        file_path = os.path.join(app.config['UPLOAD_FOLDER_VEILLE'], doc.nom_fichier)
        if os.path.exists(file_path):
            try:
                os.remove(file_path)
            except OSError:
                pass
        
        # Supprimer l'entrée en base
        db.session.delete(doc)
    
    # Supprimer les actions
    for action in veille.actions:
        db.session.delete(action)
    
    # Supprimer la veille
    db.session.delete(veille)
    db.session.commit()
    
    flash('Veille supprimée définitivement', 'success')
    return redirect(url_for('veille_archives'))

