@app.route('/admin/directions')
@login_required
def admin_directions():
    """Gestion des directions avec filtres multi-tenant"""
    
    # Vérifier la permission
    if not current_user.has_permission('can_view_departments'):
        flash('Accès refusé : permission de voir les directions/services requise', 'error')
        return redirect(url_for('dashboard'))
    
    # ===== RÉCUPÉRER LES PARAMÈTRES DE FILTRE =====
    pole_filter = request.args.get('pole', 'tous')
    sort_by = request.args.get('sort', 'nom_asc')
    search_query = request.args.get('search', '')
    
    # ===== CONSTRUIRE LA REQUÊTE DE BASE =====
    query = get_client_filter(Direction).filter_by(
        is_archived=False, 
        is_active=True
    )
    
    # ===== APPLIQUER LE FILTRE PAR PÔLE =====
    if pole_filter != 'tous' and pole_filter.isdigit():
        query = query.filter(Direction.pole_id == int(pole_filter))
    
    # ===== APPLIQUER LA RECHERCHE =====
    if search_query:
        query = query.filter(
            db.or_(
                Direction.nom.ilike(f'%{search_query}%'),
                Direction.description.ilike(f'%{search_query}%')
            )
        )
    
    # ===== RÉCUPÉRER LES DIRECTIONS =====
    directions = query.all()
    
    # ===== APPLIQUER LE TRI (en Python pour plus de flexibilité) =====
    if sort_by == 'nom_asc':
        directions = sorted(directions, key=lambda x: x.nom.lower())
    elif sort_by == 'nom_desc':
        directions = sorted(directions, key=lambda x: x.nom.lower(), reverse=True)
    elif sort_by == 'services_asc':
        directions = sorted(directions, key=lambda x: len([s for s in x.services if s.is_active]))
    elif sort_by == 'services_desc':
        directions = sorted(directions, key=lambda x: len([s for s in x.services if s.is_active]), reverse=True)
    elif sort_by == 'pole_asc':
        directions = sorted(directions, key=lambda x: x.pole.nom.lower() if x.pole else 'zzz')
    elif sort_by == 'pole_desc':
        directions = sorted(directions, key=lambda x: x.pole.nom.lower() if x.pole else 'aaa', reverse=True)
    elif sort_by == 'responsable':
        # Les directions avec responsable en premier
        directions = sorted(directions, key=lambda x: (0 if x.a_responsable else 1, x.nom.lower()))
    
    # ===== RÉCUPÉRER LES PÔLES POUR LES FILTRES =====
    if current_user.role == 'super_admin':
        poles = Pole.query.filter_by(is_archived=False).order_by(Pole.ordre).all()
    else:
        poles = get_client_filter(Pole).filter_by(is_archived=False).order_by(Pole.ordre).all()
    
    # ===== STATISTIQUES PAR PÔLE =====
    stats_poles = {}
    for pole in poles:
        nb_directions = len([d for d in pole.directions if not d.is_archived and d.is_active])
        stats_poles[pole.id] = {
            'directions': nb_directions
        }
    
    # ===== STATISTIQUES GLOBALES =====
    total_services = 0
    total_responsables = 0
    directions_avec_resp = 0
    responsables_utilisateurs = 0
    responsables_manuels = 0
    
    for direction in directions:
        # Compter les directions avec responsable
        if direction.a_responsable:
            directions_avec_resp += 1
            if direction.responsable_id:
                responsables_utilisateurs += 1
            elif direction.responsable_nom_manuel:
                responsables_manuels += 1
        
        # Compter les services
        services_actifs = [s for s in direction.services if s.is_active]
        total_services += len(services_actifs)
        
        for service in services_actifs:
            if service.a_responsable:
                total_responsables += 1
    
    # Taux d'encadrement
    taux_encadrement = round((total_responsables / total_services * 100) if total_services > 0 else 0)
    
    # Récupérer les utilisateurs pour les modals d'édition
    users = get_client_filter(User).filter_by(is_active=True).all()
    
    # Directions archivées (pour le badge)
    directions_archivees = get_client_filter(Direction).filter_by(is_archived=True).count()
    
    return render_template('admin/directions.html',
                         directions=directions,
                         poles=poles,
                         users=users,
                         stats_poles=stats_poles,
                         total_services=total_services,
                         total_responsables=total_responsables,
                         directions_avec_resp=directions_avec_resp,
                         responsables_utilisateurs=responsables_utilisateurs,
                         responsables_manuels=responsables_manuels,
                         taux_encadrement=taux_encadrement,
                         directions_archivees=directions_archivees)

@app.route('/admin/direction/<int:direction_id>/supprimer', methods=['DELETE'])
@login_required
def supprimer_direction(direction_id):
    """Supprimer une direction et ses services (soft delete)"""
    # Vérifier la permission de gérer les départements
    if not current_user.has_permission('can_manage_departments'):
        return jsonify({'success': False, 'error': 'Permission non autorisée'}), 403
    
    direction = Direction.query.get_or_404(direction_id)
    
    # Vérifier l'accès au client
    if not check_client_access(direction):
        return jsonify({'success': False, 'error': 'Accès non autorisé à cette direction'}), 403
    
    try:
        # 🔴 CORRECTION: Utiliser ProcessusActivite au lieu de Processus
        has_cartographies = Cartographie.query.filter_by(direction_id=direction_id, is_archived=False).count() > 0
        has_processus = ProcessusActivite.query.filter_by(direction_id=direction_id, is_archived=False).count() > 0
        
        if has_cartographies or has_processus:
            return jsonify({
                'success': False, 
                'error': f'Cette direction est utilisée dans {has_cartographies} cartographie(s) et {has_processus} processus. Archivez-la au lieu de la supprimer.'
            }), 400
        
        # Soft delete des services associés
        services = Service.query.filter_by(direction_id=direction_id).all()
        for service in services:
            service.is_active = False
            service.is_archived = True
            service.archived_at = datetime.utcnow()
            service.archived_by = current_user.id
        
        # Soft delete de la direction
        direction.is_active = False
        direction.is_archived = True
        direction.archived_at = datetime.utcnow()
        direction.archived_by = current_user.id
        
        # Journaliser l'action
        log_activity(current_user.id, 'suppression_direction',
                    f"Suppression direction {direction.nom}",
                    'direction', direction.id)
        
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Direction "{direction.nom}" supprimée avec succès'
        })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500


