@app.route('/admin/direction/nouvelle', methods=['GET', 'POST'])
@login_required
def nouvelle_direction():
    """Créer une nouvelle direction"""
    
    form = DirectionForm()
    
    # Récupérer les utilisateurs et les pôles du client
    users = get_client_filter(User).filter_by(is_active=True).all()
    poles = get_client_filter(Pole).filter_by(is_archived=False).order_by(Pole.ordre).all()
    
    form.responsable_id.choices = [(0, '--- Aucun responsable ---')] + [(u.id, u.username) for u in users]
    # Les pôles sont gérés dans le template, pas dans les choices du formulaire
    
    if form.validate_on_submit():
        try:
            direction = Direction(
                nom=form.nom.data,
                description=form.description.data,
                pole_id=request.form.get('pole_id') if request.form.get('pole_id') and request.form.get('pole_id') != '0' else None,
                client_id=current_user.client_id
            )
            
            # Gestion du responsable
            if form.type_responsable.data == 'utilisateur' and form.responsable_id.data and form.responsable_id.data != 0:
                direction.responsable_id = form.responsable_id.data
                direction.responsable_nom_manuel = None
                direction.responsable_type = 'utilisateur'
            elif form.type_responsable.data == 'manuel' and form.responsable_nom_manuel.data:
                direction.responsable_id = None
                direction.responsable_nom_manuel = form.responsable_nom_manuel.data
                direction.responsable_type = 'manuel'
            else:
                direction.responsable_id = None
                direction.responsable_nom_manuel = None
                direction.responsable_type = 'utilisateur'
            
            db.session.add(direction)
            db.session.commit()
            
            flash(f'✅ Direction "{direction.nom}" créée avec succès', 'success')
            return redirect(url_for('admin_directions'))
            
        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')
    
    return render_template('admin/direction_form.html', form=form, users=users, poles=poles)

