@app.route('/api/rattacher-directions', methods=['POST'])
@login_required
def api_rattacher_directions():
    """Rattache plusieurs directions à un pôle"""
    
    data = request.get_json()
    pole_id = data.get('pole_id')
    direction_ids = data.get('direction_ids', [])
    
    pole = Pole.query.get_or_404(pole_id)
    if not check_client_access(pole):
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403
    
    try:
        for dir_id in direction_ids:
            direction = Direction.query.get(dir_id)
            if direction and check_client_access(direction):
                direction.pole_id = pole_id
                direction.updated_at = datetime.utcnow()
        
        db.session.commit()
        return jsonify({'success': True, 'message': f'{len(direction_ids)} direction(s) rattachée(s)'})
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

