@app.route('/controle/campagne/<int:campagne_id>/fichiers')
@login_required
def liste_fichiers_campagne_controle(campagne_id):
    """Liste des fichiers d'une campagne"""
    
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    fichiers = FichierCampagneControle.query.filter_by(campagne_id=campagne_id).order_by(FichierCampagneControle.uploaded_at.desc()).all()
    
    return jsonify({
        'success': True,
        'fichiers': [{
            'id': f.id,
            'nom_fichier': f.nom_fichier,
            'categorie': f.categorie,
            'type_fichier': f.type_fichier,
            'taille_formatee': f.get_taille_formatee(),
            'uploaded_at': f.uploaded_at.strftime('%d/%m/%Y %H:%M'),
            'uploader': f.uploader.username if f.uploader else 'Inconnu'
        } for f in fichiers]
    })


@app.route('/controle/campagne/<int:campagne_id>/fichier/upload', methods=['POST'])
@login_required
def upload_fichier_campagne_controle(campagne_id):
    """Uploader un fichier pour une campagne"""
    
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    if 'fichier' not in request.files:
        flash('Aucun fichier sélectionné', 'error')
        return redirect(url_for('detail_campagne_controle', campagne_id=campagne_id))
    
    fichier = request.files['fichier']
    if fichier.filename == '':
        flash('Aucun fichier sélectionné', 'error')
        return redirect(url_for('detail_campagne_controle', campagne_id=campagne_id))
    
    # Vérifier l'extension
    allowed = {'pdf', 'doc', 'docx', 'xls', 'xlsx', 'jpg', 'jpeg', 'png', 'txt'}
    ext = fichier.filename.rsplit('.', 1)[1].lower() if '.' in fichier.filename else ''
    
    if ext not in allowed:
        flash(f'Extension .{ext} non autorisée', 'error')
        return redirect(url_for('detail_campagne_controle', campagne_id=campagne_id))
    
    # Vérifier taille (max 10 Mo)
    fichier.seek(0, 2)
    taille = fichier.tell()
    fichier.seek(0)
    
    if taille > 10 * 1024 * 1024:
        flash('Fichier trop volumineux (max 10 Mo)', 'error')
        return redirect(url_for('detail_campagne_controle', campagne_id=campagne_id))
    
    try:
        # Créer dossier
        upload_folder = os.path.join('uploads', 'campagnes_controle', str(campagne_id))
        os.makedirs(upload_folder, exist_ok=True)
        
        # Nom unique
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        nom_unique = f"{timestamp}_{secure_filename(fichier.filename)}"
        chemin = os.path.join(upload_folder, nom_unique)
        
        fichier.save(chemin)
        
        nouveau_fichier = FichierCampagneControle(
            campagne_id=campagne_id,
            nom_fichier=fichier.filename,
            nom_unique=nom_unique,
            chemin_fichier=chemin,
            type_fichier=fichier.content_type or ext,
            taille=taille,
            categorie=request.form.get('categorie', 'document'),
            description=request.form.get('description', ''),
            uploaded_by=current_user.id,
            client_id=current_user.client_id
        )
        
        db.session.add(nouveau_fichier)
        db.session.commit()
        
        flash('✅ Fichier ajouté avec succès', 'success')
        
    except Exception as e:
        db.session.rollback()
        flash(f'Erreur: {str(e)}', 'error')
    
    return redirect(url_for('detail_campagne_controle', campagne_id=campagne_id))


@app.route('/controle/fichier/<int:fichier_id>/telecharger')
@login_required
def telecharger_fichier_campagne_controle(fichier_id):
    """Télécharger un fichier"""
    
    fichier = FichierCampagneControle.query.get_or_404(fichier_id)
    
    if not os.path.exists(fichier.chemin_fichier):
        flash('Fichier introuvable', 'error')
        return redirect(url_for('liste_campagnes_controle'))
    
    return send_file(fichier.chemin_fichier, as_attachment=True, download_name=fichier.nom_fichier)


@app.route('/controle/fichier/<int:fichier_id>/supprimer', methods=['POST'])
@login_required
def supprimer_fichier_campagne_controle(fichier_id):
    """Supprimer un fichier"""
    
    fichier = FichierCampagneControle.query.get_or_404(fichier_id)
    
    if fichier.uploaded_by != current_user.id and not current_user.is_client_admin:
        return jsonify({'success': False, 'error': 'Permission insuffisante'}), 403
    
    try:
        if os.path.exists(fichier.chemin_fichier):
            os.remove(fichier.chemin_fichier)
        
        db.session.delete(fichier)
        db.session.commit()
        
        return jsonify({'success': True})
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/controle/statistiques-globales')
@login_required
def statistiques_globales_controle():
    """Statistiques globales de toutes les campagnes avec multi-tenant"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    # ============================================
    # MULTI-TENANT : Filtrer par client
    # ============================================
    if current_user.role == 'super_admin':
        viewing_client_id = session.get('viewing_client_id')
        if viewing_client_id:
            campagnes = CampagneControle.query.filter_by(client_id=viewing_client_id, is_archived=False).all()
        else:
            campagnes = CampagneControle.query.filter_by(is_archived=False).all()
    else:
        campagnes = CampagneControle.query.filter_by(client_id=current_user.client_id, is_archived=False).all()
    
    # Statistiques globales
    stats = {
        'total': len(campagnes),
        'en_cours': len([c for c in campagnes if c.statut == 'en_cours']),
        'termine': len([c for c in campagnes if c.statut == 'termine']),
        'en_preparation': len([c for c in campagnes if c.statut == 'en_preparation']),
        'suspendu': len([c for c in campagnes if c.statut == 'suspendu']),
        'annule': len([c for c in campagnes if c.statut == 'annule']),
        'total_dossiers_prevus': sum(c.nb_dossiers_prevus for c in campagnes),
        'total_dossiers_controles': sum(c.nb_dossiers_controles for c in campagnes),
        'total_conformes': sum(c.nb_conformes for c in campagnes),
        'total_anomalies': sum(c.nb_anomalies for c in campagnes),
        'taux_global': 0
    }
    
    if stats['total_dossiers_controles'] > 0:
        stats['taux_global'] = round((stats['total_conformes'] / stats['total_dossiers_controles']) * 100, 1)
    
    # Données pour graphique par mois
    par_mois = {}
    for c in campagnes:
        mois = c.created_at.strftime('%Y-%m')
        if mois not in par_mois:
            par_mois[mois] = {'total': 0, 'termine': 0, 'taux': 0}
        par_mois[mois]['total'] += 1
        if c.statut == 'termine':
            par_mois[mois]['termine'] += 1
        par_mois[mois]['taux'] = round((par_mois[mois]['termine'] / par_mois[mois]['total']) * 100, 1)
    
    # Trier par mois
    par_mois = dict(sorted(par_mois.items()))
    
    return render_template('controle/statistiques_globales.html', stats=stats, par_mois=par_mois, now=datetime.now())

@app.route('/controle/campagne/<int:campagne_id>/exporter')
@login_required
def export_campagne_controle(campagne_id):
    """Exporter une campagne de contrôle en Excel"""
    
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    try:
        import openpyxl
        from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
        from io import BytesIO
        
        wb = openpyxl.Workbook()
        
        # ============================================
        # FEUILLE 1 : FICHE DE CONTRÔLE
        # ============================================
        ws = wb.active
        ws.title = "Fiche de contrôle"
        
        # Titre
        ws.merge_cells('A1:F1')
        ws['A1'] = f"CAMPAGNE DE CONTRÔLE - {campagne.reference}"
        ws['A1'].font = Font(size=14, bold=True, color="FFFFFF")
        ws['A1'].fill = PatternFill(start_color="2C3E50", end_color="2C3E50", fill_type="solid")
        ws['A1'].alignment = Alignment(horizontal='center')
        
        # Informations générales
        row = 3
        info = [
            ('Nom', campagne.nom),
            ('Description', campagne.description or ''),
            ('Statut', campagne.get_statut_label()),
            ('Date de début', campagne.date_debut.strftime('%d/%m/%Y') if campagne.date_debut else ''),
            ('Date de fin', campagne.date_fin.strftime('%d/%m/%Y') if campagne.date_fin else ''),
            ('Créé par', campagne.createur.username if campagne.createur else ''),
            ('Créé le', campagne.created_at.strftime('%d/%m/%Y %H:%M') if campagne.created_at else ''),
        ]
        
        for label, value in info:
            ws.cell(row=row, column=1, value=label).font = Font(bold=True)
            ws.cell(row=row, column=2, value=value)
            row += 1
        
        # Organisation
        row += 1
        ws.cell(row=row, column=1, value="Organisation").font = Font(bold=True)
        row += 1
        
        if campagne.pole:
            ws.cell(row=row, column=1, value="Pôle")
            ws.cell(row=row, column=2, value=campagne.pole.nom)
        elif campagne.direction:
            ws.cell(row=row, column=1, value="Direction")
            ws.cell(row=row, column=2, value=campagne.direction.nom)
        elif campagne.service:
            ws.cell(row=row, column=1, value="Service")
            ws.cell(row=row, column=2, value=campagne.service.nom)
        
        # Acteurs
        row += 2
        ws.cell(row=row, column=1, value="Acteurs").font = Font(bold=True)
        row += 1
        
        ws.cell(row=row, column=1, value="Valideur")
        ws.cell(row=row, column=2, value=campagne.valideur.username if campagne.valideur else 'Non assigné')
        row += 1
        ws.cell(row=row, column=1, value="Évaluateur")
        ws.cell(row=row, column=2, value=campagne.evaluateur.username if campagne.evaluateur else 'Non assigné')
        
        # Volumes
        row += 2
        ws.cell(row=row, column=1, value="Volumes").font = Font(bold=True)
        row += 1
        
        volumes = [
            ('Volume prévisionnel total', campagne.volume_previsionnel),
            ('Nombre de dossiers prévus', campagne.nb_dossiers_prevus),
            ('Dossiers règlement à contrôler', campagne.nb_dossiers_reglement),
        ]
        
        for label, value in volumes:
            ws.cell(row=row, column=1, value=label)
            ws.cell(row=row, column=2, value=value)
            row += 1
        
        # Résultats
        row += 2
        ws.cell(row=row, column=1, value="Résultats").font = Font(bold=True)
        row += 1
        
        resultats = [
            ('Dossiers contrôlés', campagne.nb_dossiers_controles),
            ('Dossiers conformes', campagne.nb_conformes),
            ('Dossiers en anomalie', campagne.nb_anomalies),
            ('Taux de conformité', f"{campagne.taux_conformite}%"),
            ('Avancement', f"{campagne.get_avancement()}%"),
        ]
        
        for label, value in resultats:
            ws.cell(row=row, column=1, value=label)
            ws.cell(row=row, column=2, value=value)
            row += 1
        
        # Commentaires
        if campagne.commentaire_general or campagne.conclusion or campagne.actions_correctives:
            row += 2
            ws.cell(row=row, column=1, value="Commentaires").font = Font(bold=True)
            row += 1
            
            if campagne.commentaire_general:
                ws.cell(row=row, column=1, value="Commentaire général")
                ws.cell(row=row, column=2, value=campagne.commentaire_general)
                row += 1
            if campagne.conclusion:
                ws.cell(row=row, column=1, value="Conclusion")
                ws.cell(row=row, column=2, value=campagne.conclusion)
                row += 1
            if campagne.actions_correctives:
                ws.cell(row=row, column=1, value="Actions correctives")
                ws.cell(row=row, column=2, value=campagne.actions_correctives)
        
        # Ajuster les colonnes
        ws.column_dimensions['A'].width = 25
        ws.column_dimensions['B'].width = 50
        
        # ============================================
        # FEUILLE 2 : STATISTIQUES
        # ============================================
        ws2 = wb.create_sheet("Statistiques")
        
        ws2.merge_cells('A1:D1')
        ws2['A1'] = f"STATISTIQUES - {campagne.reference}"
        ws2['A1'].font = Font(size=14, bold=True, color="FFFFFF")
        ws2['A1'].fill = PatternFill(start_color="2C3E50", end_color="2C3E50", fill_type="solid")
        ws2['A1'].alignment = Alignment(horizontal='center')
        
        # Graphique en barres simplifié
        ws2['A3'] = "Indicateur"
        ws2['B3'] = "Valeur"
        ws2['C3'] = "Pourcentage"
        ws2['A3'].font = Font(bold=True)
        ws2['B3'].font = Font(bold=True)
        ws2['C3'].font = Font(bold=True)
        
        stats_data = [
            ("Dossiers prévus", campagne.nb_dossiers_prevus, "100%"),
            ("Dossiers contrôlés", campagne.nb_dossiers_controles, f"{campagne.get_avancement()}%"),
            ("Dossiers conformes", campagne.nb_conformes, f"{campagne.taux_conformite}%"),
            ("Dossiers en anomalie", campagne.nb_anomalies, f"{(campagne.nb_anomalies / campagne.nb_dossiers_controles * 100) if campagne.nb_dossiers_controles > 0 else 0:.1f}%"),
        ]
        
        row = 4
        for label, value, pourcent in stats_data:
            ws2.cell(row=row, column=1, value=label)
            ws2.cell(row=row, column=2, value=value)
            ws2.cell(row=row, column=3, value=pourcent)
            row += 1
        
        ws2.column_dimensions['A'].width = 25
        ws2.column_dimensions['B'].width = 15
        ws2.column_dimensions['C'].width = 15
        
        # Sauvegarde
        buffer = BytesIO()
        wb.save(buffer)
        buffer.seek(0)
        
        return Response(
            buffer.getvalue(),
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            headers={
                "Content-Disposition": f"attachment; filename=campagne_controle_{campagne.reference}_{datetime.now().strftime('%Y%m%d_%H%M')}.xlsx"
            }
        )
        
    except ImportError:
        flash("Bibliothèque openpyxl non disponible", "error")
        return redirect(url_for('statistiques_campagne_controle', campagne_id=campagne.id))
    except Exception as e:
        flash(f"Erreur lors de l'export: {str(e)}", "error")
        return redirect(url_for('statistiques_campagne_controle', campagne_id=campagne.id))



# ============================================
# ROUTES POUR LES CAMPAGNES DE CONTRÔLE
# ============================================
@app.route('/controle/campagnes')
@login_required
def liste_campagnes_controle():
    """Liste des campagnes de contrôle avec multi-tenant"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    # ============================================
    # RÉCUPÉRATION DES FILTRES - CORRIGÉ
    # ============================================
    statut = request.args.get('statut', '')
    pole_id = request.args.get('pole_id', '')
    direction_id = request.args.get('direction_id', '')
    
    # CORRECTION ICI : Accepter 'on' comme valeur vraie
    show_archived_value = request.args.get('show_archived', 'false')
    show_archived = show_archived_value in ['true', 'on', '1', 'True', True]
    
    print(f"🔍 [DEBUG] show_archived_value: {show_archived_value}")
    print(f"🔍 [DEBUG] show_archived: {show_archived}")
    
    # ============================================
    # MULTI-TENANT : Filtrer par client
    # ============================================
    if current_user.role == 'super_admin':
        query = CampagneControle.query
        viewing_client_id = session.get('viewing_client_id')
        if viewing_client_id:
            query = query.filter_by(client_id=viewing_client_id)
    else:
        query = CampagneControle.query.filter_by(client_id=current_user.client_id)
    
    # ============================================
    # FILTRE ARCHIVAGE - CORRIGÉ
    # ============================================
    if show_archived:
        # Mode "Afficher les archivés" : on ne prend QUE les archivés
        query = query.filter(CampagneControle.is_archived == True)
        print(f"   📦 MODE ARCHIVES: is_archived = True")
    else:
        # Mode normal : on exclut les archivés
        query = query.filter(CampagneControle.is_archived == False)
        print(f"   📋 MODE NORMAL: is_archived = False")
        
        # Filtre statut uniquement en mode normal
        if statut:
            query = query.filter_by(statut=statut)
    
    # Filtre pôle
    if pole_id and pole_id.isdigit():
        query = query.filter_by(pole_id=int(pole_id))
    
    # Filtre direction
    if direction_id and direction_id.isdigit():
        query = query.filter_by(direction_id=int(direction_id))
    
    campagnes = query.order_by(CampagneControle.created_at.desc()).all()
    
    print(f"🔍 [DEBUG] {len(campagnes)} campagne(s) trouvée(s)")
    
    # ============================================
    # DONNÉES POUR LES FILTRES
    # ============================================
    if current_user.role == 'super_admin':
        viewing_client_id = session.get('viewing_client_id')
        if viewing_client_id:
            poles = Pole.query.filter_by(client_id=viewing_client_id, is_archived=False).order_by(Pole.nom).all()
            directions = Direction.query.filter_by(client_id=viewing_client_id, is_archived=False, is_active=True).order_by(Direction.nom).all()
        else:
            poles = Pole.query.filter_by(is_archived=False).order_by(Pole.nom).all()
            directions = Direction.query.filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
    else:
        poles = Pole.query.filter_by(client_id=current_user.client_id, is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Direction.nom).all()
    
    # ============================================
    # STATISTIQUES (sur TOUTES les campagnes non archivées)
    # ============================================
    if current_user.role == 'super_admin':
        viewing_client_id = session.get('viewing_client_id')
        if viewing_client_id:
            toutes_campagnes = CampagneControle.query.filter_by(client_id=viewing_client_id, is_archived=False).all()
        else:
            toutes_campagnes = CampagneControle.query.filter_by(is_archived=False).all()
    else:
        toutes_campagnes = CampagneControle.query.filter_by(client_id=current_user.client_id, is_archived=False).all()
    
    stats = {
        'total': len(toutes_campagnes),
        'en_cours': len([c for c in toutes_campagnes if c.statut == 'en_cours']),
        'termine': len([c for c in toutes_campagnes if c.statut == 'termine']),
        'en_preparation': len([c for c in toutes_campagnes if c.statut == 'en_preparation']),
        'archives': CampagneControle.query.filter_by(is_archived=True).count() if current_user.role == 'super_admin' else CampagneControle.query.filter_by(client_id=current_user.client_id, is_archived=True).count(),
        'taux_moyen': 0
    }
    
    if toutes_campagnes:
        stats['taux_moyen'] = round(sum(c.taux_conformite for c in toutes_campagnes) / len(toutes_campagnes), 1)
    
    return render_template('controle/liste_campagnes.html',
                         campagnes=campagnes,
                         stats=stats,
                         poles=poles,
                         directions=directions,
                         show_archived=show_archived,
                         now=datetime.now())

@app.route('/controle/campagne/nouvelle', methods=['GET', 'POST'])
@login_required
def nouvelle_campagne_controle():
    """Créer une nouvelle campagne de contrôle"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    form = CampagneControleForm()
    
    # Remplir les choix
    if current_user.role == 'super_admin':
        poles = Pole.query.filter_by(is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(is_active=True).order_by(User.username).all()
    else:
        poles = Pole.query.filter_by(client_id=current_user.client_id, is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(client_id=current_user.client_id, is_active=True).order_by(User.username).all()
    
    form.pole_id.choices = [(0, '-- Sélectionner --')] + [(p.id, p.nom) for p in poles]
    form.direction_id.choices = [(0, '-- Sélectionner --')] + [(d.id, d.nom) for d in directions]
    form.service_id.choices = [(0, '-- Sélectionner --')] + [(s.id, s.nom) for s in services]
    form.valideur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    form.evaluateur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    
    if form.validate_on_submit():
        try:
            # Générer référence
            annee = datetime.now().year
            dernier = CampagneControle.query.filter(
                CampagneControle.reference.like(f'CC-{annee}-%')
            ).order_by(CampagneControle.reference.desc()).first()
            
            if dernier:
                num = int(dernier.reference.split('-')[-1]) + 1
            else:
                num = 1
            
            reference = f"CC-{annee}-{num:03d}"
            
            campagne = CampagneControle(
                reference=reference,
                nom=form.nom.data,
                description=form.description.data,
                date_debut=form.date_debut.data,
                date_fin=form.date_fin.data,
                statut=form.statut.data,
                volume_previsionnel=form.volume_previsionnel.data or 0,
                nb_dossiers_prevus=form.nb_dossiers_prevus.data or 0,
                nb_dossiers_reglement=form.nb_dossiers_reglement.data or 0,
                nb_dossiers_controles=form.nb_dossiers_controles.data or 0,
                nb_anomalies=form.nb_anomalies.data or 0,
                nb_conformes=form.nb_conformes.data or 0,
                commentaire_general=form.commentaire_general.data,
                conclusion=form.conclusion.data,
                actions_correctives=form.actions_correctives.data,
                createur_id=current_user.id,
                valideur_id=form.valideur_id.data if form.valideur_id.data != 0 else None,
                evaluateur_id=form.evaluateur_id.data if form.evaluateur_id.data != 0 else None,
                client_id=current_user.client_id
            )
            
            # Assigner l'organisation
            if form.type_organisation == 'pole' and form.pole_id.data:
                campagne.pole_id = form.pole_id.data
            elif form.type_organisation == 'direction' and form.direction_id.data:
                campagne.direction_id = form.direction_id.data
            elif form.type_organisation == 'service' and form.service_id.data:
                campagne.service_id = form.service_id.data
            
            campagne.calculer_taux_conformite()
            
            db.session.add(campagne)
            db.session.commit()
            
            flash(f'✅ Campagne "{reference}" créée avec succès.', 'success')
            return redirect(url_for('detail_campagne_controle', campagne_id=campagne.id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('controle/form_campagne.html', form=form, action='Créer')


