def modifier_campagne_controle(campagne_id):
    """Modifier une campagne de contrôle"""
    
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    form = CampagneControleForm(obj=campagne)
    
    # Remplir les choix
    if current_user.role == 'super_admin':
        poles = Pole.query.filter_by(is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(is_active=True).order_by(User.username).all()
    else:
        poles = Pole.query.filter_by(client_id=current_user.client_id, is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(client_id=current_user.client_id, is_active=True).order_by(User.username).all()
    
    form.pole_id.choices = [(0, '-- Sélectionner --')] + [(p.id, p.nom) for p in poles]
    form.direction_id.choices = [(0, '-- Sélectionner --')] + [(d.id, d.nom) for d in directions]
    form.service_id.choices = [(0, '-- Sélectionner --')] + [(s.id, s.nom) for s in services]
    form.valideur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    form.evaluateur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    
    if request.method == 'GET':
        if campagne.pole_id:
            form.type_organisation = 'pole'
            form.pole_id.data = campagne.pole_id
        elif campagne.direction_id:
            form.type_organisation = 'direction'
            form.direction_id.data = campagne.direction_id
        elif campagne.service_id:
            form.type_organisation = 'service'
            form.service_id.data = campagne.service_id
        
        form.valideur_id.data = campagne.valideur_id or 0
        form.evaluateur_id.data = campagne.evaluateur_id or 0
    
    if form.validate_on_submit():
        try:
            campagne.nom = form.nom.data
            campagne.description = form.description.data
            campagne.date_debut = form.date_debut.data
            campagne.date_fin = form.date_fin.data
            campagne.statut = form.statut.data
            campagne.volume_previsionnel = form.volume_previsionnel.data or 0
            campagne.nb_dossiers_prevus = form.nb_dossiers_prevus.data or 0
            campagne.nb_dossiers_reglement = form.nb_dossiers_reglement.data or 0
            campagne.nb_dossiers_controles = form.nb_dossiers_controles.data or 0
            campagne.nb_anomalies = form.nb_anomalies.data or 0
            campagne.nb_conformes = form.nb_conformes.data or 0
            campagne.commentaire_general = form.commentaire_general.data
            campagne.conclusion = form.conclusion.data
            campagne.actions_correctives = form.actions_correctives.data
            campagne.valideur_id = form.valideur_id.data if form.valideur_id.data != 0 else None
            campagne.evaluateur_id = form.evaluateur_id.data if form.evaluateur_id.data != 0 else None
            campagne.updated_at = datetime.utcnow()
            
            # Mettre à jour l'organisation
            campagne.pole_id = None
            campagne.direction_id = None
            campagne.service_id = None
            
            if form.type_organisation == 'pole' and form.pole_id.data:
                campagne.pole_id = form.pole_id.data
            elif form.type_organisation == 'direction' and form.direction_id.data:
                campagne.direction_id = form.direction_id.data
            elif form.type_organisation == 'service' and form.service_id.data:
                campagne.service_id = form.service_id.data
            
            campagne.calculer_taux_conformite()
            
            db.session.commit()
            
            flash(f'✅ Campagne "{campagne.reference}" mise à jour.', 'success')
            return redirect(url_for('detail_campagne_controle', campagne_id=campagne.id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('controle/form_campagne.html', form=form, campagne=campagne, action='Modifier')


