@app.route('/controle/campagne/<int:campagne_id>/statistiques')
@login_required
def statistiques_campagne_controle(campagne_id):
    """Statistiques et graphiques d'une campagne"""
    
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    # Données pour les graphiques
    stats = {
        'conformite': campagne.taux_conformite,
        'non_conforme': 100 - campagne.taux_conformite if campagne.taux_conformite else 0,
        'avancement': campagne.get_avancement(),
        'prevus': campagne.nb_dossiers_prevus,
        'controles': campagne.nb_dossiers_controles,
        'anomalies': campagne.nb_anomalies,
        'conformes': campagne.nb_conformes
    }
    
    return render_template('controle/statistiques.html',
                         campagne=campagne,
                         stats=stats)


