# EXPORT PDF POUR CAMPAGNE DE CONTRÔLE
# ============================================

@app.route('/controle/campagne/<int:campagne_id>/export-pdf')
@login_required
def export_campagne_controle_pdf(campagne_id):
    """Export PDF professionnel d'une campagne de contrôle"""
    
    from weasyprint import HTML
    from weasyprint.text.fonts import FontConfiguration
    from datetime import datetime
    
    # Récupérer la campagne
    if current_user.role == 'super_admin':
        campagne = CampagneControle.query.get_or_404(campagne_id)
    else:
        campagne = CampagneControle.query.filter_by(id=campagne_id, client_id=current_user.client_id).first_or_404()
    
    # Organisation
    organisation = None
    org_type = ''
    if campagne.pole_id:
        organisation = Pole.query.get(campagne.pole_id)
        org_type = 'Pôle'
    elif campagne.direction_id:
        organisation = Direction.query.get(campagne.direction_id)
        org_type = 'Direction'
    elif campagne.service_id:
        organisation = Service.query.get(campagne.service_id)
        org_type = 'Service'
    
    # Calcul des indicateurs
    taux_conformite = float(campagne.taux_conformite)
    avancement = campagne.get_avancement()
    
    # Déterminer la couleur du taux
    taux_couleur = 'success' if taux_conformite >= 80 else 'warning' if taux_conformite >= 60 else 'danger'
    avancement_couleur = 'success' if avancement >= 80 else 'warning' if avancement >= 60 else 'info'
    
    # Construction du HTML
    html_parts = []
    
    html_parts.append('''
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="UTF-8">
        <title>Campagne de contrôle - ''' + campagne.reference + '''</title>
        <style>
            @page {
                size: A4;
                margin: 2cm;
                @top-center {
                    content: "Campagne de contrôle - Document confidentiel";
                    font-size: 9pt;
                    color: #666;
                }
                @bottom-center {
                    content: "Page " counter(page) " / " counter(pages);
                    font-size: 9pt;
                    color: #666;
                }
            }
            body {
                font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
                line-height: 1.5;
                color: #1a2639;
                background: white;
                margin: 0;
                padding: 0;
            }
            .header { text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 3px solid #1a3650; }
            .title { font-size: 28px; font-weight: 700; color: #1a3650; margin: 10px 0 5px; }
            .subtitle { font-size: 14px; color: #4a5568; letter-spacing: 2px; }
            .reference { font-size: 12px; color: #718096; margin-top: 10px; }
            .section { margin-bottom: 30px; page-break-inside: avoid; }
            .section-title { font-size: 18px; font-weight: 600; color: #1a3650; padding-bottom: 8px; border-bottom: 2px solid #cbd5e0; margin-bottom: 20px; display: flex; align-items: center; gap: 10px; }
            .card { background: #f7fafc; border-radius: 12px; padding: 20px; margin-bottom: 20px; border-left: 4px solid #2c5282; }
            .grid-2 { display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; }
            .grid-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
            .info-row { display: flex; padding: 8px 0; border-bottom: 1px solid #e2e8f0; }
            .info-label { width: 180px; font-weight: 600; color: #4a5568; }
            .info-value { flex: 1; color: #2d3748; }
            .badge { display: inline-block; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 600; }
            .badge-success { background: #c6f6d5; color: #22543d; }
            .badge-warning { background: #feebc8; color: #7b341e; }
            .badge-danger { background: #fed7d7; color: #742a2a; }
            .badge-info { background: #bee3f8; color: #2c5282; }
            .badge-primary { background: #dbeafe; color: #1e40af; }
            .progress-container { background: #e2e8f0; border-radius: 10px; height: 12px; overflow: hidden; margin: 10px 0; }
            .progress-bar { height: 100%; border-radius: 10px; transition: width 0.3s ease; }
            .progress-bar.success { background: linear-gradient(90deg, #48bb78, #38a169); }
            .progress-bar.warning { background: linear-gradient(90deg, #ed8936, #dd6b20); }
            .progress-bar.danger { background: linear-gradient(90deg, #f56565, #e53e3e); }
            .progress-bar.info { background: linear-gradient(90deg, #4299e1, #3182ce); }
            .footer { margin-top: 40px; padding-top: 20px; text-align: center; font-size: 10px; color: #a0aec0; border-top: 1px solid #e2e8f0; }
            .stat-circle { width: 80px; height: 80px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 10px; font-size: 28px; font-weight: bold; color: white; }
            @media print { body { print-color-adjust: exact; -webkit-print-color-adjust: exact; } }
        </style>
    </head>
    <body>
    ''')
    
    # Header
    html_parts.append(f'''
    <div class="header">
        <div class="title">CAMPAGNE DE CONTRÔLE</div>
        <div class="subtitle">Fiche de contrôle par campagne</div>
        <div class="reference">Référence: {campagne.reference}</div>
    </div>
    ''')
    
    # Informations générales
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📋 Informations générales</div>
        <div class="card">
            <div class="grid-2">
                <div>
                    <div class="info-row"><div class="info-label">Nom</div><div class="info-value">{campagne.nom}</div></div>
                    <div class="info-row"><div class="info-label">Statut</div><div class="info-value"><span class="badge {'badge-success' if campagne.statut == 'termine' else 'badge-info' if campagne.statut == 'en_cours' else 'badge-warning'}">{campagne.get_statut_label()}</span></div></div>
                    <div class="info-row"><div class="info-label">Période</div><div class="info-value">{campagne.date_debut.strftime('%d/%m/%Y')} - {campagne.date_fin.strftime('%d/%m/%Y')}</div></div>
                </div>
                <div>
                    <div class="info-row"><div class="info-label">Organisation</div><div class="info-value">{org_type}: {organisation.nom if organisation else 'Non spécifié'}</div></div>
                    <div class="info-row"><div class="info-label">Créé par</div><div class="info-value">{campagne.createur.username if campagne.createur else 'Système'}</div></div>
                    <div class="info-row"><div class="info-label">Créé le</div><div class="info-value">{campagne.created_at.strftime('%d/%m/%Y')}</div></div>
                </div>
            </div>
    ''')
    
    if campagne.description:
        html_parts.append(f'<div class="info-row"><div class="info-label">Description</div><div class="info-value">{campagne.description}</div></div>')
    
    html_parts.append('</div></div>')
    
    # Acteurs
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">👥 Acteurs</div>
        <div class="card">
            <div class="grid-2">
                <div class="info-row"><div class="info-label">Valideur</div><div class="info-value">{campagne.valideur.username if campagne.valideur else 'Non assigné'}</div></div>
                <div class="info-row"><div class="info-label">Évaluateur</div><div class="info-value">{campagne.evaluateur.username if campagne.evaluateur else 'Non assigné'}</div></div>
            </div>
        </div>
    </div>
    ''')
    
    # Indicateurs de performance
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📊 Indicateurs de performance</div>
        <div class="grid-3">
            <div class="card" style="text-align: center;">
                <div class="stat-circle" style="background: linear-gradient(135deg, #4299e1, #3182ce);">{avancement}%</div>
                <div style="font-weight: 600;">Taux d'avancement</div>
                <div class="progress-container" style="margin-top: 10px;"><div class="progress-bar {avancement_couleur}" style="width: {avancement}%"></div></div>
                <div style="font-size: 12px; margin-top: 5px;">{campagne.nb_dossiers_controles} / {campagne.nb_dossiers_prevus} dossiers contrôlés</div>
            </div>
            <div class="card" style="text-align: center;">
                <div class="stat-circle" style="background: linear-gradient(135deg, #48bb78, #38a169);">{taux_conformite}%</div>
                <div style="font-weight: 600;">Taux de conformité</div>
                <div class="progress-container" style="margin-top: 10px;"><div class="progress-bar {taux_couleur}" style="width: {taux_conformite}%"></div></div>
                <div style="font-size: 12px; margin-top: 5px;">{campagne.nb_conformes} conformes / {campagne.nb_anomalies} anomalies</div>
            </div>
            <div class="card" style="text-align: center;">
                <div class="stat-circle" style="background: linear-gradient(135deg, #ed8936, #dd6b20);">{campagne.volume_previsionnel}</div>
                <div style="font-weight: 600;">Volume total</div>
                <div style="font-size: 12px; margin-top: 5px;">Dossiers règlement: {campagne.nb_dossiers_reglement}</div>
            </div>
        </div>
    </div>
    ''')
    
    # Résultats détaillés
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📈 Résultats détaillés</div>
        <div class="card">
            <div class="grid-2">
                <div>
                    <div class="info-row"><div class="info-label">Volume prévisionnel total</div><div class="info-value"><strong>{campagne.volume_previsionnel}</strong></div></div>
                    <div class="info-row"><div class="info-label">Dossiers prévus</div><div class="info-value"><strong>{campagne.nb_dossiers_prevus}</strong></div></div>
                    <div class="info-row"><div class="info-label">Dossiers règlement à contrôler</div><div class="info-value"><strong>{campagne.nb_dossiers_reglement}</strong></div></div>
                </div>
                <div>
                    <div class="info-row"><div class="info-label">Dossiers contrôlés</div><div class="info-value"><strong class="text-primary">{campagne.nb_dossiers_controles}</strong></div></div>
                    <div class="info-row"><div class="info-label">Dossiers conformes</div><div class="info-value"><strong class="text-success">{campagne.nb_conformes}</strong></div></div>
                    <div class="info-row"><div class="info-label">Dossiers en anomalie</div><div class="info-value"><strong class="text-danger">{campagne.nb_anomalies}</strong></div></div>
                </div>
            </div>
        </div>
    </div>
    ''')
    
    # Commentaires
    if campagne.commentaire_general or campagne.conclusion or campagne.actions_correctives:
        html_parts.append('<div class="section"><div class="section-title">💬 Commentaires et conclusions</div><div class="card">')
        
        if campagne.commentaire_general:
            html_parts.append(f'<div class="info-row"><div class="info-label">Commentaire général</div><div class="info-value">{campagne.commentaire_general}</div></div>')
        
        if campagne.conclusion:
            html_parts.append(f'<div class="info-row"><div class="info-label">Conclusion</div><div class="info-value">{campagne.conclusion}</div></div>')
        
        if campagne.actions_correctives:
            html_parts.append(f'<div class="info-row"><div class="info-label">Actions correctives</div><div class="info-value">{campagne.actions_correctives}</div></div>')
        
        html_parts.append('</div></div>')
    
    # Footer
    html_parts.append(f'''
    <div class="footer">
        <p>Document généré automatiquement le {datetime.now().strftime('%d/%m/%Y à %H:%M')}</p>
        <p>Egalyx Control - Campagne de contrôle - Tous droits réservés</p>
        <p>Ce document est confidentiel</p>
    </div>
    </body>
    </html>
    ''')
    
    html_content = ''.join(html_parts)
    
    try:
        font_config = FontConfiguration()
        pdf = HTML(string=html_content).write_pdf(font_config=font_config)
        
        filename = f"Campagne_Controle_{campagne.reference}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf"
        
        response = Response(pdf, mimetype='application/pdf')
        response.headers['Content-Disposition'] = f'attachment; filename={filename}'
        
        return response
        
    except Exception as e:
        flash(f'Erreur lors de la génération du PDF: {str(e)}', 'error')
        return redirect(url_for('detail_campagne_controle', campagne_id=campagne.id))

# ============================================
# EXPORT PDF POUR PLAN QUALITÉ
# ============================================

@app.route('/qualite/plan/<int:plan_id>/export-pdf')
@login_required
def export_plan_qualite_pdf(plan_id):
    """Export PDF professionnel d'un plan qualité"""
    
    from weasyprint import HTML
    from weasyprint.text.fonts import FontConfiguration
    from datetime import datetime
    
    # Récupérer le plan
    if current_user.role == 'super_admin':
        plan = PlanQualiteFonction.query.get_or_404(plan_id)
    else:
        plan = PlanQualiteFonction.query.filter_by(id=plan_id, client_id=current_user.client_id).first_or_404()
    
    # Organisation
    organisation = None
    org_type = ''
    if plan.pole_id:
        organisation = Pole.query.get(plan.pole_id)
        org_type = 'Pôle'
    elif plan.direction_id:
        organisation = Direction.query.get(plan.direction_id)
        org_type = 'Direction'
    elif plan.service_id:
        organisation = Service.query.get(plan.service_id)
        org_type = 'Service'
    
    # Actions
    actions = ActionAmeliorationQualite.query.filter_by(plan_qualite_id=plan_id).all()
    
    # Statistiques
    stats_actions = {
        'total': len(actions),
        'terminees': len([a for a in actions if a.statut == 'terminee']),
        'en_cours': len([a for a in actions if a.statut == 'en_cours']),
        'a_faire': len([a for a in actions if a.statut == 'a_faire']),
        'avancement': plan.calculer_progression()
    }
    
    # Construction du HTML
    html_parts = []
    
    html_parts.append(f'''
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="UTF-8">
        <title>Plan Qualité - {plan.reference}</title>
        <style>
            @page {{
                size: A4;
                margin: 2cm;
                @top-center {{ content: "Plan d'Assurance et d'Amélioration Qualité - Document confidentiel"; font-size: 9pt; color: #666; }}
                @bottom-center {{ content: "Page " counter(page) " / " counter(pages); font-size: 9pt; color: #666; }}
            }}
            body {{ font-family: 'Segoe UI', Arial, sans-serif; line-height: 1.5; color: #1a2639; background: white; margin: 0; padding: 0; }}
            .header {{ text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 3px solid #1a3650; }}
            .title {{ font-size: 28px; font-weight: 700; color: #1a3650; margin: 10px 0 5px; }}
            .subtitle {{ font-size: 14px; color: #4a5568; letter-spacing: 2px; }}
            .reference {{ font-size: 12px; color: #718096; margin-top: 10px; }}
            .section {{ margin-bottom: 30px; page-break-inside: avoid; }}
            .section-title {{ font-size: 18px; font-weight: 600; color: #1a3650; padding-bottom: 8px; border-bottom: 2px solid #cbd5e0; margin-bottom: 20px; }}
            .card {{ background: #f7fafc; border-radius: 12px; padding: 20px; margin-bottom: 20px; border-left: 4px solid #2c5282; }}
            .grid-2 {{ display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; }}
            .grid-3 {{ display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }}
            .info-row {{ display: flex; padding: 8px 0; border-bottom: 1px solid #e2e8f0; }}
            .info-label {{ width: 180px; font-weight: 600; color: #4a5568; }}
            .info-value {{ flex: 1; color: #2d3748; }}
            .badge {{ display: inline-block; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 600; }}
            .badge-success {{ background: #c6f6d5; color: #22543d; }}
            .badge-warning {{ background: #feebc8; color: #7b341e; }}
            .badge-info {{ background: #bee3f8; color: #2c5282; }}
            .progress-container {{ background: #e2e8f0; border-radius: 10px; height: 12px; overflow: hidden; margin: 10px 0; }}
            .progress-bar {{ height: 100%; border-radius: 10px; transition: width 0.3s ease; }}
            .progress-bar.success {{ background: linear-gradient(90deg, #48bb78, #38a169); }}
            .data-table {{ width: 100%; border-collapse: collapse; margin: 15px 0; }}
            .data-table th {{ background: #edf2f7; padding: 12px; text-align: left; font-weight: 600; color: #2d3748; border-bottom: 2px solid #cbd5e0; }}
            .data-table td {{ padding: 10px 12px; border-bottom: 1px solid #e2e8f0; }}
            .footer {{ margin-top: 40px; padding-top: 20px; text-align: center; font-size: 10px; color: #a0aec0; border-top: 1px solid #e2e8f0; }}
            .stars {{ display: inline-flex; gap: 4px; }}
            .star {{ color: #ecc94b; font-size: 16px; }}
            .star.empty {{ color: #e2e8f0; }}
            @media print {{ body {{ print-color-adjust: exact; -webkit-print-color-adjust: exact; }} }}
        </style>
    </head>
    <body>
    ''')
    
    # Header
    html_parts.append(f'''
    <div class="header">
        <div class="title">PLAN D'ASSURANCE ET D'AMÉLIORATION QUALITÉ</div>
        <div class="subtitle">Plan qualité - Version {plan.version if hasattr(plan, 'version') else '1.0'}</div>
        <div class="reference">Référence: {plan.reference}</div>
    </div>
    ''')
    
    # Informations générales
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📋 Informations générales</div>
        <div class="card">
            <div class="grid-2">
                <div>
                    <div class="info-row"><div class="info-label">Titre</div><div class="info-value">{plan.titre}</div></div>
                    <div class="info-row"><div class="info-label">Statut</div><div class="info-value"><span class="badge {'badge-success' if plan.statut == 'actif' else 'badge-warning'}">{plan.get_statut_label()}</span></div></div>
                    <div class="info-row"><div class="info-label">Période</div><div class="info-value">{plan.date_debut.strftime('%d/%m/%Y')} - {plan.date_fin.strftime('%d/%m/%Y')}</div></div>
                </div>
                <div>
                    <div class="info-row"><div class="info-label">Niveau de maturité</div><div class="info-value"><div class="stars">{''.join(['<span class="star">★</span>' for _ in range(plan.niveau_maturite|int)])}{''.join(['<span class="star empty">★</span>' for _ in range(5 - (plan.niveau_maturite|int))])}</div><div>{plan.get_niveau_maturite_label()}</div></div></div>
                    <div class="info-row"><div class="info-label">Organisation</div><div class="info-value">{org_type}: {organisation.nom if organisation else 'Non spécifié'}</div></div>
                    <div class="info-row"><div class="info-label">Créé le</div><div class="info-value">{plan.created_at.strftime('%d/%m/%Y')}</div></div>
                </div>
            </div>
    ''')
    
    if plan.description:
        html_parts.append(f'<div class="info-row"><div class="info-label">Description</div><div class="info-value">{plan.description}</div></div>')
    
    html_parts.append('</div></div>')
    
    # Assurance qualité
    if plan.procedures_applicables or plan.documents_reference or plan.controles_cles:
        html_parts.append(f'''
        <div class="section">
            <div class="section-title">🛡️ Assurance qualité (Préventif)</div>
            <div class="card">
        ''')
        
        if plan.procedures_applicables:
            html_parts.append(f'<div class="info-row"><div class="info-label">Procédures applicables</div><div class="info-value">{plan.procedures_applicables}</div></div>')
        
        if plan.documents_reference:
            html_parts.append(f'<div class="info-row"><div class="info-label">Documents de référence</div><div class="info-value">{plan.documents_reference}</div></div>')
        
        if plan.controles_cles:
            html_parts.append(f'<div class="info-row"><div class="info-label">Contrôles clés</div><div class="info-value">{plan.controles_cles}</div></div>')
        
        if plan.responsable_conformite:
            html_parts.append(f'<div class="info-row"><div class="info-label">Responsable conformité</div><div class="info-value">{plan.responsable_conformite.username}</div></div>')
        
        html_parts.append('</div></div>')
    
    # Objectifs qualité
    if plan.objectifs_qualite:
        html_parts.append(f'''
        <div class="section">
            <div class="section-title">🎯 Objectifs qualité</div>
            <div class="card">
                <ul style="margin: 0 0 0 20px;">
                    {''.join([f'<li style="margin: 8px 0;">{obj["objectif"]}</li>' for obj in plan.objectifs_qualite])}
                </ul>
            </div>
        </div>
        ''')
    
    # Indicateurs clés
    if plan.indicateurs_cles:
        html_parts.append(f'''
        <div class="section">
            <div class="section-title">📈 Indicateurs clés (KPI)</div>
            <table class="data-table">
                <thead><tr><th>Indicateur</th><th>Cible</th><th>Unité</th></tr></thead>
                <tbody>
                    {''.join([f'<tr><td>{ind["nom"]}</td><td>{ind["cible"]}</td><td>{ind.get("unite", "-")}</td></tr>' for ind in plan.indicateurs_cles])}
                </tbody>
            </table>
        </div>
        ''')
    
    # Revue du plan
    if plan.date_prochaine_revue or plan.date_derniere_revue:
        html_parts.append(f'''
        <div class="section">
            <div class="section-title">📅 Revue et audit du plan</div>
            <div class="card">
                <div class="grid-2">
                    <div class="info-row"><div class="info-label">Prochaine revue</div><div class="info-value">{plan.date_prochaine_revue.strftime('%d/%m/%Y') if plan.date_prochaine_revue else 'Non planifiée'}</div></div>
                    <div class="info-row"><div class="info-label">Dernière revue</div><div class="info-value">{plan.date_derniere_revue.strftime('%d/%m/%Y') if plan.date_derniere_revue else 'Jamais'}</div></div>
                </div>
            </div>
        </div>
        ''')
    
    # Actions d'amélioration
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">✅ Actions d'amélioration ({stats_actions['total']})</div>
        <div class="grid-3" style="margin-bottom: 20px;">
            <div class="card" style="text-align: center;">
                <div style="font-size: 32px; font-weight: 700; color: #4299e1;">{stats_actions['total']}</div>
                <div>Actions totales</div>
            </div>
            <div class="card" style="text-align: center;">
                <div style="font-size: 32px; font-weight: 700; color: #48bb78;">{stats_actions['terminees']}</div>
                <div>Actions terminées</div>
            </div>
            <div class="card" style="text-align: center;">
                <div style="font-size: 32px; font-weight: 700; color: #ed8936;">{stats_actions['avancement']}%</div>
                <div>Avancement global</div>
                <div class="progress-container" style="margin-top: 10px;"><div class="progress-bar success" style="width: {stats_actions['avancement']}%"></div></div>
            </div>
        </div>
    ''')
    
    if actions:
        html_parts.append('''
        <table class="data-table">
            <thead><tr><th>Référence</th><th>Intitulé</th><th>Échéance</th><th>Priorité</th><th>Statut</th><th>Avancement</th></tr></thead>
            <tbody>
        ''')
        
        for a in actions:
            priorite_class = 'badge-danger' if a.priorite == 'haute' else 'badge-warning' if a.priorite == 'moyenne' else 'badge-info'
            statut_class = 'badge-success' if a.statut == 'terminee' else 'badge-warning' if a.statut == 'en_cours' else 'badge-info'
            html_parts.append(f'''
                <tr>
                    <td><code>{a.reference}</code></td>
                    <td>{a.intitule[:50]}</td>
                    <td>{a.date_echeance.strftime('%d/%m/%Y') if a.date_echeance else '-'}</td>
                    <td><span class="badge {priorite_class}">{a.priorite.title()}</span></td>
                    <td><span class="badge {statut_class}">{a.statut.replace('_', ' ').title()}</span></td>
                    <td>
                        <div style="display: flex; align-items: center; gap: 8px;">
                            <div class="progress-container" style="width: 80px;"><div class="progress-bar success" style="width: {a.pourcentage_realisation}%"></div></div>
                            <span>{a.pourcentage_realisation}%</span>
                        </div>
                    </td>
                </tr>
            ''')
        
        html_parts.append('</tbody></table>')
    
    html_parts.append('</div>')
    
    # Footer
    html_parts.append(f'''
    <div class="footer">
        <p>Document généré automatiquement le {datetime.now().strftime('%d/%m/%Y à %H:%M')}</p>
        <p>Egalyx Control - Plan d'Assurance et d'Amélioration Qualité - Tous droits réservés</p>
        <p>Ce document est confidentiel</p>
    </div>
    </body>
    </html>
    ''')
    
    html_content = ''.join(html_parts)
    
    try:
        font_config = FontConfiguration()
        pdf = HTML(string=html_content).write_pdf(font_config=font_config)
        
        filename = f"Plan_Qualite_{plan.reference}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf"
        
        response = Response(pdf, mimetype='application/pdf')
        response.headers['Content-Disposition'] = f'attachment; filename={filename}'
        
        return response
        
    except Exception as e:
        flash(f'Erreur lors de la génération du PDF: {str(e)}', 'error')
        return redirect(url_for('detail_plan_qualite', plan_id=plan_id))

# ============================================
# EXPORT PDF POUR CARTOGRAPHIE DES RISQUES PAR FONCTION D'ASSURANCE
# ============================================
@app.route('/qualite/cartographie-risques/<int:risque_id>/export-pdf')
@login_required
def export_cartographie_risque_pdf(risque_id):
    """Export PDF ultra complet d'un risque de la cartographie"""
    
    from weasyprint import HTML
    from weasyprint.text.fonts import FontConfiguration
    from datetime import datetime
    import json
    
    # Récupérer le risque
    if current_user.role == 'super_admin':
        risque = CartographieRisqueFonction.query.get_or_404(risque_id)
    else:
        risque = CartographieRisqueFonction.query.filter_by(id=risque_id, client_id=current_user.client_id).first_or_404()
    
    # Calcul du niveau de risque
    niveau_risque, niveau_couleur = risque.get_niveau_risque()
    
    # Couleurs pour les badges
    niveau_colors = {
        'Faible': '#10b981',
        'Moyen': '#f59e0b',
        'Élevé': '#ef4444',
        'Critique': '#7f1d1d'
    }
    
    # Construction du HTML (version simplifiée sans date_dernier_test)
    html_parts = []
    
    html_parts.append(f'''
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="UTF-8">
        <title>Cartographie des risques - {risque.zone_risque_majeur}</title>
        <style>
            @page {{
                size: A4;
                margin: 1.5cm;
                @top-center {{
                    content: "Cartographie des risques par fonction d'assurance - Document confidentiel";
                    font-size: 9pt;
                    color: #666;
                }}
                @bottom-center {{
                    content: "Page " counter(page) " / " counter(pages);
                    font-size: 9pt;
                    color: #666;
                }}
            }}
            body {{
                font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
                line-height: 1.5;
                color: #1a2639;
                background: white;
                margin: 0;
                padding: 0;
            }}
            .header {{
                text-align: center;
                margin-bottom: 30px;
                padding-bottom: 20px;
                border-bottom: 3px solid #1a3650;
            }}
            .title {{
                font-size: 28px;
                font-weight: 700;
                color: #1a3650;
                margin: 10px 0 5px;
            }}
            .subtitle {{
                font-size: 14px;
                color: #4a5568;
                letter-spacing: 2px;
            }}
            .reference {{
                font-size: 12px;
                color: #718096;
                margin-top: 10px;
            }}
            .section {{
                margin-bottom: 25px;
                page-break-inside: avoid;
            }}
            .section-title {{
                font-size: 18px;
                font-weight: 600;
                color: #1a3650;
                padding-bottom: 8px;
                border-bottom: 2px solid #cbd5e0;
                margin-bottom: 15px;
                display: flex;
                align-items: center;
                gap: 10px;
            }}
            .card {{
                background: #f7fafc;
                border-radius: 12px;
                padding: 20px;
                margin-bottom: 20px;
                border-left: 4px solid #2c5282;
            }}
            .risk-card {{
                border-left: 4px solid {niveau_colors.get(niveau_risque, '#2c5282')};
                background: linear-gradient(135deg, #ffffff 0%, #f8fafc 100%);
            }}
            .grid-2 {{
                display: grid;
                grid-template-columns: repeat(2, 1fr);
                gap: 20px;
            }}
            .grid-3 {{
                display: grid;
                grid-template-columns: repeat(3, 1fr);
                gap: 20px;
            }}
            .grid-4 {{
                display: grid;
                grid-template-columns: repeat(4, 1fr);
                gap: 15px;
            }}
            .info-row {{
                display: flex;
                padding: 10px 0;
                border-bottom: 1px solid #e2e8f0;
            }}
            .info-label {{
                width: 200px;
                font-weight: 600;
                color: #4a5568;
            }}
            .info-value {{
                flex: 1;
                color: #2d3748;
            }}
            .badge {{
                display: inline-block;
                padding: 4px 12px;
                border-radius: 20px;
                font-size: 12px;
                font-weight: 600;
            }}
            .badge-success {{ background: #c6f6d5; color: #22543d; }}
            .badge-warning {{ background: #feebc8; color: #7b341e; }}
            .badge-danger {{ background: #fed7d7; color: #742a2a; }}
            .badge-info {{ background: #bee3f8; color: #2c5282; }}
            .risk-level {{
                display: inline-block;
                padding: 6px 16px;
                border-radius: 30px;
                font-weight: 700;
                font-size: 14px;
            }}
            .risk-faible {{ background: #d1fae5; color: #065f46; }}
            .risk-moyen {{ background: #fed7aa; color: #9b2c1d; }}
            .risk-eleve {{ background: #fecaca; color: #991b1b; }}
            .risk-critique {{ background: #450a0a; color: #fecaca; }}
            .footer {{
                margin-top: 40px;
                padding-top: 20px;
                text-align: center;
                font-size: 10px;
                color: #a0aec0;
                border-top: 1px solid #e2e8f0;
            }}
            .progress-container {{
                background: #e2e8f0;
                border-radius: 10px;
                height: 12px;
                overflow: hidden;
                margin: 10px 0;
            }}
            .progress-bar {{
                height: 100%;
                border-radius: 10px;
                transition: width 0.3s ease;
            }}
            @media print {{
                body {{ print-color-adjust: exact; -webkit-print-color-adjust: exact; }}
            }}
        </style>
    </head>
    <body>
    ''')
    
    # Header
    html_parts.append(f'''
    <div class="header">
        <div class="title">CARTOGRAPHIE DES RISQUES</div>
        <div class="subtitle">Par fonction d'assurance - Analyse détaillée</div>
        <div class="reference">Année: {risque.annee} | Document généré le {datetime.now().strftime('%d/%m/%Y')}</div>
    </div>
    ''')
    
    # Carte d'identité du risque
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">🎯 IDENTIFICATION DU RISQUE</div>
        <div class="card risk-card">
            <div class="grid-2">
                <div>
                    <div class="info-row"><div class="info-label">Pôle</div><div class="info-value"><strong>{risque.pole}</strong></div></div>
                    <div class="info-row"><div class="info-label">Direction</div><div class="info-value"><strong>{risque.direction}</strong></div></div>
                    <div class="info-row"><div class="info-label">Direction partie prenante</div><div class="info-value">{risque.direction_partie_prenante or '-'}</div></div>
                </div>
                <div>
                    <div class="info-row"><div class="info-label">Zone de risque majeur</div><div class="info-value"><strong style="color: {niveau_colors.get(niveau_risque, '#2c5282')};">{risque.zone_risque_majeur}</strong></div></div>
                    <div class="info-row"><div class="info-label">Typologie du risque</div><div class="info-value">{risque.typologie_risque or '-'}</div></div>
                    <div class="info-row"><div class="info-label">Niveau de risque</div><div class="info-value"><span class="risk-level risk-{niveau_risque.lower()}">{niveau_risque}</span></div></div>
                </div>
            </div>
        </div>
    </div>
    ''')
    
    # Évaluation du risque
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📊 ÉVALUATION DU RISQUE</div>
        <div class="grid-3">
            <div class="card" style="text-align: center;">
                <div style="font-size: 48px; font-weight: 700; color: {'#ef4444' if risque.impact in ['Très fort à éviter', 'Fort à éviter'] else '#f59e0b'};">{risque.impact}</div>
                <div style="margin-top: 10px; font-weight: 600;">IMPACT</div>
            </div>
            <div class="card" style="text-align: center;">
                <div style="font-size: 48px; font-weight: 700; color: {'#ef4444' if risque.probabilite in ['Certain', 'Très probable'] else '#f59e0b'};">{risque.probabilite}</div>
                <div style="margin-top: 10px; font-weight: 600;">PROBABILITÉ</div>
            </div>
            <div class="card" style="text-align: center;">
                <div style="font-size: 48px; font-weight: 700; color: {'#10b981' if risque.niveau_maitrise in ['Excellent', 'Bonne'] else '#ef4444'};">{risque.niveau_maitrise}</div>
                <div style="margin-top: 10px; font-weight: 600;">NIVEAU DE MAÎTRISE</div>
            </div>
        </div>
    </div>
    ''')
    
    # Matrice de criticité
    impact_score = 5 if risque.impact in ['Très fort à éviter', 'Fort à éviter'] else 4 if risque.impact == 'Modéré' else 3
    proba_score = 5 if risque.probabilite in ['Certain', 'Très probable'] else 4 if risque.probabilite == 'Probable' else 3
    criticite_score = impact_score * proba_score
    
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">📈 MATRICE DE CRITICITÉ</div>
        <div class="card">
            <div style="font-weight: 700; margin-bottom: 10px;">Score de criticité : {criticite_score}/25</div>
            <div class="progress-container" style="margin: 15px 0;">
                <div class="progress-bar {'success' if criticite_score <= 8 else 'warning' if criticite_score <= 16 else 'danger'}" style="width: {(criticite_score / 25 * 100)}%; height: 20px;"></div>
            </div>
            <div class="grid-4" style="margin-top: 15px;">
                <div style="text-align: center;"><span style="background: #10b981; display: inline-block; width: 12px; height: 12px; border-radius: 2px;"></span> 0-5: Faible</div>
                <div style="text-align: center;"><span style="background: #f59e0b; display: inline-block; width: 12px; height: 12px; border-radius: 2px;"></span> 6-10: Moyen</div>
                <div style="text-align: center;"><span style="background: #ef4444; display: inline-block; width: 12px; height: 12px; border-radius: 2px;"></span> 11-15: Élevé</div>
                <div style="text-align: center;"><span style="background: #7f1d1d; display: inline-block; width: 12px; height: 12px; border-radius: 2px;"></span> 16-25: Critique</div>
            </div>
        </div>
    </div>
    ''')
    
    # Niveaux de contrôle
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">🔒 NIVEAUX DE CONTRÔLE</div>
        <div class="grid-3">
    ''')
    
    niveaux = [
        ('Niveau 1 - Contrôle opérationnel', risque.niveau_1, '#3b82f6'),
        ('Niveau 2 - Supervision', risque.niveau_2, '#8b5cf6'),
        ('Niveau 3 - Contrôle indépendant', risque.niveau_3, '#ec4899')
    ]
    
    for titre, contenu, couleur in niveaux:
        html_parts.append(f'''
            <div class="card" style="border-top: 3px solid {couleur};">
                <div style="font-weight: 700; margin-bottom: 10px;">{titre}</div>
                <div>{contenu or 'Non renseigné'}</div>
            </div>
        ''')
    
    html_parts.append('</div></div>')
    
    # Synthèse et recommandations
    html_parts.append(f'''
    <div class="section">
        <div class="section-title">💡 SYNTHÈSE ET RECOMMANDATIONS</div>
        <div class="card">
            <div class="grid-2">
                <div>
                    <div style="font-weight: 700; margin-bottom: 10px;">Points d'attention</div>
                    <ul>
                        <li>Impact: <strong>{risque.impact}</strong></li>
                        <li>Probabilité: <strong>{risque.probabilite}</strong></li>
                        <li>Niveau de maîtrise: <strong>{risque.niveau_maitrise}</strong></li>
                    </ul>
                </div>
                <div>
                    <div style="font-weight: 700; margin-bottom: 10px;">Recommandations</div>
                    <ul>
                        <li>{'🔴 Renforcer les contrôles de niveau 1' if risque.niveau_maitrise in ['Faible', 'Insuffisante'] else '🟢 Maintenir le niveau de contrôle'}</li>
                        <li>{'⚠️ Programmer un audit spécifique' if niveau_risque in ['Élevé', 'Critique'] else '📊 Surveillance périodique recommandée'}</li>
                        <li>{'📋 Mettre à jour le plan d\'audit annuel' if risque.plan_audit_annuel else '📅 Établir un premier plan d\'audit'}</li>
                    </ul>
                </div>
            </div>
        </div>
    </div>
    ''')
    
    # Footer
    html_parts.append(f'''
    <div class="footer">
        <p>Document généré automatiquement le {datetime.now().strftime('%d/%m/%Y à %H:%M')}</p>
        <p>Egalyx Control - Cartographie des risques par fonction d'assurance - Tous droits réservés</p>
        <p>Ce document est confidentiel et ne doit pas être diffusé en dehors de l'organisation</p>
    </div>
    </body>
    </html>
    ''')
    
    html_content = ''.join(html_parts)
    
    try:
        font_config = FontConfiguration()
        pdf = HTML(string=html_content).write_pdf(font_config=font_config)
        
        filename = f"Cartographie_Risque_{risque.pole}_{risque.zone_risque_majeur[:30]}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.pdf"
        filename = filename.replace(' ', '_').replace('/', '-')
        
        response = Response(pdf, mimetype='application/pdf')
        response.headers['Content-Disposition'] = f'attachment; filename={filename}'
        
        return response
        
    except Exception as e:
        flash(f'Erreur lors de la génération du PDF: {str(e)}', 'error')
        return redirect(url_for('liste_cartographie_risques'))

# ========================
# ROUTES POUR LA GESTION DES INCIDENTS
