@app.route('/incidents')
@login_required
def liste_incidents():
    """Liste des incidents avec recherche avancée"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Permission requise', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupération des filtres
    gravite = request.args.get('gravite', '')
    type_incident = request.args.get('type_incident', '')
    statut = request.args.get('statut', '')
    escalation = request.args.get('escalation', '')
    sla_viole = request.args.get('sla_viole', '')
    
    query = get_client_filter(Incident).filter_by(is_archived=False)
    
    if gravite:
        query = query.filter_by(gravite=gravite)
    if type_incident:
        query = query.filter_by(type_incident=type_incident)
    if statut:
        query = query.filter_by(statut=statut)
    if escalation:
        query = query.filter_by(niveau_escalade=int(escalation))
    if sla_viole == 'oui':
        query = query.filter_by(sla_viole=True)
    elif sla_viole == 'non':
        query = query.filter_by(sla_viole=False)
    
    page = request.args.get('page', 1, type=int)
    per_page = 20
    
    incidents = query.order_by(Incident.date_occurrence.desc()).paginate(
        page=page, per_page=per_page, error_out=False
    )
    
    # Vérification automatique des SLA
    for incident in incidents.items:
        if incident.verifier_sla():
            db.session.commit()
    
    # Statistiques pour le dashboard
    stats = {
        'total': query.count(),
        'critiques': query.filter_by(gravite='critique').count(),
        'sla_violes': query.filter_by(sla_viole=True).count(),
        'escalade_niveau2': query.filter_by(niveau_escalade=2).count(),
        'escalade_niveau3': query.filter_by(niveau_escalade=3).count(),
        'en_attente_approbation': query.filter_by(approbation_statut='en_attente', approbation_requise=True).count()
    }
    
    return render_template('incidents/liste.html', 
                         incidents=incidents.items,
                         pagination=incidents,
                         stats=stats,
                         current_user=current_user)


@app.route('/incident/nouveau', methods=['GET', 'POST'])
@login_required
def nouvel_incident():
    """Créer un nouvel incident - IA automatique pour tous les niveaux"""
    
    from forms_incident import IncidentForm
    from datetime import datetime, timedelta
    from services.incident_ia_service import IncidentIAService  # ✅ Import IA
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Permission requise', 'error')
        return redirect(url_for('liste_incidents'))
    
    form = IncidentForm()
    
    # Remplir les choix dynamiques
    risques = get_client_filter(Risque).filter_by(is_archived=False).all()
    form.risque_id.choices = [(0, 'Aucun')] + [(r.id, f"{r.reference} - {r.intitule}") for r in risques]
    
    dispositifs = get_client_filter(DispositifMaitrise).filter_by(is_archived=False).all()
    form.dispositif_id.choices = [(0, 'Aucun')] + [(d.id, f"{d.reference} - {d.nom}") for d in dispositifs]
    
    utilisateurs = get_client_filter(User).filter_by(is_active=True).all()
    form.responsable_resolution_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    form.superviseur_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    form.directeur_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    
    if form.validate_on_submit():
        try:
            incident = Incident()
            form.populate_obj(incident)
            incident.declare_par_id = current_user.id
            incident.client_id = current_user.client_id
            incident.created_by = current_user.id
            incident.statut = 'ouvert'
            
            # Gérer les valeurs vides
            if incident.risque_id == 0:
                incident.risque_id = None
            if incident.dispositif_id == 0:
                incident.dispositif_id = None
            if incident.responsable_resolution_id == 0:
                incident.responsable_resolution_id = None
            if incident.superviseur_id == 0:
                incident.superviseur_id = None
            if incident.directeur_id == 0:
                incident.directeur_id = None
            
            # Générer la référence
            incident.reference = incident.generer_reference()
            
            # Calculer la date limite SLA
            if incident.sla_heures:
                incident.sla_date_limite = datetime.utcnow() + timedelta(hours=incident.sla_heures)
            
            db.session.add(incident)
            db.session.commit()
            
            # ✅ Déclencher l'analyse IA automatiquement pour TOUS les incidents
            try:
                IncidentIAService.analyser_incident(incident)
                db.session.commit()
                print(f"✅ Analyse IA automatique déclenchée pour {incident.reference}")
            except Exception as e:
                print(f"⚠️ Erreur analyse IA auto: {e}")
            
            flash(f'Incident {incident.reference} créé avec succès', 'success')
            return redirect(url_for('detail_incident', id=incident.id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('incidents/form.html', form=form, action='Créer')


@app.route('/incident/<int:id>')
@login_required
def detail_incident(id):
    """Détail complet d'un incident"""
    
    incident = get_client_object_or_404(Incident, id)
    
    if not check_client_access(incident):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('liste_incidents'))
    
    # Récupérer l'historique
    historique = IncidentHistorique.query.filter_by(incident_id=id)\
        .order_by(IncidentHistorique.created_at.desc()).all()
    
    return render_template('incidents/detail.html', 
                         incident=incident, 
                         historique=historique,
                         current_user=current_user)

@app.route('/incident/<int:id>/resoudre', methods=['GET', 'POST'])
@login_required
def resoudre_incident(id):
    from forms_incident import IncidentResolutionForm
    from services.incident_ia_service import IncidentIAService
    from datetime import datetime

    incident = get_client_object_or_404(Incident, id)

    if not check_client_access(incident):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('liste_incidents'))

    # Déclencher l'analyse IA si absente (quel que soit le niveau)
    if not incident.analyse_ia:
        try:
            IncidentIAService.analyser_incident(incident)
            db.session.commit()
            flash('🤖 Analyse IA automatique effectuée', 'info')
        except Exception as e:
            print(f"Erreur analyse IA auto: {e}")

    # Générer les suggestions IA (mais ne pas pré-remplir)
    suggestions_ia = {}
    if incident.analyse_ia:
        suggestions_ia = IncidentIAService.suggerer_resolution(incident)

    form = IncidentResolutionForm()

    # NE PAS pré-remplir avec les suggestions IA (seulement les valeurs déjà saisies)
    if request.method == 'GET':
        form.statut.data = incident.statut if incident.statut != 'ouvert' else 'en_cours'
        form.cause_racine.data = incident.cause_racine or ''
        form.actions_correctives.data = incident.actions_correctives or ''
        form.lecons_apprises.data = incident.lecons_apprises or ''
        form.commentaire_cloture.data = incident.commentaire_cloture or ''

    if form.validate_on_submit():
        try:
            ancien_statut = incident.statut

            incident.statut = form.statut.data
            incident.cause_racine = form.cause_racine.data
            incident.actions_correctives = form.actions_correctives.data
            incident.lecons_apprises = form.lecons_apprises.data
            incident.commentaire_cloture = form.commentaire_cloture.data

            if form.statut.data in ['resolu', 'ferme']:
                incident.date_resolution = datetime.utcnow()

            incident.updated_at = datetime.utcnow()
            db.session.commit()

            # Création plan d'action si demandé
            if form.creer_plan_action.data:
                from models import PlanAction
                count = PlanAction.query.filter_by(client_id=current_user.client_id).count()
                reference = f"PA-INC-{incident.id}-{count + 1:03d}"
                plan = PlanAction(
                    reference=reference,
                    nom=f"Traitement incident {incident.reference}",
                    description=f"Actions correctives suite à l'incident: {incident.titre}\n\nCause racine: {incident.cause_racine or 'Non spécifiée'}",
                    risque_id=incident.risque_id,
                    responsable_id=incident.responsable_resolution_id,
                    statut='en_cours',
                    created_by=current_user.id,
                    client_id=current_user.client_id
                )
                db.session.add(plan)
                db.session.flush()
                incident.plan_action_id = plan.id
                db.session.commit()
                flash(f'📋 Plan d\'action {reference} créé', 'info')

            # Journaliser
            IncidentHistorique(
                incident_id=id,
                action='resolution',
                details=f"Statut changé de {ancien_statut} à {incident.statut}",
                utilisateur_id=current_user.id
            )
            db.session.commit()

            flash(f'✅ Incident {incident.reference} mis à jour avec succès', 'success')
            return redirect(url_for('detail_incident', id=id))

        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')

    return render_template('incidents/resolution.html',
                           form=form,
                           incident=incident,
                           now=datetime.utcnow(),
                           suggestions_ia=suggestions_ia)
@app.route('/incident/<int:id>/approuver', methods=['GET', 'POST'])
@login_required
def approuver_incident(id):
    """Page d'approbation d'incident pour superviseur"""
    
    from forms_incident import IncidentApprobationForm
    
    incident = get_client_object_or_404(Incident, id)
    
    if not check_client_access(incident):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('liste_incidents'))
    
    if not incident.approbation_requise:
        flash('L\'approbation n\'est pas requise pour cet incident', 'warning')
        return redirect(url_for('detail_incident', id=id))
    
    if incident.approbation_statut != 'en_attente':
        flash(f'Cet incident a déjà été {incident.get_approbation_statut_label()}', 'info')
        return redirect(url_for('detail_incident', id=id))
    
    form = IncidentApprobationForm()
    
    if form.validate_on_submit():
        try:
            if form.approbation.data == 'approuve':
                incident.approuver(current_user.id, form.commentaire.data)
                flash('✅ Incident approuvé et clôturé avec succès', 'success')
            else:
                incident.rejeter(current_user.id, form.commentaire.data)
                flash('⚠️ Incident rejeté - Retour en cours pour corrections', 'warning')
            
            # Journaliser l'action
            from models import IncidentHistorique
            historique = IncidentHistorique(
                incident_id=id,
                action=f'approbation_{form.approbation.data}',
                details=form.commentaire.data,
                utilisateur_id=current_user.id,
                created_at=datetime.utcnow()
            )
            db.session.add(historique)
            db.session.commit()
            
            return redirect(url_for('detail_incident', id=id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')
    
    return render_template('incidents/approbation.html', 
                         form=form, 
                         incident=incident)

# ========================
# TÂCHE PLANIFIÉE - VÉRIFICATION ESCALADES
# ========================

def verifier_escalades_auto():
    """Vérifie automatiquement les escalades des incidents (toutes les heures)"""
    from services.escalade_service import EscaladeService
    
    print("🔍 Vérification automatique des escalades d'incidents...")
    with app.app_context():
        incidents = Incident.query.filter(
            Incident.statut.in_(['ouvert', 'en_cours']),
            Incident.niveau_escalade < 3,
            Incident.is_archived == False
        ).all()
        
        escalades_declenchees = 0
        for incident in incidents:
            if EscaladeService.verifier_et_escalader_auto(incident):
                escalades_declenchees += 1
                print(f"⚠️ Escalade automatique déclenchée pour {incident.reference} (niveau {incident.niveau_escalade})")
        
        db.session.commit()
        print(f"✅ Vérification terminée: {escalades_declenchees} escalade(s) déclenchée(s)")

# Ajoutez cette tâche à votre scheduler existant
def demarrer_taches_escalade():
    """Démarre les tâches planifiées pour les escalades"""
    from apscheduler.schedulers.background import BackgroundScheduler
    
    scheduler = BackgroundScheduler()
    
    # Vérifier les escalades toutes les heures
    scheduler.add_job(
        func=verifier_escalades_auto,
        trigger="interval",
        hours=1,
        id="verif_escalades_auto",
        name="Vérification automatique des escalades",
        replace_existing=True
    )
    
    scheduler.start()
    print("✅ Tâches d'escalade démarrées")

# Appeler au démarrage (dans votre contexte d'application)
with app.app_context():
    try:
        demarrer_taches_escalade()
    except Exception as e:
        print(f"⚠️ Erreur démarrage tâches escalade: {e}")


