from services.escalade_service import EscaladeService

@app.route('/api/incident/<int:id>/escalader', methods=['POST'])
@login_required
def api_escalader_incident(id):
    """API pour escalader manuellement un incident"""
    incident = get_client_object_or_404(Incident, id)
    
    # Vérifier les permissions
    if not current_user.has_permission('can_manage_audit'):
        return jsonify({'success': False, 'error': 'Permission non autorisée'}), 403
    
    data = request.get_json()
    raison = data.get('raison', '')
    
    if not raison:
        return jsonify({'success': False, 'error': 'Une raison est requise pour l\'escalade'}), 400
    
    if incident.niveau_escalade >= 3:
        return jsonify({'success': False, 'error': 'Niveau maximum déjà atteint'}), 400
    
    try:
        success = EscaladeService.escalader(incident, auto=False, raison=raison)
        
        if success:
            return jsonify({
                'success': True,
                'message': f'Incident escaladé au niveau {incident.niveau_escalade}',
                'niveau': incident.niveau_escalade,
                'nouveau_responsable': incident.responsable.username if incident.responsable else None
            })
        else:
            return jsonify({'success': False, 'error': 'Escalade impossible'}), 400
            
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

