@app.route('/api/client/user/<int:user_id>/reset-password', methods=['POST'])
@login_required
def api_reset_user_password(user_id):
    """Réinitialiser le mot de passe d'un utilisateur"""
    
    # Vérifier que l'utilisateur est super admin
    if current_user.role != 'super_admin':
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403
    
    user = User.query.get_or_404(user_id)
    data = request.get_json()
    new_password = data.get('password')
    
    if not new_password or len(new_password) < 8:
        return jsonify({'success': False, 'error': 'Le mot de passe doit contenir au moins 8 caractères'}), 400
    
    try:
        user.set_password(new_password)
        user.updated_at = datetime.utcnow()
        db.session.commit()
        
        # Journaliser l'action
        log_activity(current_user.id, 'reset_password',
                    f'Mot de passe réinitialisé pour {user.username}',
                    'user', user.id)
        
        return jsonify({
            'success': True,
            'message': f'Mot de passe réinitialisé pour {user.username}',
            'username': user.username
        })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500
    

