@app.route('/incident/<int:id>/escalader', methods=['POST'])
@login_required
def escalader_incident(id):
    """Escalader manuellement un incident"""
    
    from datetime import datetime
    from models import IncidentHistorique, Notification
    
    incident = get_client_object_or_404(Incident, id)
    
    if not check_client_access(incident):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    if incident.niveau_escalade >= 3:
        flash('Niveau maximum déjà atteint', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    if incident.is_archived:
        flash('Cet incident est archivé, impossible de l\'escalader', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    if incident.statut in ['ferme', 'resolu', 'rejete']:
        flash('Cet incident est déjà clôturé, impossible de l\'escalader', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    raison = request.form.get('raison', '').strip()
    
    if not raison:
        flash('La raison de l\'escalade est requise', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    try:
        ancien_niveau = incident.niveau_escalade
        ancien_responsable_id = incident.responsable_resolution_id
        
        # Incrémenter le niveau
        incident.niveau_escalade += 1
        incident.escalade_date = datetime.utcnow()
        incident.escalation_auto = False
        incident.raison_escalade = raison
        incident.derniere_action_date = datetime.utcnow()
        incident.updated_at = datetime.utcnow()
        
        # Changer le responsable selon le nouveau niveau
        nouveau_responsable_id = None
        if incident.niveau_escalade == 2 and incident.superviseur_id:
            nouveau_responsable_id = incident.superviseur_id
            incident.responsable_resolution_id = incident.superviseur_id
        elif incident.niveau_escalade == 3 and incident.directeur_id:
            nouveau_responsable_id = incident.directeur_id
            incident.responsable_resolution_id = incident.directeur_id
        
        # Journaliser l'historique
        historique = IncidentHistorique(
            incident_id=id,
            action='escalade_manuelle',
            details=f"Escalade N{ancien_niveau} -> N{incident.niveau_escalade} | Raison: {raison}",
            utilisateur_id=current_user.id,
            created_at=datetime.utcnow()
        )
        db.session.add(historique)
        
        # Créer une notification pour le nouveau responsable
        if nouveau_responsable_id and nouveau_responsable_id != ancien_responsable_id:
            notification = Notification(
                type_notification='escalade',
                titre=f"Incident escaladé - Niveau {incident.niveau_escalade}",
                message=f"L'incident {incident.reference} - {incident.titre} a été escaladé au niveau {incident.niveau_escalade}.\n\nRaison: {raison}\n\nMerci de prendre en charge cet incident.",
                destinataire_id=nouveau_responsable_id,
                entite_type='incident',
                entite_id=incident.id,
                urgence='urgent' if incident.niveau_escalade >= 2 else 'important',
                donnees_supplementaires={
                    'incident_reference': incident.reference,
                    'ancien_niveau': ancien_niveau,
                    'nouveau_niveau': incident.niveau_escalade,
                    'raison': raison,
                    'escalade_par': current_user.username
                },
                created_at=datetime.utcnow(),
                client_id=incident.client_id
            )
            db.session.add(notification)
            
            # Notifier aussi l'ancien responsable qu'il n'est plus responsable
            if ancien_responsable_id:
                notification_ancien = Notification(
                    type_notification='info',
                    titre=f"Incident {incident.reference} - Changement de responsable",
                    message=f"L'incident {incident.reference} a été escaladé au niveau {incident.niveau_escalade}. Vous n'êtes plus responsable de cet incident.",
                    destinataire_id=ancien_responsable_id,
                    entite_type='incident',
                    entite_id=incident.id,
                    urgence='normal',
                    created_at=datetime.utcnow(),
                    client_id=incident.client_id
                )
                db.session.add(notification_ancien)
        
        db.session.commit()
        
        flash(f'✅ Incident escaladé au niveau {incident.niveau_escalade} ({incident.get_niveau_escalade_label()})', 'success')
        
    except Exception as e:
        db.session.rollback()
        import traceback
        traceback.print_exc()
        flash(f'❌ Erreur lors de l\'escalade: {str(e)}', 'error')
    
    return redirect(url_for('detail_incident', id=id))

