import json

@app.template_filter('from_json')
def from_json_filter(value):
    """Convertit une chaîne JSON en objet Python"""
    if not value:
        return {}
    try:
        if isinstance(value, str):
            return json.loads(value)
        return value
    except (json.JSONDecodeError, TypeError):
        return {}

@app.route('/incidents/dashboard-ia')
@login_required
def dashboard_ia_incidents():
    """Dashboard d'analyse IA des incidents"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Permission requise', 'error')
        return redirect(url_for('dashboard'))
    
    from services.incident_ia_service import IncidentIAService
    
    # Détection des tendances
    tendances = IncidentIAService.detecter_tendance_incidents(current_user.client_id)
    
    # Suggestions d'amélioration
    ameliorations = IncidentIAService.suggerer_ameliorations(current_user.client_id)
    
    # Incidents avec analyse IA
    incidents_ia = get_client_filter(Incident)\
        .filter(Incident.analyse_ia.isnot(None))\
        .order_by(Incident.ia_score_confiance.desc())\
        .limit(10).all()
    
    # Risques de récurrence élevés
    incidents_recurrents = []
    for inc in get_client_filter(Incident).filter_by(is_archived=False).all():
        if inc.date_resolution:
            pred = IncidentIAService.predire_recurrence(inc)
            if pred['probabilite_recurrence'] > 70:
                incidents_recurrents.append({
                    'incident': inc,
                    'probabilite': pred['probabilite_recurrence'],
                    'recommandation': pred['recommandation']
                })
    
    return render_template('incidents/dashboard_ia.html',
                         tendances=tendances,
                         ameliorations=ameliorations,
                         incidents_ia=incidents_ia,
                         incidents_recurrents=incidents_recurrents[:10])


