@app.route('/api/incidents', methods=['GET'])
@login_required
def api_liste_incidents():
    """API REST - Liste des incidents"""
    
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    
    query = get_client_filter(Incident).filter_by(is_archived=False)
    
    # Filtres
    for field in ['gravite', 'type_incident', 'statut']:
        if request.args.get(field):
            query = query.filter(getattr(Incident, field) == request.args.get(field))
    
    pagination = query.paginate(page=page, per_page=per_page, error_out=False)
    
    return jsonify({
        'success': True,
        'data': [inc.to_dict() for inc in pagination.items],
        'pagination': {
            'page': page,
            'per_page': per_page,
            'total': pagination.total,
            'pages': pagination.pages
        }
    })


