@app.route('/api/incidents/stats', methods=['GET'])
@login_required
def api_stats_incidents():
    """API REST - Statistiques des incidents"""
    
    query = get_client_filter(Incident).filter_by(is_archived=False)
    
    stats = {
        'total': query.count(),
        'par_gravite': {},
        'par_type': {},
        'par_statut': {},
        'par_escalade': {},
        'sla_violes': query.filter_by(sla_viole=True).count(),
        'temps_moyen_resolution': None
    }
    
    for gravite in ['critique', 'elevee', 'moyenne', 'mineure']:
        stats['par_gravite'][gravite] = query.filter_by(gravite=gravite).count()
    
    for type_inc in ['securite', 'conformite', 'operationnel', 'technique', 'juridique']:
        stats['par_type'][type_inc] = query.filter_by(type_incident=type_inc).count()
    
    for statut in ['ouvert', 'en_cours', 'resolu', 'ferme', 'rejete']:
        stats['par_statut'][statut] = query.filter_by(statut=statut).count()
    
    for niveau in [1, 2, 3]:
        stats['par_escalade'][f'niveau_{niveau}'] = query.filter_by(niveau_escalade=niveau).count()
    
    # Temps moyen de résolution
    incidents_fermes = query.filter(Incident.statut.in_(['ferme', 'resolu']))\
                            .filter(Incident.date_resolution.isnot(None))\
                            .all()
    
    if incidents_fermes:
        delais = [(inc.date_resolution - inc.date_occurrence).days for inc in incidents_fermes]
        stats['temps_moyen_resolution'] = round(sum(delais) / len(delais), 1)
    
    return jsonify({'success': True, 'stats': stats})


