@app.route('/support/ticket/<int:id>/traiter', methods=['POST'])
@login_required
def traiter_ticket(id):
    """Traiter un ticket et le convertir en incident si nécessaire"""
    
    ticket = TicketSupport.query.get_or_404(id)
    
    if request.form.get('convertir_incident') == 'on':
        # Créer un incident à partir du ticket
        incident = Incident(
            titre=ticket.sujet,
            description=f"Ticket support: {ticket.reference}\n\n{ticket.description}",
            gravite='moyenne',
            type_incident='technique',
            date_occurrence=ticket.created_at,
            declare_par_id=current_user.id,
            client_id=current_user.client_id,
            created_by=current_user.id
        )
        incident.reference = incident.generer_reference()
        
        db.session.add(incident)
        db.session.flush()
        
        ticket.incident_id = incident.id
    
    ticket.statut = request.form.get('statut', 'traite')
    ticket.traite_par_id = current_user.id
    ticket.updated_at = datetime.utcnow()
    
    db.session.commit()
    
    flash(f'Ticket {ticket.reference} traité avec succès', 'success')
    return redirect(url_for('liste_tickets_support'))


@app.route('/incidents/export/excel')
@login_required
def export_incidents_excel():
    """Export des incidents au format Excel"""
    
    if not current_user.has_permission('can_export_data'):
        flash('Permission refusée', 'error')
        return redirect(url_for('liste_incidents'))
    
    try:
        import openpyxl
        from openpyxl.styles import Font, Alignment, PatternFill, Border, Side
        from io import BytesIO
        from datetime import datetime
        
        # Récupérer les incidents avec filtres
        gravite = request.args.get('gravite', '')
        type_incident = request.args.get('type_incident', '')
        statut = request.args.get('statut', '')
        
        query = get_client_filter(Incident).filter_by(is_archived=False)
        
        if gravite:
            query = query.filter_by(gravite=gravite)
        if type_incident:
            query = query.filter_by(type_incident=type_incident)
        if statut:
            query = query.filter_by(statut=statut)
        
        incidents = query.order_by(Incident.date_occurrence.desc()).all()
        
        # Créer le classeur
        wb = openpyxl.Workbook()
        
        # ========== FEUILLE 1 : LISTE DES INCIDENTS ==========
        ws1 = wb.active
        ws1.title = "Incidents"
        
        # En-têtes
        headers = ['Référence', 'Titre', 'Description', 'Type', 'Gravité', 'Statut',
                   'Date occurrence', 'Date détection', 'Date résolution', 'Délai (jours)',
                   'Cause racine', 'Actions correctives', 'Leçons apprises',
                   'Risque associé', 'Responsable', 'SLA (heures)', 'Niveau escalade']
        
        # Style des en-têtes
        header_font = Font(bold=True, color="FFFFFF")
        header_fill = PatternFill(start_color="1a3650", end_color="1a3650", fill_type="solid")
        
        for col, header in enumerate(headers, 1):
            cell = ws1.cell(row=1, column=col, value=header)
            cell.font = header_font
            cell.fill = header_fill
            cell.alignment = Alignment(horizontal='center')
        
        # Remplir les données
        for row, incident in enumerate(incidents, 2):
            ws1.cell(row=row, column=1, value=incident.reference)
            ws1.cell(row=row, column=2, value=incident.titre)
            ws1.cell(row=row, column=3, value=incident.description or '')
            ws1.cell(row=row, column=4, value=incident.get_type_label())
            ws1.cell(row=row, column=5, value=incident.get_gravite_label())
            ws1.cell(row=row, column=6, value=incident.get_statut_label())
            ws1.cell(row=row, column=7, value=incident.date_occurrence.strftime('%d/%m/%Y %H:%M') if incident.date_occurrence else '')
            ws1.cell(row=row, column=8, value=incident.date_detection.strftime('%d/%m/%Y %H:%M') if incident.date_detection else '')
            ws1.cell(row=row, column=9, value=incident.date_resolution.strftime('%d/%m/%Y %H:%M') if incident.date_resolution else '')
            ws1.cell(row=row, column=10, value=incident.get_delai_resolution() if incident.get_delai_resolution() else '')
            ws1.cell(row=row, column=11, value=incident.cause_racine or '')
            ws1.cell(row=row, column=12, value=incident.actions_correctives or '')
            ws1.cell(row=row, column=13, value=incident.lecons_apprises or '')
            ws1.cell(row=row, column=14, value=incident.risque.reference if incident.risque else '')
            ws1.cell(row=row, column=15, value=incident.responsable.username if incident.responsable else '')
            ws1.cell(row=row, column=16, value=incident.sla_heures or '')
            ws1.cell(row=row, column=17, value=incident.get_niveau_escalade_label())
            
            # Colorer la ligne selon la gravité
            if incident.gravite == 'critique':
                for col in range(1, 18):
                    ws1.cell(row, col).fill = PatternFill(start_color="FFE5E5", end_color="FFE5E5", fill_type="solid")
            elif incident.gravite == 'elevee':
                for col in range(1, 18):
                    ws1.cell(row, col).fill = PatternFill(start_color="FFF3CD", end_color="FFF3CD", fill_type="solid")
        
        # Ajuster les colonnes
        for col in range(1, 18):
            ws1.column_dimensions[openpyxl.utils.get_column_letter(col)].width = 18
        
        # ========== FEUILLE 2 : STATISTIQUES ==========
        ws2 = wb.create_sheet("Statistiques")
        
        stats = {
            'Total incidents': len(incidents),
            'Par gravité': {},
            'Par type': {},
            'Par statut': {},
            'Par escalade': {},
            'Temps moyen résolution': None
        }
        
        for inc in incidents:
            stats['Par gravité'][inc.get_gravite_label()] = stats['Par gravité'].get(inc.get_gravite_label(), 0) + 1
            stats['Par type'][inc.get_type_label()] = stats['Par type'].get(inc.get_type_label(), 0) + 1
            stats['Par statut'][inc.get_statut_label()] = stats['Par statut'].get(inc.get_statut_label(), 0) + 1
            stats['Par escalade'][inc.get_niveau_escalade_label()] = stats['Par escalade'].get(inc.get_niveau_escalade_label(), 0) + 1
        
        # Calcul du temps moyen de résolution
        incidents_resolus = [i for i in incidents if i.date_resolution]
        if incidents_resolus:
            delais = [(i.date_resolution - i.date_occurrence).days for i in incidents_resolus]
            stats['Temps moyen résolution'] = round(sum(delais) / len(delais), 1)
        
        row = 1
        for key, value in stats.items():
            if isinstance(value, dict):
                ws2.cell(row=row, column=1, value=key)
                row += 1
                for subkey, subvalue in value.items():
                    ws2.cell(row=row, column=1, value=f"  - {subkey}")
                    ws2.cell(row=row, column=2, value=subvalue)
                    row += 1
            else:
                ws2.cell(row=row, column=1, value=key)
                ws2.cell(row=row, column=2, value=value)
                row += 1
        
        # ========== FEUILLE 3 : INCIDENTS PAR MOIS ==========
        ws3 = wb.create_sheet("Incidents par mois")
        
        mois_stats = {}
        for inc in incidents:
            mois = inc.date_occurrence.strftime('%Y-%m')
            if mois not in mois_stats:
                mois_stats[mois] = {'total': 0, 'critiques': 0}
            mois_stats[mois]['total'] += 1
            if inc.gravite == 'critique':
                mois_stats[mois]['critiques'] += 1
        
        ws3.cell(1, 1, "Mois")
        ws3.cell(1, 2, "Total incidents")
        ws3.cell(1, 3, "Incidents critiques")
        
        for row, (mois, data) in enumerate(sorted(mois_stats.items()), 2):
            ws3.cell(row, 1, mois)
            ws3.cell(row, 2, data['total'])
            ws3.cell(row, 3, data['critiques'])
        
        # Sauvegarde
        buffer = BytesIO()
        wb.save(buffer)
        buffer.seek(0)
        
        filename = f"incidents_{datetime.now().strftime('%Y%m%d_%H%M%S')}.xlsx"
        
        return send_file(
            buffer,
            as_attachment=True,
            download_name=filename,
            mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        )
        
    except Exception as e:
        flash(f'Erreur lors de l\'export Excel: {str(e)}', 'error')
        return redirect(url_for('liste_incidents'))


@app.route('/incidents/export/csv')
@login_required
def export_incidents_csv():
    """Export des incidents au format CSV"""
    
    if not current_user.has_permission('can_export_data'):
        flash('Permission refusée', 'error')
        return redirect(url_for('liste_incidents'))
    
    try:
        import csv
        from io import StringIO
        from datetime import datetime
        
        # Récupérer les incidents avec filtres
        gravite = request.args.get('gravite', '')
        type_incident = request.args.get('type_incident', '')
        statut = request.args.get('statut', '')
        
        query = get_client_filter(Incident).filter_by(is_archived=False)
        
        if gravite:
            query = query.filter_by(gravite=gravite)
        if type_incident:
            query = query.filter_by(type_incident=type_incident)
        if statut:
            query = query.filter_by(statut=statut)
        
        incidents = query.order_by(Incident.date_occurrence.desc()).all()
        
        output = StringIO()
        writer = csv.writer(output, delimiter=';', quoting=csv.QUOTE_ALL)
        
        # En-têtes
        headers = [
            'Référence', 'Titre', 'Description', 'Type', 'Gravité', 'Statut',
            'Date occurrence', 'Date détection', 'Date résolution', 'Délai (jours)',
            'Cause racine', 'Actions correctives', 'Leçons apprises',
            'Risque associé', 'Responsable', 'SLA (heures)', 'Niveau escalade'
        ]
        writer.writerow(headers)
        
        # Données
        for incident in incidents:
            writer.writerow([
                incident.reference,
                incident.titre,
                incident.description or '',
                incident.get_type_label(),
                incident.get_gravite_label(),
                incident.get_statut_label(),
                incident.date_occurrence.strftime('%d/%m/%Y %H:%M') if incident.date_occurrence else '',
                incident.date_detection.strftime('%d/%m/%Y %H:%M') if incident.date_detection else '',
                incident.date_resolution.strftime('%d/%m/%Y %H:%M') if incident.date_resolution else '',
                incident.get_delai_resolution() or '',
                incident.cause_racine or '',
                incident.actions_correctives or '',
                incident.lecons_apprises or '',
                incident.risque.reference if incident.risque else '',
                incident.responsable.username if incident.responsable else '',
                incident.sla_heures or '',
                incident.get_niveau_escalade_label()
            ])
        
        output.seek(0)
        
        filename = f"incidents_{datetime.now().strftime('%Y%m%d_%H%M%S')}.csv"
        
        return Response(
            output.getvalue(),
            mimetype='text/csv; charset=utf-8',
            headers={
                'Content-Disposition': f'attachment; filename={filename}'
            }
        )
        
    except Exception as e:
        flash(f'Erreur lors de l\'export CSV: {str(e)}', 'error')
        return redirect(url_for('liste_incidents'))


