# ========================
# TÂCHES AUTOMATISÉES (Scheduler)
# ========================

def verifier_escalade_auto():
    """Vérifie et escalade automatiquement les incidents dépassant les délais"""
    
    with app.app_context():
        incidents = Incident.query.filter(
            Incident.statut.in_(['ouvert', 'en_cours']),
            Incident.escalation_auto == False
        ).all()
        
        for incident in incidents:
            # Vérifier si le SLA est dépassé
            if incident.sla_date_limite and datetime.utcnow() > incident.sla_date_limite:
                incident.escalader()
                db.session.commit()
                
                # Créer une notification
                creer_notification(
                    type_notification='warning',
                    titre=f"SLA violé - Incident {incident.reference}",
                    message=f"L'incident a été automatiquement escaladé au niveau {incident.niveau_escalade}",
                    destinataire_id=incident.superviseur_id or incident.responsable_resolution_id,
                    entite_type='incident',
                    entite_id=incident.id
                )


def analyser_incidents_ia_auto():
    """Analyse automatique des incidents récents avec IA"""
    
    with app.app_context():
        from services.incident_ia_service import IncidentIAService
        
        incidents = Incident.query.filter(
            Incident.analyse_ia == None,
            Incident.created_at >= datetime.utcnow() - timedelta(days=7)
        ).limit(50).all()
        
        for incident in incidents:
            if incident.gravite in ['critique', 'elevee']:
                IncidentIAService.analyser_incident(incident)
                db.session.commit()
                time.sleep(1)  # Pause pour éviter de surcharger l'API


# Démarrer les tâches automatiques
def demarrer_taches_incidents():
    """Démarre les tâches planifiées pour les incidents"""
    
    scheduler = BackgroundScheduler()
    
    # Vérification des escalades toutes les heures
    scheduler.add_job(
        func=verifier_escalade_auto,
        trigger="interval",
        hours=1,
        id="verif_escalade_auto",
        name="Vérification automatique des escalades"
    )
    
    # Analyse IA des nouveaux incidents (toutes les 6 heures)
    scheduler.add_job(
        func=analyser_incidents_ia_auto,
        trigger="interval",
        hours=6,
        id="analyse_ia_auto",
        name="Analyse IA automatique des incidents"
    )
    
    scheduler.start()
    print("✅ Tâches incidents démarrées")



@app.route('/incident/<int:id>/modifier', methods=['GET', 'POST'])
@login_required
def modifier_incident(id):
    """Page de modification d'un incident"""
    
    from forms_incident import IncidentForm
    from datetime import datetime, timedelta
    from models import IncidentHistorique
    
    incident = get_client_object_or_404(Incident, id)
    
    if not check_client_access(incident):
        flash('Accès non autorisé', 'error')
        return redirect(url_for('liste_incidents'))
    
    # Vérifier si l'utilisateur peut modifier
    if not incident.peut_modifier(current_user):
        flash('Vous n\'avez pas les permissions pour modifier cet incident', 'error')
        return redirect(url_for('detail_incident', id=id))
    
    form = IncidentForm(obj=incident)
    
    # Remplir les choix dynamiques
    risques = get_client_filter(Risque).filter_by(is_archived=False).all()
    form.risque_id.choices = [(0, 'Aucun')] + [(r.id, f"{r.reference} - {r.intitule}") for r in risques]
    
    dispositifs = get_client_filter(DispositifMaitrise).filter_by(is_archived=False).all()
    form.dispositif_id.choices = [(0, 'Aucun')] + [(d.id, f"{d.reference} - {d.nom}") for d in dispositifs]
    
    utilisateurs = get_client_filter(User).filter_by(is_active=True).all()
    form.responsable_resolution_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    form.superviseur_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    form.directeur_id.choices = [(0, 'Non assigné')] + [(u.id, f"{u.username} - {u.role}") for u in utilisateurs]
    
    if form.validate_on_submit():
        try:
            # Mettre à jour les champs
            incident.titre = form.titre.data
            incident.description = form.description.data
            incident.gravite = form.gravite.data
            incident.type_incident = form.type_incident.data
            incident.date_occurrence = form.date_occurrence.data
            incident.sla_heures = form.sla_heures.data
            incident.approbation_requise = form.approbation_requise.data
            
            # Gérer les IDs
            incident.risque_id = form.risque_id.data if form.risque_id.data != 0 else None
            incident.dispositif_id = form.dispositif_id.data if form.dispositif_id.data != 0 else None
            incident.responsable_resolution_id = form.responsable_resolution_id.data if form.responsable_resolution_id.data != 0 else None
            incident.superviseur_id = form.superviseur_id.data if form.superviseur_id.data != 0 else None
            incident.directeur_id = form.directeur_id.data if form.directeur_id.data != 0 else None
            
            # Recalculer la date limite SLA
            if incident.sla_heures:
                incident.sla_date_limite = datetime.utcnow() + timedelta(hours=incident.sla_heures)
            
            incident.updated_at = datetime.utcnow()
            db.session.commit()
            
            # Journaliser la modification
            historique = IncidentHistorique(
                incident_id=id,
                action='modification',
                details=f"Incident modifié par {current_user.username}",
                utilisateur_id=current_user.id,
                created_at=datetime.utcnow()
            )
            db.session.add(historique)
            db.session.commit()
            
            flash(f'✅ Incident {incident.reference} modifié avec succès', 'success')
            return redirect(url_for('detail_incident', id=id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'❌ Erreur: {str(e)}', 'error')
    
    # Pré-remplir le formulaire pour GET
    if request.method == 'GET':
        form.risque_id.data = incident.risque_id or 0
        form.dispositif_id.data = incident.dispositif_id or 0
        form.responsable_resolution_id.data = incident.responsable_resolution_id or 0
        form.superviseur_id.data = incident.superviseur_id or 0
        form.directeur_id.data = incident.directeur_id or 0
    
    return render_template('incidents/form_modifier.html', 
                         form=form, 
                         incident=incident,
                         action='Modifier')

