@app.route('/pca/plans')
@login_required
def liste_plans_pca():
    """Liste des plans de continuité d'activité"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    # Filtres
    statut = request.args.get('statut', '')
    show_archived = request.args.get('show_archived', 'false') == 'true'
    
    # Requête multi-tenant
    if current_user.role == 'super_admin':
        query = PlanContinuiteActivite.query
        viewing_client_id = session.get('viewing_client_id')
        if viewing_client_id:
            query = query.filter_by(client_id=viewing_client_id)
    else:
        query = PlanContinuiteActivite.query.filter_by(client_id=current_user.client_id)
    
    if not show_archived:
        query = query.filter_by(is_archived=False)
    
    if statut:
        query = query.filter_by(statut=statut)
    
    plans = query.order_by(PlanContinuiteActivite.created_at.desc()).all()
    
    # Statistiques
    tous_plans = query.filter_by(is_archived=False).all() if not show_archived else query.all()
    
    stats = {
        'total': len(tous_plans),
        'en_redaction': len([p for p in tous_plans if p.statut == 'en_redaction']),
        'valide': len([p for p in tous_plans if p.statut == 'valide']),
        'obsolète': len([p for p in tous_plans if p.statut == 'obsolète']),
        'maturite_moyenne': round(sum(p.niveau_maturite for p in tous_plans) / len(tous_plans), 1) if tous_plans else 0,
        'archives': PlanContinuiteActivite.query.filter_by(is_archived=True).count()
    }
    
    # Données pour filtres
    poles = get_client_filter(Pole).filter_by(is_archived=False).order_by(Pole.nom).all()
    directions = get_client_filter(Direction).filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
    
    return render_template('pca/liste_plans.html',
                         plans=plans,
                         stats=stats,
                         poles=poles,
                         directions=directions,
                         show_archived=show_archived,
                         now=datetime.now())


@app.route('/pca/plan/nouveau', methods=['GET', 'POST'])
@login_required
def nouveau_plan_pca():
    """Créer un nouveau plan PCA"""
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    form = PlanContinuiteActiviteForm()
    
    # Remplir les choix multi-tenant
    if current_user.role == 'super_admin':
        poles = Pole.query.filter_by(is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(is_active=True).order_by(User.username).all()
    else:
        poles = Pole.query.filter_by(client_id=current_user.client_id, is_archived=False).order_by(Pole.nom).all()
        directions = Direction.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Direction.nom).all()
        services = Service.query.filter_by(client_id=current_user.client_id, is_archived=False, is_active=True).order_by(Service.nom).all()
        users = User.query.filter_by(client_id=current_user.client_id, is_active=True).order_by(User.username).all()
    
    form.pole_id.choices = [(0, '-- Sélectionner --')] + [(p.id, p.nom) for p in poles]
    form.direction_id.choices = [(0, '-- Sélectionner --')] + [(d.id, d.nom) for d in directions]
    form.service_id.choices = [(0, '-- Sélectionner --')] + [(s.id, s.nom) for s in services]
    form.responsable_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    form.redacteur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    form.valideur_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    
    if form.validate_on_submit():
        try:
            # Générer référence
            annee = datetime.now().year
            dernier = PlanContinuiteActivite.query.filter(
                PlanContinuiteActivite.reference.like(f'PCA-{annee}-%')
            ).order_by(PlanContinuiteActivite.reference.desc()).first()
            
            if dernier:
                num = int(dernier.reference.split('-')[-1]) + 1
            else:
                num = 1
            
            reference = f"PCA-{annee}-{num:03d}"
            
            # Traiter les champs JSON
            processus_critiques = [p.strip() for p in form.processus_critiques.data.split('\n') if p.strip()] if form.processus_critiques.data else []
            strategies = [s.strip() for s in form.strategies.data.split('\n') if s.strip()] if form.strategies.data else []
            sites_secours = [s.strip() for s in form.sites_secours.data.split('\n') if s.strip()] if form.sites_secours.data else []
            ressources_critiques = [r.strip() for r in form.ressources_critiques.data.split('\n') if r.strip()] if form.ressources_critiques.data else []
            
            plan = PlanContinuiteActivite(
                reference=reference,
                titre=form.titre.data,
                description=form.description.data,
                version=form.version.data,
                date_validite=form.date_validite.data,
                date_dernier_test=form.date_dernier_test.data,
                date_prochain_test=form.date_prochain_test.data,
                processus_critiques=processus_critiques,
                bia_realisee=form.bia_realisee.data,
                bia_date=form.bia_date.data,
                delai_arret_max=form.delai_arret_max.data,
                perte_donnees_max=form.perte_donnees_max.data,
                strategies=strategies,
                sites_secours=sites_secours,
                procedures_urgence=form.procedures_urgence.data,
                procedures_reprise=form.procedures_reprise.data,
                procedures_retour_normal=form.procedures_retour_normal.data,
                ressources_critiques=ressources_critiques,
                duree_critique=form.duree_critique.data,
                statut=form.statut.data,
                niveau_maturite=form.niveau_maturite.data,
                responsable_id=form.responsable_id.data if form.responsable_id.data != 0 else None,
                redacteur_id=form.redacteur_id.data if form.redacteur_id.data != 0 else None,
                valideur_id=form.valideur_id.data if form.valideur_id.data != 0 else None,
                created_by=current_user.id,
                client_id=current_user.client_id
            )
            
            # Assigner l'organisation
            if form.type_organisation.data == 'pole' and form.pole_id.data:
                plan.pole_id = form.pole_id.data
            elif form.type_organisation.data == 'direction' and form.direction_id.data:
                plan.direction_id = form.direction_id.data
            elif form.type_organisation.data == 'service' and form.service_id.data:
                plan.service_id = form.service_id.data
            
            db.session.add(plan)
            db.session.commit()
            
            flash(f'✅ Plan PCA "{reference}" créé avec succès.', 'success')
            return redirect(url_for('detail_plan_pca', plan_id=plan.id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('pca/form_plan.html', form=form, action='Créer')


@app.route('/pca/plan/<int:plan_id>')
@login_required
def detail_plan_pca(plan_id):
    """Détail d'un plan PCA"""
    
    if current_user.role == 'super_admin':
        plan = PlanContinuiteActivite.query.get_or_404(plan_id)
    else:
        plan = PlanContinuiteActivite.query.filter_by(id=plan_id, client_id=current_user.client_id).first_or_404()
    
    # Organisation
    organisation = None
    if plan.pole_id:
        organisation = Pole.query.get(plan.pole_id)
    elif plan.direction_id:
        organisation = Direction.query.get(plan.direction_id)
    elif plan.service_id:
        organisation = Service.query.get(plan.service_id)
    
    # Actions
    actions = ActionPCA.query.filter_by(plan_id=plan_id, client_id=current_user.client_id).order_by(ActionPCA.priorite).all()
    
    # Exercices
    exercices = ExercicePCA.query.filter_by(plan_id=plan_id, client_id=current_user.client_id).order_by(ExercicePCA.date_exercice.desc()).all()
    
    # Statistiques des actions
    stats_actions = {
        'total': len(actions),
        'terminees': len([a for a in actions if a.statut == 'termine']),
        'en_cours': len([a for a in actions if a.statut == 'en_cours']),
        'a_faire': len([a for a in actions if a.statut == 'a_faire']),
        'avancement_moyen': sum(a.pourcentage_realisation for a in actions) / len(actions) if actions else 0
    }
    
    return render_template('pca/detail_plan.html',
                         plan=plan,
                         organisation=organisation,
                         actions=actions,
                         exercices=exercices,
                         stats_actions=stats_actions,
                         now=datetime.now())


