@app.route('/pca/plan/<int:plan_id>/action/nouvelle', methods=['GET', 'POST'])
@login_required
def nouvelle_action_pca(plan_id):
    """Créer une nouvelle action PCA"""
    
    plan = get_client_object_or_404(PlanContinuiteActivite, plan_id)
    form = ActionPCAForm()
    
    # Remplir les choix
    users = get_client_filter(User).filter_by(is_active=True).order_by(User.username).all()
    form.responsable_id.choices = [(0, '-- Non assigné --')] + [(u.id, u.username) for u in users]
    
    # PRÉ-REMPLISSAGE DEPUIS L'IA
    if request.method == 'GET':
        intitule_ia = request.args.get('intitule', '')
        description_ia = request.args.get('description', '')
        phase_ia = request.args.get('phase', '')
        priorite_ia = request.args.get('priorite', '')
        
        if intitule_ia:
            form.intitule.data = intitule_ia
            flash('💡 Action pré-remplie avec une suggestion IA.', 'info')
        if description_ia:
            form.description.data = description_ia
        if phase_ia and phase_ia in ['preparation', 'crise', 'reprise', 'retour', 'test']:
            form.phase.data = phase_ia
        if priorite_ia and priorite_ia in ['haute', 'moyenne', 'basse']:
            form.priorite.data = priorite_ia
        
        # Générer référence
        dernier = ActionPCA.query.filter_by(plan_id=plan_id).order_by(ActionPCA.id.desc()).first()
        num = 1
        if dernier:
            try:
                num = int(dernier.reference.split('-')[-1]) + 1
            except:
                num = 1
        form.reference.data = f"PCA-ACT-{plan_id}-{num:03d}"
    
    if form.validate_on_submit():
        try:
            action = ActionPCA(
                plan_id=plan_id,
                reference=form.reference.data,
                intitule=form.intitule.data,
                description=form.description.data,
                phase=form.phase.data,
                priorite=form.priorite.data,
                delai_execution=form.delai_execution.data,
                responsable_id=form.responsable_id.data if form.responsable_id.data != 0 else None,
                date_debut=form.date_debut.data,
                date_fin_prevue=form.date_fin_prevue.data,
                statut=form.statut.data,
                pourcentage_realisation=form.pourcentage_realisation.data,
                commentaire=form.commentaire.data,
                created_by=current_user.id,
                client_id=current_user.client_id
            )
            db.session.add(action)
            db.session.commit()
            flash(f'✅ Action "{action.reference}" créée avec succès.', 'success')
            return redirect(url_for('detail_plan_pca', plan_id=plan_id))
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('pca/form_action.html', form=form, plan=plan, action='Créer')

