@app.route('/pca/exercice/<int:exercice_id>/modifier', methods=['GET', 'POST'])
@login_required
def modifier_exercice_pca(exercice_id):
    """Modifier un exercice PCA"""
    
    if current_user.role == 'super_admin':
        exercice = ExercicePCA.query.get_or_404(exercice_id)
    else:
        exercice = ExercicePCA.query.filter_by(id=exercice_id, client_id=current_user.client_id).first_or_404()
    
    if not current_user.has_permission('can_manage_audit'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('detail_plan_pca', plan_id=exercice.plan_id))
    
    plan = exercice.plan
    form = ExercicePCAForm(obj=exercice)
    
    if form.validate_on_submit():
        try:
            exercice.nom = form.nom.data
            exercice.description = form.description.data
            exercice.type_exercice = form.type_exercice.data
            exercice.date_exercice = form.date_exercice.data
            exercice.duree = form.duree.data
            exercice.scenario = form.scenario.data
            
            # Traiter objectifs
            if form.objectifs.data:
                objectifs = [o.strip() for o in form.objectifs.data.split('\n') if o.strip()]
                exercice.objectifs = objectifs
            else:
                exercice.objectifs = []
            
            exercice.updated_at = datetime.utcnow()
            db.session.commit()
            
            flash(f'✅ Exercice "{exercice.reference}" mis à jour.', 'success')
            return redirect(url_for('detail_plan_pca', plan_id=plan.id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('pca/form_exercice.html', 
                         form=form, 
                         plan=plan, 
                         exercice=exercice, 
                         action='Modifier')


@app.route('/pca/exercice/<int:exercice_id>/supprimer', methods=['POST'])
@login_required
def supprimer_exercice_pca(exercice_id):
    """Supprimer un exercice PCA"""
    
    if current_user.role == 'super_admin':
        exercice = ExercicePCA.query.get_or_404(exercice_id)
    else:
        exercice = ExercicePCA.query.filter_by(id=exercice_id, client_id=current_user.client_id).first_or_404()
    
    if not current_user.has_permission('can_manage_audit'):
        return jsonify({'success': False, 'error': 'Accès non autorisé'}), 403
    
    try:
        plan_id = exercice.plan_id
        db.session.delete(exercice)
        db.session.commit()
        
        flash('✅ Exercice supprimé avec succès.', 'success')
        return redirect(url_for('detail_plan_pca', plan_id=plan_id))
        
    except Exception as e:
        db.session.rollback()
        flash(f'Erreur: {str(e)}', 'error')
        return redirect(url_for('detail_plan_pca', plan_id=exercice.plan_id))

