@app.route('/api/pca/suggestions/actions/<int:plan_id>', methods=['GET'])
@login_required
def api_pca_suggestions_actions(plan_id):
    """API pour suggérer des actions pour un plan PCA"""
    try:
        plan = get_client_object_or_404(PlanContinuiteActivite, plan_id)
        
        plan_data = {
            'bia_realisee': plan.bia_realisee,
            'delai_arret_max': plan.delai_arret_max,
            'perte_donnees_max': plan.perte_donnees_max,
            'processus_critiques': plan.processus_critiques or [],
            'strategies': plan.strategies or [],
            'sites_secours': plan.sites_secours or [],
            'procedures_urgence': plan.procedures_urgence,
            'procedures_reprise': plan.procedures_reprise,
            'procedures_retour_normal': plan.procedures_retour_normal,
            'ressources_critiques': plan.ressources_critiques or [],
            'date_prochain_test': plan.date_prochain_test,
            'niveau_maturite': plan.niveau_maturite
        }
        
        # Récupérer les actions existantes
        existing_actions = ActionPCA.query.filter_by(plan_id=plan_id).all()
        
        suggestions = IAPcaService.suggerer_actions_specifiques(plan_data, existing_actions)
        
        return jsonify({
            'success': True,
            'suggestions': suggestions,
            'count': len(suggestions)
        })
        
    except Exception as e:
        current_app.logger.error(f"Erreur suggestions actions PCA: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

