# MODULE QUALITÉ - ROUTES POUR LES PLANS QUALITÉ FONCTION
# ============================================================================
@app.route('/qualite/plans')
@login_required
def liste_plans_qualite():
    """Liste des plans qualité avec multi-tenant"""
    
    # Vérification des permissions
    if not current_user.has_permission('can_manage_audit') and not current_user.has_permission('can_manage_quality'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('dashboard'))
    
    # Récupération des filtres
    statut = request.args.get('statut', 'tous')
    type_fonction = request.args.get('type_fonction', '')
    fonction_id = request.args.get('fonction_id', '')
    
    # ============================================
    # CORRECTION ICI : Accepter 'on' comme valeur vraie
    # ============================================
    show_archived_value = request.args.get('show_archived', 'false')
    show_archived = show_archived_value in ['true', 'on', '1', 'True', True]
    
    print(f"🔍 [DEBUG] show_archived_value: {show_archived_value}")
    print(f"🔍 [DEBUG] show_archived: {show_archived}")
    
    # ===== REQUÊTE DE BASE AVEC MULTI-TENANT =====
    query = get_client_filter(PlanQualiteFonction)
    
    # ===== FILTRE ARCHIVAGE CORRIGÉ =====
    if show_archived:
        # Mode "Afficher les archivés" : on ne prend QUE les archivés
        query = query.filter(PlanQualiteFonction.is_archived == True)
        print(f"   📦 MODE ARCHIVES: is_archived = True")
    else:
        # Mode normal : on exclut les archivés
        query = query.filter(PlanQualiteFonction.is_archived == False)
        print(f"   📋 MODE NORMAL: is_archived = False")
        
        # Filtre statut uniquement en mode normal
        if statut != 'tous':
            query = query.filter(PlanQualiteFonction.statut == statut)
            print(f"   🏷️ Filtre statut: {statut}")
    
    # ===== FILTRE PAR FONCTION =====
    if type_fonction == 'pole' and fonction_id and fonction_id.isdigit():
        query = query.filter(PlanQualiteFonction.pole_id == int(fonction_id))
        print(f"   🏢 Filtre pôle: {fonction_id}")
    elif type_fonction == 'direction' and fonction_id and fonction_id.isdigit():
        query = query.filter(PlanQualiteFonction.direction_id == int(fonction_id))
        print(f"   🏛️ Filtre direction: {fonction_id}")
    elif type_fonction == 'service' and fonction_id and fonction_id.isdigit():
        query = query.filter(PlanQualiteFonction.service_id == int(fonction_id))
        print(f"   👥 Filtre service: {fonction_id}")
    
    plans = query.order_by(PlanQualiteFonction.created_at.desc()).all()
    print(f"   📊 {len(plans)} plan(s) trouvé(s)")
    
    # ===== STATISTIQUES MULTI-TENANT =====
    tous_plans = get_client_filter(PlanQualiteFonction).all()
    
    stats = {
        'total': len(tous_plans),
        'actifs': len([p for p in tous_plans if not p.is_archived and p.statut == 'actif']),
        'brouillons': len([p for p in tous_plans if not p.is_archived and p.statut == 'brouillon']),
        'clos': len([p for p in tous_plans if not p.is_archived and p.statut == 'clos']),
        'annules': len([p for p in tous_plans if not p.is_archived and p.statut == 'annule']),
        'archives': len([p for p in tous_plans if p.is_archived])
    }
    
    # ===== DONNÉES POUR LES FILTRES (multi-tenant) =====
    poles = get_client_filter(Pole).filter_by(is_archived=False).order_by(Pole.nom).all()
    directions = get_client_filter(Direction).filter_by(is_archived=False, is_active=True).order_by(Direction.nom).all()
    services = get_client_filter(Service).filter_by(is_archived=False, is_active=True).order_by(Service.nom).all()
    
    return render_template('qualite/liste_plans.html',
                         plans=plans,
                         stats=stats,
                         poles=poles,
                         directions=directions,
                         services=services,
                         current_filters={
                             'statut': statut,
                             'type_fonction': type_fonction,
                             'fonction_id': fonction_id
                         },
                         show_archived=show_archived,
                         now=datetime.utcnow())

@app.route('/qualite/alertes/revues')
@login_required
def alertes_revues_qualite():
    """Liste des plans nécessitant une revue prochainement"""
    
    today = datetime.now().date()
    threshold_30 = today + timedelta(days=30)
    
    # Plans avec revue dans les 30 jours ou en retard
    plans_a_revoir = get_client_filter(PlanQualiteFonction)\
        .filter(PlanQualiteFonction.is_archived == False)\
        .filter(PlanQualiteFonction.date_prochaine_revue.isnot(None))\
        .filter(PlanQualiteFonction.date_prochaine_revue <= threshold_30)\
        .order_by(PlanQualiteFonction.date_prochaine_revue.asc())\
        .all()
    
    # Séparer les urgents (en retard) des proches
    urgents = [p for p in plans_a_revoir if p.date_prochaine_revue < today]
    proches = [p for p in plans_a_revoir if p.date_prochaine_revue >= today]
    
    return render_template('qualite/alertes_revues.html',
                         urgents=urgents,
                         proches=proches,
                         today=today)

