@app.route('/api/qualite/analyser-plan/<int:plan_id>', methods=['GET'])
@login_required
def api_analyser_plan_qualite(plan_id):
    """API pour analyser un plan qualité et retourner des recommandations."""
    # Vérification d'accès multi-tenant
    plan = get_client_object_or_404(PlanQualiteFonction, plan_id)
    if not plan:
        return jsonify({'success': False, 'error': 'Plan non trouvé'}), 404

    recommendations = IAQualiteService.analyser_plan_qualite(plan_id)
    if recommendations:
        return jsonify({'success': True, 'recommendations': recommendations})
    return jsonify({'success': False, 'error': 'Analyse IA échouée'}), 500

@app.route('/api/qualite/generer-objectifs-smart', methods=['POST'])
@login_required
def api_generer_objectifs_smart():
    """API pour générer des objectifs SMART pour une action."""
    data = request.get_json()
    description = data.get('description', '')
    if not description:
        return jsonify({'success': False, 'error': 'Description manquante'}), 400

    objectifs = IAQualiteService.generer_objectifs_smart(description)
    return jsonify({'success': True, 'objectifs': objectifs})

