@app.route('/qualite/plan/<int:plan_id>/action/nouvelle', methods=['GET', 'POST'])
@login_required
def nouvelle_action_amelioration(plan_id):
    """Créer une nouvelle action d'amélioration pour un plan qualité"""
    
    plan = get_client_object_or_404(PlanQualiteFonction, plan_id)
    
    if not current_user.has_permission('can_manage_audit') and not current_user.has_permission('can_manage_quality'):
        flash('Accès non autorisé.', 'error')
        return redirect(url_for('detail_plan_qualite', plan_id=plan_id))
    
    form = ActionAmeliorationQualiteForm()
    
    # Remplir les choix des responsables
    users = get_client_filter(User).filter_by(is_active=True).order_by(User.username).all()
    form.responsable_id.choices = [(0, 'Non assigné')] + [(u.id, u.username) for u in users]
    
    # ============================================
    # PRÉ-REMPLISSAGE À PARTIR DES PARAMÈTRES GET (IA)
    # ============================================
    if request.method == 'GET':
        # Récupérer les paramètres de l'URL (envoyés par l'IA)
        intitule_ia = request.args.get('intitule', '')
        description_ia = request.args.get('description', '')
        priorite_ia = request.args.get('priorite', '')
        
        if intitule_ia:
            form.intitule.data = intitule_ia
            flash('💡 Formulaire pré-rempli avec une suggestion IA.', 'info')
        
        if description_ia:
            form.description.data = description_ia
        
        if priorite_ia and priorite_ia in ['haute', 'moyenne', 'basse']:
            form.priorite.data = priorite_ia
        
        # Générer une référence automatique
        dernier_action = ActionAmeliorationQualite.query\
            .filter_by(plan_qualite_id=plan_id)\
            .order_by(ActionAmeliorationQualite.id.desc())\
            .first()
        
        if dernier_action:
            try:
                num = int(dernier_action.reference.split('-')[-1]) + 1
            except:
                num = 1
        else:
            num = 1
        
        form.reference.data = f"AQ-{plan.reference}-{num:03d}"
        
        # Dates par défaut
        if not form.date_echeance.data:
            form.date_echeance.data = datetime.now().date() + timedelta(days=30)
    
    if form.validate_on_submit():
        try:
            action = ActionAmeliorationQualite(
                plan_qualite_id=plan_id,
                reference=form.reference.data,
                intitule=form.intitule.data,
                description=form.description.data,
                date_echeance=form.date_echeance.data,
                priorite=form.priorite.data,
                statut=form.statut.data,
                pourcentage_realisation=form.pourcentage_realisation.data,
                commentaire_realisation=form.commentaire_realisation.data,
                responsable_id=form.responsable_id.data if form.responsable_id.data != 0 else None,
                created_by=current_user.id,
                client_id=current_user.client_id
            )
            
            db.session.add(action)
            db.session.commit()
            
            # Journaliser l'action
            log_activity(current_user.id, 'creation_action_amelioration',
                        f"Création action {action.reference} pour plan {plan.reference}",
                        'action_qualite', action.id)
            
            flash(f'✅ Action "{action.reference}" créée avec succès.', 'success')
            return redirect(url_for('detail_plan_qualite', plan_id=plan_id))
            
        except Exception as e:
            db.session.rollback()
            flash(f'Erreur: {str(e)}', 'error')
    
    return render_template('qualite/form_action.html', 
                         form=form, 
                         plan=plan,
                         action='Créer')

