@app.route('/qualite/action/<int:action_id>/changer-statut', methods=['POST'])
@login_required
def changer_statut_action_qualite(action_id):
    """API: Changer rapidement le statut d'une action (pour AJAX)"""
    action = get_client_object_or_404(ActionAmeliorationQualite, action_id)
    
    if not current_user.has_permission('can_manage_audit'):
        return jsonify({'success': False, 'error': 'Permission non autorisée'}), 403
    
    data = request.get_json()
    nouveau_statut = data.get('statut')
    
    if nouveau_statut not in ['a_faire', 'en_cours', 'terminee', 'bloquee']:
        return jsonify({'success': False, 'error': 'Statut invalide'}), 400
    
    try:
        ancien_statut = action.statut
        action.statut = nouveau_statut
        action.updated_at = datetime.utcnow()
        
        # Si terminée, forcer l'avancement à 100%
        if nouveau_statut == 'terminee' and action.pourcentage_realisation < 100:
            action.pourcentage_realisation = 100
        
        db.session.commit()
        
        return jsonify({
            'success': True,
            'message': f'Statut changé de {ancien_statut} à {nouveau_statut}',
            'statut': nouveau_statut,
            'pourcentage': action.pourcentage_realisation
        })
        
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500

