@app.route('/api/audit/<int:audit_id>/constatations')
@csrf.exempt
@login_required
def api_constatations_audit(audit_id):
    """API pour récupérer les constatations d'un audit"""
    audit = Audit.query.get_or_404(audit_id)
    
    # Vérifier l'accès multi-tenant
    if not check_client_access(audit):
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    constatations = []
    for constat in audit.constatations:
        # Vérifier que la constatation appartient au bon client
        if constat.client_id == current_user.client_id:
            constatations.append({
                'id': constat.id,
                'reference': constat.reference,
                'description': constat.description,
                'type': constat.type_constatation,
                'gravite': constat.gravite,
                'statut': constat.statut,
                'cause_racine': constat.cause_racine,
                'conclusion': constat.conclusion,
                'commentaires': constat.commentaires,
                'recommandations_immediates': constat.recommandations_immediates,
                'processus_concerne': constat.processus_concerne
            })
    
    return jsonify(constatations)

@app.route('/api/risques/actifs')
@login_required
def api_risques_actifs():
    """API pour récupérer les risques actifs"""
    risques = Risque.query.filter_by(is_archived=False).all()
    
    risques_data = []
    for risque in risques:
        risques_data.append({
            'id': risque.id,
            'reference': risque.reference,
            'intitule': risque.intitule,
            'categorie': risque.categorie
        })
    
    return jsonify(risques_data)

