# CORRECTION DE LA ROUTE PLANS_ACTION_AUDIT (alias pour compatibilité)
# ============================================================================
@app.route('/api/plan-action/<int:plan_id>/audits', methods=['GET', 'POST', 'PUT'])
@login_required
def api_plan_audits(plan_id):
    """API pour gérer les audits liés à un plan"""
    plan = PlanAction.query.get_or_404(plan_id)
    
    if not check_client_access(plan):
        return jsonify({'error': 'Accès non autorisé'}), 403
    
    # GET: Récupérer les audits disponibles
    if request.method == 'GET':
        # Récupérer tous les audits du client
        audits = get_client_filter(Audit).filter_by(is_archived=False).order_by(Audit.reference).all()
        
        # IDs déjà liés
        ids_lies = [a.id for a in plan.audits]
        
        return jsonify({
            'success': True,
            'audits': [{
                'id': a.id,
                'reference': a.reference,
                'titre': a.titre,
                'type_audit': a.type_audit,
                'statut': a.statut,
                'est_lie': a.id in ids_lies
            } for a in audits]
        })
    
    # POST/PUT: Mettre à jour les liens
    elif request.method in ['POST', 'PUT']:
        data = request.get_json()
        audit_ids = data.get('audit_ids', [])
        
        try:
            # Vider les liens existants
            plan.audits = []
            
            # Ajouter les nouveaux
            for audit_id in audit_ids:
                audit = Audit.query.get(audit_id)
                if audit and check_client_access(audit):
                    plan.audits.append(audit)
            
            db.session.commit()
            
            return jsonify({
                'success': True,
                'message': f'Plan lié à {len(audit_ids)} audit(s)'
            })
            
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500




