# Ajoutez cette fonction après toutes vos routes
@app.after_request
def after_request(response):
    """Ajouter les headers CORS à toutes les réponses"""
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    response.headers.add('Access-Control-Allow-Methods', 'GET,PUT,POST,DELETE,OPTIONS')
    return response
def configurer_hooks_multi_tenant():
    """
    Configure tous les hooks nécessaires pour le multi-tenant
    Doit être appelée APRÈS la création de tous les modèles
    """
    try:
        print("🔧 Configuration des hooks multi-tenant...")
        
        # Liste des modèles à hooker (sécurisée)
        models_to_hook = []
        
        # Récupérer dynamiquement les modèles depuis SQLAlchemy
        from sqlalchemy.inspection import inspect
        import sys
        
        # Chercher tous les modèles définis dans le scope
        for name, obj in list(sys.modules[__name__].__dict__.items()):
            try:
                if hasattr(obj, '__tablename__') and hasattr(obj, '__table__'):
                    # C'est un modèle SQLAlchemy
                    models_to_hook.append(obj)
                    print(f"  ✓ Modèle détecté: {obj.__name__}")
            except:
                continue
        
        # Liste explicite en backup
        if not models_to_hook:
            # Noms des modèles à chercher
            model_names = [
                'Cartographie', 'Risque', 'EvaluationRisque', 'KRI', 'MesureKRI',
                'Processus', 'EtapeProcessus', 'SousEtapeProcessus', 'Audit',
                'Constatation', 'Recommandation', 'PlanAction', 'EtapePlanAction',
                'VeilleReglementaire', 'ActionConformite', 'ProcessusActivite',
                'Questionnaire', 'Question', 'CampagneEvaluation'
            ]
            
            # Chercher chaque modèle
            for name in model_names:
                if name in globals():
                    models_to_hook.append(globals()[name])
                    print(f"  ✓ Modèle trouvé: {name}")
        
        # Appliquer les hooks
        hook_count = 0
        for model in models_to_hook:
            try:
                # Vérifier que le modèle a besoin du hook
                if hasattr(model, 'client_id') or hasattr(model, 'created_by'):
                    event.listen(model, 'before_insert', apply_client_id_before_insert)
                    hook_count += 1
                    print(f"  ✓ Hook appliqué à: {model.__name__}")
            except Exception as e:
                print(f"  ⚠️ Erreur hook {model}: {e}")
        
        print(f"✅ {hook_count} hooks multi-tenant configurés")
        
    except Exception as e:
        print(f"❌ Erreur configuration hooks: {e}")
        import traceback
        traceback.print_exc()

# Appeler la fonction au démarrage
with app.app_context():
    configurer_hooks_multi_tenant()

