# Dans app.py - ROUTE POUR LE FORMULAIRE DE CONTACT
import hashlib
from datetime import datetime

@app.route('/api/contact', methods=['POST'])
@csrf.exempt 
def api_contact():
    """API pour traiter les formulaires de contact"""
    try:
        # Récupérer les données (JSON ou form-data)
        if request.is_json:
            data = request.get_json()
        else:
            data = request.form
        
        # Extraire les champs
        nom_complet = data.get('nom_complet', '').strip()
        email = data.get('email', '').strip().lower()
        societe = data.get('societe', '').strip()
        telephone = data.get('telephone', '').strip()
        sujet = data.get('sujet', '').strip()
        message = data.get('message', '').strip()
        
        # Validation
        errors = []
        if not nom_complet:
            errors.append("Le nom complet est requis")
        if not email or '@' not in email:
            errors.append("Un email valide est requis")
        if not message:
            errors.append("Le message est requis")
        
        if errors:
            return jsonify({
                'success': False,
                'errors': errors
            }), 400
        
        # Générer une référence unique
        timestamp = datetime.now().strftime('%Y%m%d%H%M%S')
        hash_input = f"{email}{timestamp}{nom_complet}"
        reference = f"DEMO-{hashlib.md5(hash_input.encode()).hexdigest()[:8].upper()}"
        
        # Envoyer les emails via Hostinger
        email_sent = email_service.send_contact_confirmation(
            nom_complet=nom_complet,
            email=email,
            societe=societe,
            telephone=telephone,
            sujet=sujet or "Demande de démonstration",
            message=message,
            reference=reference
        )
        
        # Sauvegarder dans la base de données (optionnel)
        try:
            # Créer la table si elle n'existe pas
            from models import DemandeContact
            
            demande = DemandeContact(
                nom_complet=nom_complet,
                email=email,
                societe=societe,
                telephone=telephone,
                sujet=sujet,
                message=message,
                reference=reference,
                ip_address=request.remote_addr,
                user_agent=request.headers.get('User-Agent', 'Inconnu')
            )
            db.session.add(demande)
            db.session.commit()
            logger.info(f"✅ Demande sauvegardée en base: {reference}")
        except Exception as e:
            logger.warning(f"⚠️ Impossible de sauvegarder en base: {e}")
            # Fallback: fichier log
            with open('demandes_contact.log', 'a', encoding='utf-8') as f:
                f.write(f"{datetime.now().isoformat()}|{reference}|{nom_complet}|{email}|{societe}|{sujet}\n")
        
        # Journaliser l'activité
        try:
            from utils import log_activity
            log_activity(
                utilisateur_id=current_user.id if current_user.is_authenticated else None,
                action='contact_form',
                details=f"Demande de contact - {reference}",
                entite_type='contact',
                entite_id=None
            )
        except:
            pass
        
        return jsonify({
            'success': True,
            'message': 'Votre demande a été envoyée avec succès ! Notre équipe vous contactera dans les plus brefs délais.',
            'reference': reference,
            'email_sent': email_sent
        })
        
    except Exception as e:
        logger.error(f"❌ Erreur formulaire contact: {e}")
        import traceback
        traceback.print_exc()
        
        return jsonify({
            'success': False,
            'message': 'Une erreur est survenue lors de l\'envoi. Veuillez réessayer ou nous contacter directement.'
        }), 500


