# Page de login - redirection vers auth/login_fullscreen
@app.route('/login', methods=['GET', 'POST'])
@csrf.exempt
def login():
    """Page de connexion - Redirection vers login fullscreen"""
    
    # Si déjà connecté, rediriger vers dashboard
