# Page de login fullscreen (votre page de login existante)
@app.route('/auth/login_fullscreen', methods=['GET', 'POST'])
@csrf.exempt
def login_fullscreen():
    """Page de connexion fullscreen"""
    
    # Si déjà connecté, rediriger vers dashboard
    if current_user.is_authenticated:
        return redirect(url_for('dashboard'))
    
    form = LoginForm()
    
    if request.method == 'POST' and form.validate_on_submit():
        user = User.query.filter_by(username=form.username.data).first()
        
        if user and user.check_password(form.password.data):
            if not user.is_active:
                flash('Ce compte est désactivé', 'error')
                return render_template('auth/login_fullscreen.html', form=form)
            
            login_user(user, remember=form.remember_me.data)
            next_page = request.args.get('next')
            
            # Journaliser la connexion
            log_activity(user.id, 'connexion', f"Utilisateur {user.username} connecté")
            
            flash(f'Bienvenue {user.username}!', 'success')
            return redirect(next_page or url_for('dashboard'))
        else:
            flash('Nom d\'utilisateur ou mot de passe incorrect', 'error')
    
    return render_template('auth/login_fullscreen.html', form=form)

@app.route('/reset-password/<token>', methods=['GET', 'POST'])
def reset_password(token):
    """Page de réinitialisation de mot de passe avec token"""
    
    if current_user.is_authenticated:
        return redirect(url_for('dashboard'))
    
    # Trouver l'utilisateur avec ce token
    user = User.query.filter_by(reset_password_token=token).first()
    
    # Vérifier la validité du token
    if not user or not user.verify_reset_token(token):
        flash('❌ Le lien de réinitialisation est invalide ou a expiré.', 'error')
        return redirect(url_for('forgot_password'))
    
    class ResetPasswordForm(FlaskForm):
        password = PasswordField('Nouveau mot de passe', validators=[
            DataRequired(message='Le mot de passe est requis'),
            Length(min=8, message='Le mot de passe doit contenir au moins 8 caractères')
        ])
        confirm_password = PasswordField('Confirmer le mot de passe', validators=[
            DataRequired(message='Veuillez confirmer le mot de passe'),
            EqualTo('password', message='Les mots de passe doivent correspondre')
        ])
        submit = SubmitField('Réinitialiser mon mot de passe')
    
    form = ResetPasswordForm()
    
    if form.validate_on_submit():
        try:
            # Changer le mot de passe
            user.set_password(form.password.data)
            
            # Invalider le token
            user.reset_password_token = None
            user.reset_password_expires = None
            
            db.session.commit()
            
            flash('✅ Votre mot de passe a été réinitialisé avec succès.', 'success')
            return redirect(url_for('login_fullscreen'))
            
        except Exception as e:
            flash(str(e), 'error')
    
    return render_template('auth/reset_password.html', form=form, token=token)

@app.route('/forgot-password', methods=['GET', 'POST'])
def forgot_password():
    """Page de demande de réinitialisation de mot de passe"""
    
    if current_user.is_authenticated:
        return redirect(url_for('dashboard'))
    
    class ForgotPasswordForm(FlaskForm):
        email = StringField('Email', validators=[
            DataRequired(message='L\'email est requis'),
            Email(message='Format d\'email invalide')
        ])
        submit = SubmitField('Envoyer le lien de réinitialisation')
    
    form = ForgotPasswordForm()
    
    if form.validate_on_submit():
        email = form.email.data
        user = User.query.filter_by(email=email).first()
        
        # ✅ MÊME MESSAGE QUE L'UTILISATEUR EXISTE OU NON (SÉCURITÉ)
        flash('📧 Si un compte existe avec cet email, vous recevrez un lien de réinitialisation sous quelques minutes.', 'info')
        
        # Journalisation (côté serveur uniquement)
        if user:
            print(f"✅ Demande de réinit pour compte existant: {email}")
            
            # Générer un token unique
            token = user.generate_reset_token()
            reset_url = url_for('reset_password', token=token, _external=True)
            
            # Envoyer l'email
            send_password_reset_email(
                to_email=user.email,
                reset_url=reset_url,
                username=user.username
            )
            
            # Journaliser l'action
            log_security_event('password_reset_requested', 
                              {'user_id': user.id, 'email': user.email})
        else:
            print(f"⚠️ Demande de réinit pour email inconnu: {email}")
            log_security_event('password_reset_unknown_email', 
                              {'email': email, 'ip': request.remote_addr})
        
        # ✅ REDIRIGER VERS LA MÊME PAGE (pas de distinction)
        return redirect(url_for('forgot_password'))
    
    return render_template('auth/forgot_password.html', form=form)

