@app.before_request
def check_password_expiry():
    """
    Vérifie si le mot de passe de l'utilisateur a expiré
    et le redirige vers la page de changement forcé
    """
    if current_user.is_authenticated:
        # Ignorer certaines routes
        exempt_routes = [
            'force_change_password', 'logout', 'static',
            'change_password', 'reset_password', 'forgot_password'
        ]
        
        if request.endpoint in exempt_routes:
            return
        
        # Vérifier si le mot de passe a expiré ou si changement forcé
        if current_user.force_password_change or current_user.is_password_expired():
            flash('Votre mot de passe a expiré. Veuillez le changer pour des raisons de sécurité.', 'warning')
            return redirect(url_for('force_change_password'))


def send_password_reset_email(to_email, reset_url, username):
    """
    Envoie un email de réinitialisation de mot de passe via Hostinger
    """
    subject = "🔐 Réinitialisation de votre mot de passe - Egalyx Control"
    
    # Version texte simple
    body = f"""
    Bonjour {username},
    
    Vous avez demandé la réinitialisation de votre mot de passe.
    
    Cliquez sur le lien ci-dessous pour choisir un nouveau mot de passe :
    {reset_url}
    
    Ce lien est valable 1 heure.
    
    Si vous n'êtes pas à l'origine de cette demande, ignorez cet email.
    
    Cordialement,
    L'équipe Egalyx Control
    """
    
    # Version HTML (plus jolie)
    html_body = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="UTF-8">
        <style>
            body {{ font-family: Arial, sans-serif; line-height: 1.6; color: #333; }}
            .container {{ max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #e0e0e0; border-radius: 5px; }}
            .header {{ background: linear-gradient(135deg, #0A1929 0%, #1A3C6B 100%); color: white; padding: 20px; text-align: center; border-radius: 5px 5px 0 0; }}
            .content {{ padding: 20px; }}
            .button {{ display: inline-block; padding: 12px 24px; background: #0066CC; color: white; text-decoration: none; border-radius: 5px; margin: 20px 0; }}
            .footer {{ text-align: center; color: #666; font-size: 12px; margin-top: 20px; }}
        </style>
    </head>
    <body>
        <div class="container">
            <div class="header">
                <h2>🔐 Réinitialisation de mot de passe</h2>
            </div>
            <div class="content">
                <p>Bonjour <strong>{username}</strong>,</p>
                <p>Vous avez demandé la réinitialisation de votre mot de passe.</p>
                <p style="text-align: center;">
                    <a href="{reset_url}" class="button">Réinitialiser mon mot de passe</a>
                </p>
                <p><small>Ce lien est valable 1 heure.</small></p>
                <p>Si vous n'êtes pas à l'origine de cette demande, ignorez cet email.</p>
            </div>
            <div class="footer">
                <p>© 2024 Egalyx Control. Tous droits réservés.</p>
            </div>
        </div>
    </body>
    </html>
    """
    
    # Utiliser votre service email existant
    try:
        from app import email_service
        success = email_service.send_email(
            to_email=to_email,
            subject=subject,
            body=body,
            html_body=html_body
        )
        return success
    except Exception as e:
        print(f"❌ Erreur envoi email: {str(e)}")
        return False

